int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    // We only need to count 'n' for 'one' and 'z' for 'zero'
    // because 'e', 'r', 'o' are shared or appear in both,
    // but 'n' uniquely identifies 'one' and 'z' uniquely identifies 'zero'.
    // The problem guarantees that a valid rearrangement is possible,
    // so we don't need to worry about insufficient 'e', 'r', 'o' if 'n' or 'z' are present.
    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        }
    }

    // To maximize the binary number, we should put '1's before '0's.
    // Each 'n' corresponds to one '1' (from "one").
    // Each 'z' corresponds to one '0' (from "zero").

    bool first_digit = true;
    for (int i = 0; i < count_n; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < count_z; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

