#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need k * y sticks.
        // So, total sticks needed for coal: k * y
        // Total sticks needed for crafting: k
        // Total sticks we need to have at some point: k * y + k

        // We start with 1 stick.
        // So, we need to acquire (k * y + k - 1) additional sticks.
        // Let's call this amount 'sticks_to_acquire'.
        long long sticks_to_acquire = k * y + k - 1;

        // Each trade of type 1 (1 stick for x sticks) gives us x - 1 net sticks.
        // We need to perform 'num_stick_trades' trades of type 1 to get 'sticks_to_acquire'.
        // num_stick_trades = ceil(sticks_to_acquire / (x - 1))
        long long num_stick_trades = (sticks_to_acquire + (x - 1) - 1) / (x - 1);

        // Total trades = trades for sticks + trades for coal
        // Trades for coal = k (since each coal costs 1 trade)
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

