int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is less than n-1, it means p[i] must be n.
        // This is because if p[i] were not n, then there would be some p[j] = n.
        // Then min(p[i], p[j]) = p[i].
        // If p[i] is not n, then max_val_in_row would be at most n-1.
        // If p[i] is n, then for all j, min(p[i], p[j]) = p[j].
        // So max_val_in_row would be max(p[j] for j!=i) which is n-1.
        // This logic is slightly off.
        // Correct logic:
        // For each i, p[i] >= max(a[i][j] for j!=i).
        // If p[i] is not n, then there must be some p[k] = n.
        // Then a[i][k] = min(p[i], p[k]) = min(p[i], n) = p[i].
        // So max(a[i][j] for j!=i) would be at least p[i].
        // If p[i] is n, then for all j!=i, a[i][j] = min(n, p[j]) = p[j].
        // So max(a[i][j] for j!=i) would be max(p[j] for j!=i) which is n-1.
        // Thus, if max_val_in_row is n-1, p[i] could be n.
        // If max_val_in_row is less than n-1, then p[i] must be max_val_in_row.
        // This is because if p[i] were greater than max_val_in_row, say p[i] = X > max_val_in_row.
        // Then for all j!=i, min(X, p[j]) = a[i][j].
        // This implies p[j] >= a[i][j] for all j!=i.
        // And also X >= a[i][j] for all j!=i.
        // If X is not n, then there is some p[k]=n.
        // Then a[i][k] = min(X, n) = X.
        // But a[i][k] <= max_val_in_row, so X <= max_val_in_row, a contradiction.
        // So if max_val_in_row < n-1, then p[i] must be max_val_in_row.
        // If max_val_in_row == n-1, then p[i] could be n.
        // The problem guarantees a solution exists.
        // The simplest approach is to assume p[i] = max_val_in_row unless it's the one element that must be n.
        // The element that is n will have max_val_in_row = n-1.
        // All other elements will have max_val_in_row = p[i].
        // So, if max_val_in_row < n-1, then p[i] = max_val_in_row.
        // If max_val_in_row == n-1, then p[i] = n.
        // This works because exactly one element will have max_val_in_row = n-1.
        // For that element, p[i] must be n. For all others, p[i] = max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

