int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_R_pos = -1, it means the frog is at cell 0.
                             // If last_R_pos = k, it means the frog is at cell k.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The previous 'R' or start was at last_R_pos.
                // The gap is (i+1) - (last_R_pos + 1) + 1 = i - last_R_pos.
                // Or, more simply, the distance from last_R_pos to i+1 is (i+1) - last_R_pos.
                max_gap = std::max(max_gap, (i + 1) - (last_R_pos + 1) + 1);
                last_R_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' to n+1.
        // If last_R_pos = -1, it means all characters are 'L'. The frog must jump from 0 to n+1 directly.
        // The distance is (n+1) - 0 = n+1.
        // If last_R_pos = k, the last 'R' was at cell k+1. The frog needs to jump from k+1 to n+1.
        // The distance is (n+1) - (k+1) = n - k.
        max_gap = std::max(max_gap, (n + 1) - (last_R_pos + 1) + 1);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i from 1 to n-1
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i is a new max.
                // But as a safety check.
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some unused number less than q_i.
            // We need to pick the smallest available number to maximize chances for future elements.
            // The largest available number less than q_i is q_i - 1, then q_i - 2, etc.
            // We need to find the smallest positive integer not yet used.
            // This is equivalent to finding the smallest number in the range [1, n] that is not in used_numbers.
            // We can iterate from 1 up to n to find the first unused number.
            // However, p_i must be <= q_i.
            // The numbers that are available for p_i are those in [1, n] that are not in used_numbers.
            // We need to pick one such that p_i <= q_i.
            // To ensure we can always find a number, we should pick the smallest available number.
            // The smallest available number is the smallest positive integer not in used_numbers.
            // Let's maintain a set of available numbers.
            // Or, we can iterate downwards from q_i - 1 to find an unused number.
            // But the problem states "any possible suitable permutation".
            // So, we can pick the smallest available number that is not greater than q_i.
            // The numbers that are *not* used are candidates.
            // We need to find the smallest number `x` such that `1 <= x <= n`, `x` is not in `used_numbers`, and `x <= q_i`.
            // Since `q_i = q_{i-1}`, `p_i` must be less than or equal to `q_{i-1}`.
            // The numbers that are available are those from 1 to n that are not in `used_numbers`.
            // We need to find the smallest `x` from this set such that `x <= q_i`.
            // If we iterate from 1 upwards, the first `x` we find that is not in `used_numbers` is the smallest available.
            // If this `x` is greater than `q_i`, then it's impossible.
            // Otherwise, we use `x`.

            int current_val = 1;
            while (used_numbers.count(current_val)) {
                current_val++;
            }

            if (current_val > q[i]) { // If the smallest available number is greater than q_i
                possible = false;
                break;
            }
            p[i] = current_val;
            used_numbers.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

