int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = n;
    int current_k_count = 0;

    for (int i = 0; i < k; ++i) {
        if (i % 2 == 0) { // Take from left (small)
            p[i] = left;
            left++;
        } else { // Take from right (large)
            p[i] = right;
            right--;
        }
        current_k_count++;
    }

    // The last element of the alternating sequence determines whether we continue
    // with increasing or decreasing numbers for the remaining part.
    // If the last element was from 'left' (i.e., p[k-1] = left-1),
    // then the next element should be from 'right' to continue the pattern,
    // but we want to stop generating new differences.
    // So, if k is odd, p[k-1] was 'left', and we should fill remaining with 'right' decreasingly.
    // If k is even, p[k-1] was 'right', and we should fill remaining with 'left' increasingly.

    if (k % 2 == 1) { // Last element p[k-1] was 'left' (e.g., 1, 5, 2, 4, 3 for n=5, k=5)
                      // The next element would normally be 'right'.
                      // To avoid new differences, fill remaining with 'right' decreasingly.
        for (int i = k; i < n; ++i) {
            p[i] = right;
            right--;
        }
    } else { // Last element p[k-1] was 'right' (e.g., 1, 5, 2, 4 for n=5, k=4)
             // The next element would normally be 'left'.
             // To avoid new differences, fill remaining with 'left' increasingly.
        for (int i = k; i < n; ++i) {
            p[i] = left;
            left++;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index 'p' such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    // We start from n-1 and move left.
    int p = n - 1;
    while (p > 0 && a[p-1] <= a[p]) {
        p--;
    }

    // If p is 0, the entire array is non-decreasing.
    // If p is n-1, the last element is the only non-decreasing part.
    // p now points to the start of the longest non-decreasing suffix.

    // From this point 'p', we need to find the rightmost index 'q' (q <= p)
    // such that a[q...p-1] is non-increasing.
    // This means a[q] >= a[q+1] >= ... >= a[p-1].
    // We start from p-1 and move left.
    int q = p; // Initialize q to p. If p is 0, q remains 0.
    while (q > 0 && a[q-1] >= a[q]) {
        q--;
    }

    // The length of the prefix to erase is q.
    // The remaining array is a[q...n-1].
    std::cout << q << std::endl;
}

