int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        std::string s;
        std::cin >> s;
        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        int horizontal_moves = std::min(counts['L'], counts['R']);
        int vertical_moves = std::min(counts['U'], counts['D']);

        if (horizontal_moves == 0 && vertical_moves == 0) {
            std::cout << 0 << "\n\n";
        } else if (horizontal_moves == 0) { // Only vertical moves possible
            std::cout << 2 << "\n";
            std::cout << "UD\n";
        } else if (vertical_moves == 0) { // Only horizontal moves possible
            std::cout << 2 << "\n";
            std::cout << "LR\n";
        } else {
            std::cout << 2 * (horizontal_moves + vertical_moves) << "\n";
            for (int i = 0; i < horizontal_moves; ++i) {
                std::cout << 'L';
            }
            for (int i = 0; i < vertical_moves; ++i) {
                std::cout << 'U';
            }
            for (int i = 0; i < horizontal_moves; ++i) {
                std::cout << 'R';
            }
            for (int i = 0; i < vertical_moves; ++i) {
                std::cout << 'D';
            }
            std::cout << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. It's always beautiful.
        // For m > 1, we need to expand the current segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from min(pos[1]...pos[m]) to max(pos[1]...pos[m]).
        // We maintain current_min_idx and current_max_idx for numbers 1 to (m-1).
        // When considering 'm', we update these bounds to include pos[m].

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // contains exactly the numbers 1, 2, ..., m.
        // This implies two conditions:
        // 1. The length of the subsegment must be 'm'.
        // 2. The minimum value in the subsegment must be 1, and the maximum must be m.
        //    (This is implicitly handled by how current_min_idx and current_max_idx are updated,
        //     as they track the span of 1 to m. If the length matches, then all numbers
        //     1 to m must be present and no other numbers outside this range can be present
        //     if the length is exactly m).

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n <= 2) {
        std::cout << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return;
    }

    std::vector<int> result_subsequence;
    result_subsequence.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum
        // p[i] is a peak if p[i-1] < p[i] and p[i] > p[i+1]
        // p[i] is a valley if p[i-1] > p[i] and p[i] < p[i+1]
        bool is_peak = (p[i] > p[i-1] && p[i] > p[i+1]);
        bool is_valley = (p[i] < p[i-1] && p[i] < p[i+1]);

        if (is_peak || is_valley) {
            result_subsequence.push_back(p[i]);
        }
    }
    result_subsequence.push_back(p[n-1]);

    std::cout << result_subsequence.size() << "\n";
    for (size_t i = 0; i < result_subsequence.size(); ++i) {
        std::cout << result_subsequence[i] << (i == result_subsequence.size() - 1 ? "" : " ");
    }
    std::cout << "\n";
}

