#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // (n-1)/2 for 0-indexed array

    // 1. Make the median element equal to s
    operations += std::abs(a[median_idx] - s);
    a[median_idx] = s; // Conceptually change it for subsequent checks

    // 2. Ensure elements to the left of median are <= s
    // These are elements at indices 0 to median_idx - 1
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // 3. Ensure elements to the right of median are >= s
    // These are elements at indices median_idx + 1 to n - 1
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;

    // Iterate through each point as the leftmost point (x_i) of a potential triplet
    for (int i = 0; i < n; ++i) {
        // Find the rightmost point (x_k) that satisfies x_k - x_i <= d
        // Since x is sorted, we can use std::upper_bound to find the first element
        // strictly greater than x[i] + d.
        // All elements from x[i+1] up to (but not including) this upper_bound
        // are potential x_k candidates.
        // However, we are looking for x_k, which is the third point.
        // The condition is x_k - x_i <= d.
        // So, we need to find the index of the rightmost point `k_idx` such that x[k_idx] <= x[i] + d.
        // `std::upper_bound` returns an iterator to the first element that is greater than `value`.
        // So, `std::upper_bound(x.begin() + i + 1, x.end(), x[i] + d)` will give us an iterator
        // to the first element `x[p]` such that `x[p] > x[i] + d`.
        // The index of this element is `p`.
        // All elements from `x[i+1]` to `x[p-1]` satisfy the condition `x_k - x_i <= d`.
        // Let `k_idx` be the index `p-1`.

        auto it = std::upper_bound(x.begin() + i + 1, x.end(), x[i] + d);
        int k_idx = std::distance(x.begin(), it) - 1;

        // If k_idx is less than i + 2, it means there are not enough points
        // to form a triplet (i, j, k) where j > i and k > j.
        // Specifically, if k_idx < i + 2, it means there are 0 or 1 points
        // available after x[i] that satisfy the distance condition.
        // We need at least two points after x[i] to form a triplet (x_i, x_j, x_k).
        // So, k_idx must be at least i + 2.
        if (k_idx < i + 2) {
            continue;
        }

        // The number of points available for x_j and x_k (where x_k is the farthest)
        // is from index i+1 to k_idx.
        // Let's call this range of points `m = k_idx - (i + 1) + 1`.
        // These `m` points are `x[i+1], x[i+2], ..., x[k_idx]`.
        // We need to choose 2 points from these `m` points to be `x_j` and `x_k`.
        // The number of ways to choose 2 points from `m` points is `m * (m - 1) / 2`.
        // Here, `m` is the count of points `x_j` and `x_k` that can be chosen
        // such that `i < j < k <= k_idx`.
        // The number of points available for `j` and `k` is `k_idx - (i + 1) + 1`.
        // Let `num_available_points = k_idx - (i + 1) + 1`.
        // This is the count of points from `x[i+1]` to `x[k_idx]`.
        // If `num_available_points < 2`, we cannot form a pair `(x_j, x_k)`.
        // The condition `k_idx < i + 2` already handles this, as it means `num_available_points < 2`.
        // If `k_idx = i + 2`, then `num_available_points = 2`. We can choose `(x[i+1], x[i+2])`.
        // If `k_idx = i + 3`, then `num_available_points = 3`. We can choose `(x[i+1], x[i+2])`, `(x[i+1], x[i+3])`, `(x[i+2], x[i+3])`.
        // The number of ways to choose 2 points from `num_available_points` is `C(num_available_points, 2)`.

        long long num_available_points = k_idx - (i + 1) + 1;

        // We need at least 2 points to choose from for j and k.
        // If num_available_points is 0 or 1, C(num_available_points, 2) is 0.
        if (num_available_points >= 2) {
            count += num_available_points * (num_available_points - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
