void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need current_sum + b1 + b2 = 2 * (current_xor_sum ^ b1 ^ b2)
    // Let b1 = current_xor_sum
    // Then current_sum + current_xor_sum + b2 = 2 * (current_xor_sum ^ current_xor_sum ^ b2)
    // current_sum + current_xor_sum + b2 = 2 * (0 ^ b2)
    // current_sum + current_xor_sum + b2 = 2 * b2
    // current_sum + current_xor_sum = b2

    // So, if we append b1 = current_xor_sum and b2 = current_sum + current_xor_sum,
    // the new sum will be S' = current_sum + current_xor_sum + (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // The new XOR sum will be X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum) = 0 ^ (current_sum + current_xor_sum) = current_sum + current_xor_sum
    // And indeed, S' = 2 * X' holds.

    // This strategy always works and appends 2 elements.
    // The problem allows appending up to 3 elements and doesn't require minimization.
    // The values can be large, up to 10^18, so long long is necessary.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

