int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        // The condition for termination is that the counts of 'x', 'y', 'z'
        // in the substring must differ by at most 1.
        // If they differ by more than 1, it's always possible to form a
        // 3-character subsequence that is not "zyx", "xzy", "yxz"
        // and rearrange it to maintain the imbalance, thus never terminating.
        if (std::abs(count_x - count_y) <= 1 &&
            std::abs(count_y - count_z) <= 1 &&
            std::abs(count_x - count_z) <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int p = 0; p <= 9; ++p) { // Iterate through all possible pivot digits (0-9)
        std::string current_coloring(n, ' ');
        int last_digit_color1 = -1; // Last digit assigned to color 1
        int first_digit_color2 = -1; // First digit assigned to color 2

        // First pass: Assign digits based on pivot 'p'
        // Digits < p go to color 1
        // Digits > p go to color 2
        // Digits == p are initially unassigned (marked with '0' for now)
        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < p) {
                current_coloring[i] = '1';
                last_digit_color1 = digit;
            } else if (digit > p) {
                current_coloring[i] = '2';
                if (first_digit_color2 == -1) {
                    first_digit_color2 = digit;
                }
            } else { // digit == p
                current_coloring[i] = '0'; // Mark as unassigned for now
            }
        }

        // Check if the last_digit_color1 > first_digit_color2 condition is already violated
        if (last_digit_color1 != -1 && first_digit_color2 != -1 && last_digit_color1 > first_digit_color2) {
            continue; // This pivot 'p' won't work
        }

        // Second pass: Assign digits equal to 'p'
        // All 'p's before the first '2' go to color 1
        // All 'p's after or at the first '2' go to color 2
        bool seen_color2_digit = false;
        for (int i = 0; i < n; ++i) {
            if (current_coloring[i] == '2') {
                seen_color2_digit = true;
            }
            if (current_coloring[i] == '0') { // This is a digit 'p'
                if (!seen_color2_digit) {
                    current_coloring[i] = '1';
                    last_digit_color1 = p; // Update last_digit_color1 if 'p' is assigned to color 1
                } else {
                    current_coloring[i] = '2';
                    if (first_digit_color2 == -1) { // If this is the first 'p' assigned to color 2
                        first_digit_color2 = p;
                    }
                }
            }
        }

        // Final check for validity of the constructed coloring
        std::string s1_str = "";
        std::string s2_str = "";
        bool valid_coloring = true;

        for (int i = 0; i < n; ++i) {
            if (current_coloring[i] == '1') {
                s1_str += s[i];
            } else {
                s2_str += s[i];
            }
        }

        // Check if S1 is non-decreasing
        for (size_t i = 0; i + 1 < s1_str.length(); ++i) {
            if (s1_str[i] > s1_str[i+1]) {
                valid_coloring = false;
                break;
            }
        }
        if (!valid_coloring) continue;

        // Check if S2 is non-decreasing
        for (size_t i = 0; i + 1 < s2_str.length(); ++i) {
            if (s2_str[i] > s2_str[i+1]) {
                valid_coloring = false;
                break;
            }
        }
        if (!valid_coloring) continue;

        // Check if last digit of S1 <= first digit of S2
        if (!s1_str.empty() && !s2_str.empty()) {
            if (s1_str.back() > s2_str.front()) {
                valid_coloring = false;
            }
        }

        if (valid_coloring) {
            result = current_coloring;
            found_solution = true;
            break; // Found a valid coloring, no need to check other pivots
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

