#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_s(k, '?'); // Stores the determined characters for each position modulo k

    bool possible = true;
    for (int i = 0; i < n; ++i) {
        char current_char = s[i];
        int mod_k_pos = i % k;

        if (current_char == '0') {
            if (fixed_s[mod_k_pos] == '1') {
                possible = false;
                break;
            }
            fixed_s[mod_k_pos] = '0';
        } else if (current_char == '1') {
            if (fixed_s[mod_k_pos] == '0') {
                possible = false;
                break;
            }
            fixed_s[mod_k_pos] = '1';
        }
        // If current_char is '?', fixed_s[mod_k_pos] remains '?' or its existing fixed value.
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    int zeros = 0;
    int ones = 0;
    int question_marks = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_s[i] == '0') {
            zeros++;
        } else if (fixed_s[i] == '1') {
            ones++;
        } else { // fixed_s[i] == '?'
            question_marks++;
        }
    }

    int target_half = k / 2;

    if (zeros > target_half || ones > target_half) {
        possible = false;
    } else {
        // We need to fill (target_half - zeros) '0's and (target_half - ones) '1's using '?'s.
        // The total number of '?'s needed is (target_half - zeros) + (target_half - ones).
        // This sum must be equal to the available 'question_marks'.
        // (target_half - zeros) + (target_half - ones) = k - (zeros + ones) = question_marks.
        // So, we just need to check if we have enough '?'s to satisfy the counts.
        // This is equivalent to checking if (zeros + question_marks >= target_half) and (ones + question_marks >= target_half).
        // More simply, if zeros <= target_half and ones <= target_half, then we can always fill the remaining '?'s.
        // The number of '?'s that must become '0' is target_half - zeros.
        // The number of '?'s that must become '1' is target_half - ones.
        // The sum of these must be <= question_marks.
        // (target_half - zeros) + (target_half - ones) <= question_marks
        // k - (zeros + ones) <= question_marks
        // This is always true because question_marks = k - (zeros + ones).
        // So, the only conditions are zeros <= target_half and ones <= target_half, which we already checked.
        // The final check is if we can satisfy both counts.
        // We need target_half - zeros zeros and target_half - ones ones.
        // The remaining '?'s are question_marks - (target_half - zeros) - (target_half - ones).
        // This simplifies to question_marks - (k - zeros - ones) = question_marks - (question_marks) = 0.
        // So, if zeros <= target_half and ones <= target_half, it's always possible.
        // The only remaining check is if the number of '?'s is sufficient to make up the difference.
        // The number of '0's needed is target_half - zeros.
        // The number of '1's needed is target_half - ones.
        // The total '?'s available is question_marks.
        // If (target_half - zeros) + (target_half - ones) == question_marks, then it's possible.
        // This is equivalent to (k - zeros - ones) == question_marks, which is always true by definition of question_marks.
        // So, the only conditions are zeros <= target_half and ones <= target_half.
        // This means if we have too many 0s or too many 1s already, it's impossible.
        // Otherwise, it's always possible to fill the '?'s.
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

