int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n >= abs_m for simpler logic
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: Not enough moves to reach the target even with all diagonal moves
        // The minimum number of moves to reach (abs_n, abs_m) is abs_n (if abs_n >= abs_m)
        // This is achieved by abs_m diagonal moves and (abs_n - abs_m) horizontal moves.
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        long long ans;
        long long remaining_moves = k - abs_n;

        // After abs_n moves, we are at (abs_n, abs_m) or (abs_n, -abs_m) etc.
        // We have used abs_m diagonal moves and (abs_n - abs_m) non-diagonal moves.
        // The current position is (abs_n, abs_m).
        // We need to make 'remaining_moves' more moves.
        // Each pair of moves (e.g., (1,0) then (-1,0)) can be used to return to the current cell.
        // Each such pair of moves changes the parity of the coordinates by 0.
        // Each such pair of moves can be either two non-diagonal moves or two diagonal moves.
        // To maximize diagonal moves, we want to use diagonal moves for these remaining moves.

        // If remaining_moves is even, we can use pairs of moves like (1,1) then (-1,-1)
        // or (1,0) then (-1,0).
        // If we use (1,1) then (-1,-1), we add 2 diagonal moves.
        // If we use (1,0) then (-1,0), we add 0 diagonal moves.
        // So, if remaining_moves is even, we can make all of them diagonal.
        // The total diagonal moves would be abs_m (initial) + remaining_moves.
        if (remaining_moves % 2 == 0) {
            ans = abs_m + remaining_moves;
        } else {
            // If remaining_moves is odd, we cannot make all of them diagonal and end up at (abs_n, abs_m).
            // Consider the parity of the target coordinates (abs_n, abs_m) and the total moves k.
            // The parity of (x+y) changes with each move.
            // (x_final + y_final) % 2 must be equal to (x_initial + y_initial + k) % 2.
            // (abs_n + abs_m) % 2 must be equal to (0 + 0 + k) % 2.
            // So, (abs_n + abs_m) % 2 must be equal to k % 2.

            // If (abs_n + abs_m) % 2 != k % 2, it's impossible to reach (abs_n, abs_m) in k moves.
            // This is because each move changes the parity of (x+y) by 1 or -1 (which is 1 mod 2).
            // So, (x_final + y_final) % 2 == (x_initial + y_initial + k) % 2.
            // Since (x_initial, y_initial) = (0,0), we need (abs_n + abs_m) % 2 == k % 2.
            if ((abs_n + abs_m) % 2 != k % 2) {
                std::cout << -1 << "\n";
                continue;
            }

            // If remaining_moves is odd and (abs_n + abs_m) % 2 == k % 2,
            // we must use one non-diagonal move among the 'remaining_moves' to adjust parity.
            // For example, if we are at (X,Y) and need to make an odd number of moves to return to (X,Y),
            // we can't do it with only diagonal moves. We need at least one non-diagonal move.
            // Example: (X,Y) -> (X+1, Y) -> (X, Y). This uses 1 non-diagonal, 1 non-diagonal. Total 2 moves.
            // Example: (X,Y) -> (X+1, Y) -> (X+1, Y+1) -> (X, Y+1) -> (X, Y). Total 4 moves.
            // If we have an odd number of remaining moves, say 1. We are at (abs_n, abs_m).
            // We need to make 1 move and end up at (abs_n, abs_m). This is impossible.
            // The problem states we need to reach (abs_n, abs_m) in exactly k moves.
            // If remaining_moves is odd, we must use one non-diagonal move to "waste" a move.
            // For example, if we are at (X,Y) and need to make 1 move, we can go to (X+1,Y).
            // But we need to end up at (X,Y).
            // The logic here is that if remaining_moves is odd, we can't make all of them diagonal
            // and still end up at the same parity relative to the starting point.
            // We must use one non-diagonal move to "waste" a move, e.g., (X,Y) -> (X+1,Y) -> (X,Y).
            // This uses 2 moves, 0 diagonal.
            // If we have an odd number of remaining moves, say R.
            // We can make R-1 moves as diagonal pairs, and then one move must be non-diagonal.
            // For example, (X,Y) -> (X+1,Y) -> (X,Y) is 2 moves, 0 diagonal.
            // (X,Y) -> (X+1,Y) -> (X+1,Y+1) -> (X,Y+1) -> (X,Y) is 4 moves, 2 diagonal.
            // The maximum number of diagonal moves for 'remaining_moves' is 'remaining_moves - 1' if 'remaining_moves' is odd.
            // This is because we must use at least one non-diagonal move to change the parity of (x+y) back to what it was.
            // For example, if we are at (X,Y) and need to make 1 move, we can go to (X+1,Y).
            // But we need to end up at (X,Y).
            // The parity condition (abs_n + abs_m) % 2 == k % 2 already handles the impossibility.
            // If it's possible, and remaining_moves is odd, it means we must use one non-diagonal move
            // to adjust the parity.
            // So, we use (remaining_moves - 1) diagonal moves and 1 non-diagonal move.
            // The total diagonal moves would be abs_m + (remaining_moves - 1).
            ans = abs_m + remaining_moves - 2; // We lose 2 diagonal moves compared to the even case.
                                               // One move is non-diagonal, and another move is non-diagonal to cancel it out.
                                               // E.g., (X,Y) -> (X+1,Y) -> (X,Y) uses 2 moves, 0 diagonal.
                                               // If we had 2 moves, we could do (X,Y) -> (X+1,Y+1) -> (X,Y) for 2 diagonal.
                                               // So we lose 2 diagonal moves.
        }

        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_max_dist = dq.empty() ? 0 : L[dq.back()];
        long long dist_to_left = dq.empty() ? 0 : (i - dq.back());
        L[i] = std::max(h[i], prev_max_dist + dist_to_left);
        dq.push_back(i);
    }

    std::vector<long long> R(n);
    dq.clear();

    for (int i = n - 1; i >= 0; --i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_max_dist = dq.empty() ? 0 : R[dq.back()];
        long long dist_to_right = dq.empty() ? 0 : (dq.back() - i);
        R[i] = std::max(h[i], prev_max_dist + dist_to_right);
        dq.push_back(i);
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(L[i], R[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

