    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s_count++;
        } else {
            initial_b_count++;
        }
    }

    int initial_diff = initial_s_count - initial_b_count;

    // Calculate prefix sums for the left part (jars 1 to n)
    // diff_left[k] = (S_count - B_count) for jars 1 to k
    std::vector<int> diff_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_left[i + 1] = diff_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right part (jars n+1 to 2n)
    // diff_right[k] = (S_count - B_count) for jars 2n-k+1 to 2n
    std::vector<int> diff_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_right[i + 1] = diff_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the left (k_L)
    // to achieve a certain difference (diff_left[k_L])
    std::map<int, int> left_diff_to_k;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff = diff_left[k_L];
        if (left_diff_to_k.find(current_diff) == left_diff_to_k.end()) {
            left_diff_to_k[current_diff] = k_L;
        }
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible numbers of jars eaten from the right (k_R)
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_right_diff = diff_right[k_R];
        // The target difference for the remaining jars (after eating k_L from left and k_R from right)
        // is 0.
        // The total difference of all jars is initial_diff.
        // If we eat k_L jars from left, their diff is diff_left[k_L].
        // If we eat k_R jars from right, their diff is diff_right[k_R].
        // The remaining jars must have a diff of 0.
        // So, initial_diff - diff_left[k_L] - diff_right[k_R] = 0
        // This means diff_left[k_L] = initial_diff - diff_right[k_R]
        int target_left_diff = initial_diff - current_right_diff;

        if (left_diff_to_k.count(target_left_diff)) {
            int k_L = left_diff_to_k[target_left_diff];
            min_jars_eaten = std::min(min_jars_eaten, k_L + k_R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

