#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits are 1
    int current_or_mask = 0;    // All bits are 0
    int current_xor_mask = 0;   // All bits are 0

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_and_mask &= x;
            current_or_mask &= x;
            current_xor_mask &= x;
        } else if (op_char == '|') {
            current_and_mask |= x;
            current_or_mask |= x;
            current_xor_mask |= x;
        } else if (op_char == '^') {
            current_and_mask ^= x;
            current_or_mask ^= x;
            current_xor_mask ^= x;
        }
    }

    // Now we have the final transformation for 0 and 1.
    // For an input bit 'b':
    // If b=0, the output bit is (0 & current_and_mask) | current_or_mask ^ current_xor_mask
    // which simplifies to current_or_mask ^ current_xor_mask. Let's call this 'val0'.
    // If b=1, the output bit is (1 & current_and_mask) | current_or_mask ^ current_xor_mask
    // which simplifies to current_and_mask | current_or_mask ^ current_xor_mask. Let's call this 'val1'.

    // Let's re-evaluate the logic for val0 and val1.
    // The state of a bit 'b' after all operations can be represented by:
    // (b & A) | O ^ X
    // where A, O, X are the combined masks.
    //
    // For an initial bit 0: (0 & A) | O ^ X = 0 | O ^ X = O ^ X
    // For an initial bit 1: (1 & A) | O ^ X = A | O ^ X
    //
    // So, let's track the final state of 0 and 1.
    int final_val0 = 0;
    int final_val1 = 1023; // All bits set to 1

    // Re-simulate the operations on final_val0 and final_val1
    // This is the correct way to combine operations.
    // The variables current_and_mask, current_or_mask, current_xor_mask
    // were tracking the combined effect on the *masks themselves*, not on the input value.
    // Let's re-initialize and track the effect on 0 and 1023 (all 1s).
    // This is equivalent to tracking the effect on each bit independently.
    // final_val0 will store the result for input 0.
    // final_val1 will store the result for input 1023 (all 1s).

    std::cin.clear();
    std::cin.seekg(0); // Rewind input stream to the beginning

    std::string dummy_line;
    std::getline(std::cin, dummy_line); // Read n again, discard

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            final_val0 &= x;
            final_val1 &= x;
        } else if (op_char == '|') {
            final_val0 |= x;
            final_val1 |= x;
        } else if (op_char == '^') {
            final_val0 ^= x;
            final_val1 ^= x;
        }
    }

    // Now, final_val0 is the result for input 0.
    // final_val1 is the result for input 1023 (all 1s).
    //
    // Let the simplified program be: (input & A_new) | O_new ^ X_new
    //
    // For input 0: (0 & A_new) | O_new ^ X_new = O_new ^ X_new = final_val0
    // For input 1023: (1023 & A_new) | O_new ^ X_new = A_new | O_new ^ X_new = final_val1
    //
    // We need to find A_new, O_new, X_new.
    //
    // From O_new ^ X_new = final_val0, we know that for each bit j:
    // (O_new)_j ^ (X_new)_j = (final_val0)_j
    //
    // From A_new | O_new ^ X_new = final_val1, we know that for each bit j:
    // (A_new)_j | (O_new)_j ^ (X_new)_j = (final_val1)_j
    // (A_new)_j | (final_val0)_j = (final_val1)_j
    //
    // This gives us:
    // (A_new)_j = 1 if (final_val0)_j = 0 and (final_val1)_j = 1
    // (A_new)_j = 0 if (final_val0)_j = 0 and (final_val1)_j = 0
    // (A_new)_j = 0 if (final_val0)_j = 1 and (final_val1)_j = 1
    // (A_new)_j is undefined if (final_val0)_j = 1 and (final_val1)_j = 0 (this case should not happen, as A_new | final_val0 must be final_val1)
    //
    // In summary, (A_new)_j = (final_val1)_j & ~ (final_val0)_j
    // Or more simply, A_new = final_val1 & (~final_val0)
    //
    // Let's define A_new, O_new, X_new.
    //
    // A_new: For a bit j, if input 0 maps to 0 and input 1 maps to 1, then A_new_j must be 1.
    //        If input 0 maps to 0 and input 1 maps to 0, then A_new_j must be 0.
    //        If input 0 maps to 1 and input 1 maps to 1, then A_new_j must be 0.
    //        If input 0 maps to 1 and input 1 maps to 0, this implies a XOR operation.
    //
    // Let's analyze bit by bit. For each bit position `j` (0 to 9):
    // Let `b0 = (final_val0 >> j) & 1`
    // Let `b1 = (final_val1 >> j) & 1`
    //
    // Case 1: `b0 = 0, b1 = 0`
    //   Input bit `x_j` always becomes 0. This means `(x_j & 0) | 0 ^ 0` or `(x_j & 1) | 0 ^ 1` etc.
    //   This can be achieved by `& 0` for this bit.
    //   So, `A_new_j = 0`, `O_new_j = 0`, `X_new_j = 0`.
    //
    // Case 2: `b0 = 0, b1 = 1`
    //   Input bit `x_j` becomes `x_j`. This means `(x_j & 1) | 0 ^ 0`.
    //   So, `A_new_j = 1`, `O_new_j = 0`, `X_new_j = 0`.
    //
    // Case 3: `b0 = 1, b1 = 0`
    //   Input bit `x_j` becomes `~x_j`. This means `(x_j & 1) | 0 ^ 1`.
    //   So, `A_new_j = 1`, `O_new_j = 0`, `X_new_j = 1`.
    //
    // Case 4: `b0 = 1, b1 = 1`
    //   Input bit `x_j` always becomes 1. This means `(x_j & 0) | 1 ^ 0`.
    //   So, `A_new_j = 0`, `O_new_j = 1`, `X_new_j = 0`.
    //
    // Let's construct the new masks:
    int A_new = 0; // Mask for & operation
    int O_new = 0; // Mask for | operation
    int X_new = 0; // Mask for ^ operation

    for (int j = 0; j < 10; ++j) {
        int b0 = (final_val0 >> j) & 1;
        int b1 = (final_val1 >> j) & 1;

        if (b0 == 0 && b1 == 0) {
            // x_j -> 0. Achieved by & (0 for this bit)
            // A_new_j = 0, O_new_j = 0, X_new_j = 0
        } else if (b0 == 0 && b1 == 1) {
            // x_j -> x_j. Achieved by & (1 for this bit)
            A_new |= (1 << j);
            // O_new_j = 0, X_new_j = 0
        } else if (b0 == 1 && b1 == 0) {
            // x_j -> ~x_j. Achieved by & (1 for this bit) ^ (1 for this bit)
            A_new |= (1 << j);
            X_new |= (1 << j);
            // O_new_j = 0
        } else if (b0 == 1 && b1 == 1) {
            // x_j -> 1. Achieved by | (1 for this bit)
            O_new |= (1 << j);
            // A_new_j = 0, X_new_j = 0
        }
    }

    std::vector<std::pair<char, int>> simplified_ops;
    if (A_new != 1023) { // If A_new is not all 1s, we need an & operation
        simplified_ops.push_back({'&', A_new});
    }
    if (O_new != 0) { // If O_new is not all 0s, we need an | operation
        simplified_ops.push_back({'|', O_new});
    }
    if (X_new != 0) { // If X_new is not all 0s, we need an ^ operation
        simplified_ops.push_back({'^', X_new});
    }

    std::cout << simplified_ops.size() << "\n";
    for (const auto& op : simplified_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total number of substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // If m ones are present, they divide the string into m+1 potential blocks of zeros.
        // To minimize the number of zero-only substrings, we distribute zeros as evenly as possible.
        // Let k be the number of zeros in each of the 'm+1' blocks.
        // There will be 'rem' blocks with (k+1) zeros and (m+1-rem) blocks with k zeros.
        // k = num_zeros / (m + 1)
        // rem = num_zeros % (m + 1)

        long long k = num_zeros / (m + 1);
        long long rem = num_zeros % (m + 1);

        // Number of blocks with (k+1) zeros
        long long blocks_k_plus_1 = rem;
        // Number of blocks with k zeros
        long long blocks_k = (m + 1) - rem;

        // Calculate the number of zero-only substrings from these blocks
        long long zero_only_substrings = 0;
        if (k > 0) {
            zero_only_substrings += blocks_k * k * (k + 1) / 2;
        }
        if (k + 1 > 0) { // This condition is always true if rem > 0 and k >= 0
            zero_only_substrings += blocks_k_plus_1 * (k + 1) * (k + 2) / 2;
        }

        // The maximum f(s) is total_substrings - minimum_zero_only_substrings
        long long max_f_s = total_substrings - zero_only_substrings;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> deletion_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> deletion_order[i];
        deletion_order[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = deletion_order[k_idx]; // This is the vertex being "added back"

        active_vertices[k] = true;

        // Update shortest paths using vertex k as an intermediate
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After adding k, it can also be an endpoint for paths
        // Update paths where k is an endpoint or start point
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            if (dist[i][k] + dist[k][k] < dist[i][k]) { // Path i -> k via k (self-loop)
                dist[i][k] = dist[i][k] + dist[k][k];
            }
            if (dist[k][k] + dist[k][i] < dist[k][i]) { // Path k -> i via k (self-loop)
                dist[k][i] = dist[k][k] + dist[k][i];
            }
        }

        // Now, k can be an intermediate for paths between existing active vertices
        // And existing active vertices can be intermediates for paths involving k
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with a small positive integer

    while (X > 0) {
        long long k = 0;
        // Find the largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        // We need to find the largest k such that (1LL << k) - 1 <= X
        // Or, (1LL << (k+1)) - 1 > X
        // So, k is the highest bit set in X+1, minus 1.
        // Or, more simply, iterate k from 1 upwards.
        for (int i = 1; i <= 60; ++i) { // Max k can be around 60 for X up to 10^18
            if (((1LL << i) - 1) <= X) {
                k = i;
            } else {
                break;
            }
        }

        // If X is 1, k will be 1. (2^1 - 1 = 1)
        // If X is 2, k will be 1. (2^1 - 1 = 1)
        // If X is 3, k will be 2. (2^2 - 1 = 3)
        // If X is 4, k will be 2. (2^2 - 1 = 3)
        // If X is 5, k will be 2. (2^2 - 1 = 3)
        // If X is 6, k will be 2. (2^2 - 1 = 3)
        // If X is 7, k will be 3. (2^3 - 1 = 7)

        // Add k elements of current_val to the result array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }

        // Subtract the count of subsequences formed by these k elements
        X -= ((1LL << k) - 1);

        // If X is still positive, prepare for the next block
        if (X > 0) {
            // The next block of elements must be at least current_val + d
            // to ensure that any subsequence combining elements from this block
            // and previous blocks will have max - min >= d.
            // We add 1 to current_val + d to ensure strict inequality for the condition.
            current_val += d + 1;
            // Check if current_val exceeds 10^18, which is the limit for elements.
            // If it does, it means we cannot construct a valid array.
            // However, given X <= 10^9 and d <= 10^9, current_val can grow large.
            // The maximum number of elements is 10^4.
            // If we add d+1 for 10^4 times, current_val could be 1 + 10^4 * (10^9 + 1) ~ 10^13.
            // This is well within 10^18.
        }
    }

    std::cout << result_array.size() << "\n";
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, which fits in long long.
    // We need to perform division by 2.
    // If b is even, b/2 is integer.
    // If b is odd, (b-1)/2 is integer.
    // (b-1) * b is always even, so (b-1)*b/2 is always an integer.
    // We need to compute this modulo MOD.
    // (X * Y / 2) % MOD = (X % MOD * Y % MOD * inv(2) % MOD) % MOD
    // inv(2) modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004
    long long inv2 = 500000004;

    long long sum_r_term1 = (b - 1) % MOD;
    long long sum_r_term2 = b % MOD;
    long long sum_r = (sum_r_term1 * sum_r_term2) % MOD;
    sum_r = (sum_r * inv2) % MOD;

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // sum_k_b_plus_1 = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_{k=1 to a} k = a * (a + 1) / 2
    // sum_{k=1 to a} 1 = a
    // So, sum_k_b_plus_1 = b * a * (a + 1) / 2 + a

    long long sum_k_term1 = a % MOD;
    long long sum_k_term2 = (a + 1) % MOD;
    long long sum_k = (sum_k_term1 * sum_k_term2) % MOD;
    sum_k = (sum_k * inv2) % MOD;

    long long sum_k_b_plus_1_part1 = (b % MOD * sum_k) % MOD;
    long long sum_k_b_plus_1_part2 = a % MOD;
    long long sum_k_b_plus_1 = (sum_k_b_plus_1_part1 + sum_k_b_plus_1_part2) % MOD;

    // Total sum S = sum_r * sum_k_b_plus_1
    long long total_sum = (sum_r * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only b1=a1, bn=an rules apply)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> first_zero_block_start(n, -1);
    std::vector<int> first_one_block_start(n, -1);

    int current_block_start = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            if (current_block_start == -1) {
                current_block_start = i;
            }
            first_zero_block_start[i] = current_block_start;
        } else {
            current_block_start = -1;
        }
    }

    current_block_start = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            if (current_block_start == -1) {
                current_block_start = i;
            }
            first_one_block_start[i] = current_block_start;
        } else {
            current_block_start = -1;
        }
    }

    std::vector<int> last_zero_block_end(n, -1);
    std::vector<int> last_one_block_end(n, -1);

    int current_block_end = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            if (current_block_end == -1) {
                current_block_end = i;
            }
            last_zero_block_end[i] = current_block_end;
        } else {
            current_block_end = -1;
        }
    }

    current_block_end = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            if (current_block_end == -1) {
                current_block_end = i;
            }
            last_one_block_end[i] = current_block_end;
        } else {
            current_block_end = -1;
        }
    }

    int max_k = 0;
    std::vector<int> b = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // a[i] is 0, it can become 1 if it's part of a 1-block that expands
            if (first_one_block_start[i] != -1) { // There's a 1-block to the right
                int j = first_one_block_start[i];
                int len = j - i;
                if (len > 0) {
                    max_k = std::max(max_k, (len + 1) / 2);
                }
            }
            if (last_one_block_end[i] != -1) { // There's a 1-block to the left
                int j = last_one_block_end[i];
                int len = i - j;
                if (len > 0) {
                    max_k = std::max(max_k, (len + 1) / 2);
                }
            }
        } else { // a[i] is 1, it can become 0 if it's part of a 0-block that expands
            if (first_zero_block_start[i] != -1) { // There's a 0-block to the right
                int j = first_zero_block_start[i];
                int len = j - i;
                if (len > 0) {
                    max_k = std::max(max_k, (len + 1) / 2);
                }
            }
            if (last_zero_block_end[i] != -1) { // There's a 0-block to the left
                int j = last_zero_block_end[i];
                int len = i - j;
                if (len > 0) {
                    max_k = std::max(max_k, (len + 1) / 2);
                }
            }
        }
    }

    std::cout << max_k << "\n";

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            if (first_one_block_start[i] != -1) {
                int j = first_one_block_start[i];
                if (j - i <= max_k) {
                    b[i] = 1;
                }
            }
            if (last_one_block_end[i] != -1) {
                int j = last_one_block_end[i];
                if (i - j <= max_k) {
                    b[i] = 1;
                }
            }
        } else { // a[i] == 1
            if (first_zero_block_start[i] != -1) {
                int j = first_zero_block_start[i];
                if (j - i <= max_k) {
                    b[i] = 0;
                }
            }
            if (last_zero_block_end[i] != -1) {
                int j = last_zero_block_end[i];
                if (i - j <= max_k) {
                    b[i] = 0;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

