int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << "1\n";
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = 1;

    for (int i = 0; i < n; ++i) {
        int block_start_idx = i;
        int block_end_val = std::min(n, current_val + k - 1);

        for (int j = block_end_val; j >= current_val; --j) {
            p[block_start_idx + (block_end_val - j)] = j;
        }

        i += (block_end_val - current_val); // Move index to the end of the current block
        current_val = block_end_val + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k = 1 (2 pieces)
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string s_new = s_suffix + s_prefix;

        if (s_new != s && is_palindrome(s_new)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2 (3 pieces)
    // The problem statement implies that if k=1 doesn't work,
    // we should check k=2.
    // The only way k=2 is needed is if all single-cut rotations
    // either result in the original string or are not palindromes.
    //
    // Consider the structure of the original palindrome 's'.
    // If 's' consists of only one distinct character (e.g., "aaaaa"),
    // then any rotation will result in the same string "aaaaa".
    // In this case, it's impossible to get a new string.
    //
    // If 's' has at least two distinct characters, and it's a palindrome,
    // and no single cut rotation works, then we need to check if k=2 is possible.
    //
    // Example: "nolon"
    // n=5
    // i=1: "olon" + "n" = "olonn" (not palindrome)
    // i=2: "lon" + "no" = "lonno" (not palindrome)
    // i=3: "on" + "nol" = "onnol" (not palindrome)
    // i=4: "n" + "nolo" = "nnolo" (not palindrome)
    //
    // The example says "nolon" -> 2 cuts.
    // "no|l|on" -> "on|l|no" = "onlno" (palindrome, != "nolon")
    //
    // This implies that if a string is a palindrome, and it's not composed
    // of a single repeating character, then it's always possible to make
    // a new palindrome with 2 cuts.
    //
    // Let's verify this.
    // If s is a palindrome and not all characters are the same:
    // s = c_1 c_2 ... c_k ... c_2 c_1
    // Since not all characters are the same, there must be at least one character
    // c_i such that c_i != c_1 (for i > 1).
    //
    // Consider cutting s into s[0...N-2] and s[N-1].
    // s = s_prefix + s_suffix, where s_suffix is s[N-1].
    // s_new = s_suffix + s_prefix = s[N-1] + s[0...N-2].
    // If this is not s and is a palindrome, k=1.
    //
    // If all single-cut rotations fail, it means either:
    // 1. All rotations result in 's'. This happens if all characters in 's' are the same.
    //    e.g., "aaaaa". In this case, no matter how you cut and rearrange, you get "aaaaa".
    // 2. Some rotations are not 's', but none of them are palindromes.
    //    e.g., "nolon". Rotations like "olonn", "lonno", etc., are not palindromes.
    //
    // If all characters in 's' are the same (e.g., "qqqq"), then it's impossible.
    // We can check this by counting distinct characters.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 must be the answer.
        // The logic is that if s is a palindrome and has at least two distinct characters,
        // and no single rotation works, then we can always achieve a new palindrome with 2 cuts.
        // For example, take s = "abacaba".
        // Rotations: "bacabaa", "acabaab", "cabaaba", "abaacab", "baacaba", "aacabab".
        // None of these are palindromes.
        //
        // Consider cutting s into s[0], s[1...N-2], s[N-1].
        // For "nolon": s[0]='n', s[1...3]="olo", s[4]='n'.
        // Rearrange to s[4], s[1...3], s[0] -> "n" + "olo" + "n" = "nolon" (original)
        //
        // The example "nolon" -> "onlno" uses cuts "no|l|on" and rearranges to "on|l|no".
        // This is s[3..4] + s[2] + s[0..1].
        //
        // The problem statement guarantees that s is a palindrome.
        // If s is a palindrome and not all characters are the same,
        // then it's always possible to find a new palindrome with 2 cuts.
        // The proof for this is non-trivial but generally relies on the fact
        // that you can isolate a central part or swap outer parts to break symmetry
        // in a way that forms a new palindrome.
        // For example, if s = "abacaba", cut "a|bacab|a". Rearrange to "a|bacab|a" (original).
        // But if you cut "ab|a|caba", you can't easily form a new palindrome.
        //
        // The key insight from competitive programming problems like this is often
        // that if k=1 doesn't work, and it's not the "all same characters" impossible case,
        // then k=2 is the answer. This is a common pattern for "minimum k" problems
        // where k is small (0, 1, 2).
        //
        // The example "nolon" -> 2 cuts confirms this.
        // "otto" -> 1 cut ("ot|to" -> "toot")
        // "qqqq" -> Impossible
        // "kinnikkinnik" -> 1 cut ("kinnik|kinnik" -> "kinnikkinnik" (original))
        // Wait, "kinnikkinnik" is a palindrome.
        // n=12.
        // s_prefix = "kinnik", s_suffix = "kinnik".
        // s_new = "kinnikkinnik" (original).
        //
        // Let's re-check "kinnikkinnik".
        // The example output is 1.
        // "kinnikkinnik"
        // Cut "kinnik|kinnik" -> "kinnikkinnik" (original)
        // Cut "kinnikkinnik" at i=3: "kin" + "nikkinnik" -> "nikkinnikkin"
        // Is "nikkinnikkin" a palindrome?
        // "nikkinnikkin" reversed is "nikkinnikkin". Yes.
        // Is "nikkinnikkin" != "kinnikkinnik"? Yes.
        // So for "kinnikkinnik", k=1 is the answer.
        // My loop for k=1 should have found this.
        //
        // Let's trace "kinnikkinnik" with my code:
        // s = "kinnikkinnik", n = 12
        // i=1: "innikkinnik" + "k" = "innikkinnikk" (not palindrome)
        // i=2: "nnikkinnik" + "ki" = "nnikkinnikki" (not palindrome)
        // i=3: "nikkinnik" + "kin" = "nikkinnikkin"
        //      is_palindrome("nikkinnikkin") -> true
        //      "nikkinnikkin" != "kinnikkinnik" -> true
        //      Output 1. Correct.
        //
        // So the logic for k=1 is correct.
        // The only remaining case for k=2 is when k=1 fails AND not all characters are the same.
        // This covers "nolon".
        //
        // Therefore, the logic is:
        // 1. Try k=1. If a valid new palindrome is found, output 1.
        // 2. If k=1 fails, check if all characters in 's' are the same.
        //    If yes, output "Impossible".
        // 3. If k=1 fails AND not all characters are the same, output 2.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = -1;
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // All pairs (a_i, a_j) are in the same subsequence.
    // f(a_i, a_j) = a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    if (n >= 2) {
        long long current_goodness = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
        min_goodness = current_goodness;
        for (int i = 0; i < n; ++i) {
            best_partition[a[i].original_index] = 1;
        }
    } else { // n=1, no pairs, goodness is 0.
        min_goodness = 0;
        best_partition[a[0].original_index] = 1;
    }


    // Case 2: Partition with at least one element in each subsequence.
    // This means there will be pairs (a_i, a_j) with a_i, a_j in same subsequence
    // AND pairs (a_i, a_j) with a_i, a_j in different subsequences.
    // So, min_f will be min(a_i + a_j) and max_f will be max(a_i + a_j + h).
    // The minimum possible sum a_i + a_j is a[0].value + a[1].value.
    // The maximum possible sum a_i + a_j + h is a[n-1].value + a[n-2].value + h.
    // So, min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value + h
    // goodness = (a[n-1].value + a[n-2].value + h) - (a[0].value + a[1].value)
    // This is the goodness if all types of pairs exist.

    // However, we can try to optimize by putting a[0] and a[n-1] in different groups.
    // Consider the partition where a[0] is in S1 and a[n-1] is in S2.
    // All other elements can be in S1 or S2.
    // The smallest possible sum a_i + a_j is a[0].value + a[1].value.
    // The largest possible sum a_i + a_j is a[n-1].value + a[n-2].value.
    // The smallest possible sum a_i + a_j + h is a[0].value + a[1].value + h (if a[0] in S1, a[1] in S2).
    // The largest possible sum a_i + a_j + h is a[n-1].value + a[n-2].value + h (if a[n-1] in S1, a[n-2] in S2).

    // Let's consider a specific partition strategy:
    // Put a[0] in S1.
    // Put a[n-1] in S2.
    // Put all other elements a[1]...a[n-2] in S1.
    // S1 = {a[0], a[1], ..., a[n-2]}
    // S2 = {a[n-1]}
    //
    // Pairs in S1:
    // min_same = a[0].value + a[1].value
    // max_same = a[n-2].value + a[n-3].value (if n-2 >= 1, i.e., n >= 3)
    // If n=2, S1={a[0]}, S2={a[1]}, no same-subsequence pairs.
    //
    // Pairs in S2: None (S2 has only one element).
    //
    // Pairs across S1 and S2:
    // min_diff = a[0].value + a[n-1].value + h
    // max_diff = a[n-2].value + a[n-1].value + h
    //
    // Overall min_f and max_f:
    // min_f = min(min_same, min_diff)
    // max_f = max(max_same, max_diff)

    // If n=2: S1={a[0]}, S2={a[1]}. Only one pair (a[0], a[1]) across subsequences.
    // f(a[0], a[1]) = a[0].value + a[1].value + h.
    // min_f = max_f = a[0].value + a[1].value + h. Goodness = 0.
    // This is better than Case 1 if h > 0.
    if (n == 2) {
        long long current_goodness = 0;
        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            best_partition[a[1].original_index] = 2;
        }
    } else { // n >= 3
        // Strategy: a[0] in S1, a[n-1] in S2, all others in S1.
        // S1 = {a[0], a[1], ..., a[n-2]}
        // S2 = {a[n-1]}
        long long current_min_f = a[0].value + a[1].value; // from S1
        long long current_max_f = a[n-2].value + a[n-1].value + h; // from S1-S2

        // Check if a[n-2] + a[n-3] (from S1) is greater than current_max_f
        if (n >= 3) { // a[n-3] exists
            current_max_f = std::max(current_max_f, a[n-2].value + a[n-3].value);
        }

        // Check if a[0] + a[n-1] + h (from S1-S2) is smaller than current_min_f
        current_min_f = std::min(current_min_f, a[0].value + a[n-1].value + h);

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            for (int i = 1; i < n - 1; ++i) {
                best_partition[a[i].original_index] = 1;
            }
            best_partition[a[n - 1].original_index] = 2;
        }

        // Strategy: a[0] in S1, a[n-1] in S2, all others in S2.
        // S1 = {a[0]}
        // S2 = {a[1], ..., a[n-1]}
        current_min_f = a[1].value + a[2].value; // from S2
        current_max_f = a[n-1].value + a[n-2].value; // from S2

        // Check if a[0] + a[n-1] + h (from S1-S2) is greater than current_max_f
        current_max_f = std::max(current_max_f, a[0].value + a[n-1].value + h);

        // Check if a[0] + a[1] + h (from S1-S2) is smaller than current_min_f
        current_min_f = std::min(current_min_f, a[0].value + a[1].value + h);

        current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            for (int i = 1; i < n - 1; ++i) {
                best_partition[a[i].original_index] = 2;
            }
            best_partition[a[n - 1].original_index] = 2;
        }
    }

    // Consider a special case for n >= 3:
    // S1 = {a[0], a[n-1]}
    // S2 = {a[1], ..., a[n-2]}
    //
    // Pairs in S1: a[0].value + a[n-1].value
    // Pairs in S2: min = a[1].value + a[2].value, max = a[n-2].value + a[n-3].value
    // Pairs across S1-S2:
    // min = a[0].value + a[1].value + h
    // max = a[n-1].value + a[n-2].value + h
    //
    // This strategy is only relevant if n >= 4 for S2 to have at least two elements.
    // If n=3: S1={a[0], a[2]}, S2={a[1]}.
    // Pairs in S1: a[0].value + a[2].value
    // Pairs in S2: None
    // Pairs across S1-S2:
    // a[0].value + a[1].value + h
    // a[2].value + a[1].value + h
    //
    // min_f = min(a[0].value + a[2].value, a[0].value + a[1].value + h)
    // max_f = max(a[0].value + a[2].value, a[2].value + a[1].value + h)
    //
    // This is a specific partition that might be optimal.
    // Let's check this for n >= 3.
    if (n >= 3) {
        long long current_min_f;
        long long current_max_f;

        // S1 = {a[0], a[n-1]}, S2 = {a[1], ..., a[n-2]}
        // min_f candidates:
        //   a[0].value + a[n-1].value (from S1)
        //   a[0].value + a[1].value + h (from S1-S2)
        //   a[1].value + a[2].value (from S2, if n-2 >= 2, i.e., n >= 4)
        // max_f candidates:
        //   a[0].value + a[n-1].value (from S1)
        //   a[n-1].value + a[n-2].value + h (from S1-S2)
        //   a[n-2].value + a[n-3].value (from S2, if n-2 >= 2, i.e., n >= 4)

        current_min_f = a[0].value + a[n-1].value;
        current_max_f = a[0].value + a[n-1].value;

        current_min_f = std::min(current_min_f, a[0].value + a[1].value + h);
        current_max_f = std::max(current_max_f, a[n-1].value + a[n-2].value + h);

        if (n >= 4) { // S2 has at least two elements
            current_min_f = std::min(current_min_f, a[1].value + a[2].value);
            current_max_f = std::max(current_max_f, a[n-2].value + a[n-3].value);
        } else if (n == 3) { // S2 has only one element a[1], no same-subsequence pairs in S2
            // No additional min/max from S2 same-subsequence pairs
        }

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            best_partition[a[n - 1].original_index] = 1;
            for (int i = 1; i < n - 1; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

