int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick n numbers from 2n+1 to 4n,
        // but only the even numbers.
        // This ensures:
        // 1. All numbers are even, so gcd(a,b) >= 2.
        // 2. For any two numbers a, b in the set, if a < b, then 2a > b.
        //    This prevents a from dividing b.
        //    The smallest number we pick is 2n+2 (if n is even) or 2n+1 (if n is odd, then 2n+2).
        //    The smallest number is at least 2n+2.
        //    The largest number is at most 4n.
        //    If a divides b, then b >= 2a.
        //    But here, if a, b are from the chosen set and a < b, then a >= 2n+2.
        //    So 2a >= 4n+4.
        //    Since b <= 4n, it's impossible for b >= 2a.
        //    Thus, a cannot divide b.
        //    Example: n=2, range [1,8]. We need 2 numbers.
        //    Numbers from 2n+1 to 4n are [5, 8]. Even numbers are 6, 8.
        //    gcd(6,8)=2. 6 does not divide 8. 8 does not divide 6. Correct.
        //    Example: n=3, range [1,12]. We need 3 numbers.
        //    Numbers from 2n+1 to 4n are [7, 12]. Even numbers are 8, 10, 12.
        //    gcd(8,10)=2, gcd(8,12)=4, gcd(10,12)=2.
        //    No number divides another. Correct.
        //    Example: n=4, range [1,16]. We need 4 numbers.
        //    Numbers from 2n+1 to 4n are [9, 16]. Even numbers are 10, 12, 14, 16.
        //    gcd(10,12)=2, gcd(10,14)=2, gcd(10,16)=2, gcd(12,14)=2, gcd(12,16)=4, gcd(14,16)=2.
        //    No number divides another. Correct.

        for (int i = 0; i < n; ++i) {
            std::cout << 2 * n + 2 * (i + 1) << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

