    while (t--) {
        int n;
        std::cin >> n;
        if (360 % n == 0) { // This condition is equivalent to 360 / n being an integer.
                            // If 360/n is an integer, then 90 is a multiple of 360/n.
                            // This means 90 = k * (360/n) for some integer k.
                            // This simplifies to n = 4k.
                            // So, n must be a multiple of 4.
                            // However, the problem states that the angle between edge normals is 360/n.
                            // We need one normal at 0 degrees (or 180) and another at 90 degrees (or -90).
                            // This means 90 degrees must be a multiple of 360/n.
                            // 90 = k * (360/n)
                            // 1 = k * (4/n)
                            // n = 4k
                            // So, n must be a multiple of 4.
                            // The condition 360 % n == 0 is not sufficient.
                            // For example, if n=3, 360%3==0, but 3 is not a multiple of 4.
                            // If n=6, 360%6==0, but 6 is not a multiple of 4.
                            // The correct condition is that 90 degrees must be an integer multiple of the smallest angle between edge normals.
                            // The smallest angle between edge normals is 360/n.
                            // So, 90 / (360/n) must be an integer.
                            // 90n / 360 must be an integer.
                            // n / 4 must be an integer.
                            // This means n must be a multiple of 4.
            if (n % 4 == 0) {
                std::cout << "YES\n";
            } else {
                std::cout << "NO\n";
            }
        } else {
            // If 360 % n != 0, it means the polygon cannot be rotated such that one edge is horizontal
            // and another is vertical.
            // The angles of the normals of the edges, relative to some reference, are 0, 360/n, 2*360/n, ..., (n-1)*360/n.
            // For an edge to be parallel to OX, its normal must be at 90 degrees (or -90).
            // For an edge to be parallel to OY, its normal must be at 0 degrees (or 180).
            // This means we need to find a rotation angle 'alpha' such that:
            // (k * 360/n + alpha) % 360 == 0 (or 180) for some integer k
            // (j * 360/n + alpha) % 360 == 90 (or -90) for some integer j
            // This implies that the difference between these two angles must be 90 degrees (or 270).
            // So, ( (k - j) * 360/n ) % 360 == 90 (or 270).
            // Let m = k - j. Then (m * 360/n) % 360 == 90.
            // This means m * 360/n must be a multiple of 90.
            // m * 360/n = 90 * P for some integer P.
            // m * 4/n = P
            // n = 4m/P.
            // This implies that n must be a multiple of 4.
            // The condition 360 % n == 0 is not directly relevant to the problem's core logic.
            // The core logic is whether 90 degrees can be formed by integer multiples of 360/n.
            // This is equivalent to checking if n is a multiple of 4.
