#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // The flags `has_one` and `has_minus_one` reflect the state of elements
            // at indices < i, which are relevant for operations on a[i].
            // If a[i] is 1 or -1, it contributes to the flags for elements at indices < i.
            // But we are iterating backwards, so the flags should reflect elements at indices < current i.
            // This means we need to update flags *after* checking a[i] vs b[i].
            // The current flags `has_one` and `has_minus_one` are for elements at indices <= i.
            // When we move to i-1, we need to remove a[i]'s contribution.
            // This logic is tricky. Let's re-evaluate.
        } else if (a[i] < b[i]) {
            if (!has_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            if (!has_minus_one) {
                possible = false;
                break;
            }
        }

        // Update has_one and has_minus_one for the next iteration (i-1)
        // These flags should reflect elements at indices < i.
        // So, if a[i] was 1 or -1, it's no longer available for elements at indices < i.
        // This means we need to check if there are other 1s or -1s at indices < i.
        // This requires recomputing or maintaining counts.
        // A simpler approach is to iterate forward.
    }

    // Let's try iterating forward.
    // When checking a[i], we need to know if there's a 1 or -1 at some index k < i.
    // We can maintain `has_one_prefix` and `has_minus_one_prefix` flags.
    has_one = false; // Reset for forward pass
    has_minus_one = false; // Reset for forward pass
    possible = true;

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] < b[i]) { // Need to increase a[i]
                if (!has_one) {
                    possible = false;
                    break;
                }
            } else { // a[i] > b[i], need to decrease a[i]
                if (!has_minus_one) {
                    possible = false;
                    break;
                }
            }
        }
        // Update flags for the next iteration (i+1)
        // These flags reflect elements at indices <= i.
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

