int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int current_gap = 0;
        // The frog starts at cell 0.
        // The first 'R' character is at index 0 (s[0]).
        // The distance from cell 0 to the first 'R' cell is 1.
        // The distance from the last 'R' cell to cell n+1 is also important.
        // We can model this by adding an implicit 'R' at index -1 (cell 0)
        // and an implicit 'R' at index n (cell n+1).
        // So, we are looking for the maximum distance between consecutive 'R's,
        // including the start (cell 0) and end (cell n+1).

        // Let's consider the positions of 'R's.
        // The frog must jump from 0 to some cell i, where s[i] is 'R'.
        // Then from cell i to cell j, where s[j] is 'R', and so on.
        // Finally, from some cell k (s[k] is 'R') to cell n+1.

        // Let's find the positions of all 'R's.
        // We can simplify this by considering the "last safe R position".
        // The frog starts at cell 0.
        // The "last R position" seen so far, including the implicit start at -1 (cell 0).
        int last_r_pos = -1; 

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The gap is the distance from the previous 'R' position to the current 'R' position.
                // If last_r_pos is -1 (cell 0), and current 'R' is at index i (cell i+1),
                // the gap is (i+1) - (0) = i+1.
                // If last_r_pos is j (cell j+1), and current 'R' is at index i (cell i+1),
                // the gap is (i+1) - (j+1) = i - j.
                max_gap = std::max(max_gap, (i + 1) - (last_r_pos + 1));
                last_r_pos = i;
            }
        }
        // After iterating through the string, we need to consider the gap from the last 'R'
        // to the target cell n+1.
        // The last 'R' was at index last_r_pos (cell last_r_pos + 1).
        // The target is cell n+1.
        // The gap is (n+1) - (last_r_pos + 1).
        max_gap = std::max(max_gap, (int)s.length() + 1 - (last_r_pos + 1));

        std::cout << max_gap << "\n";
    }
    return 0;
}

