            }
        }
    }

    std::vector<int> p(n);
    if (max_val_in_matrix == n - 1) {
        // Case 1: The permutation contains n-1, meaning n is present in some p_i.
        // The maximum value in the entire matrix is n-1.
        // This implies that for the element p_k = n, all a[k][j] (j!=k) will be p_j.
        // The maximum of these p_j values will be n-1.
        // So, if the global maximum is n-1, then n must be one of the p_i values.
        // To find p_i, we look at the maximum value in row i (excluding a[i][i]).
        // If p_i is n, then max(a[i][j] for j!=i) will be n-1.
        // If p_i is not n, then max(a[i][j] for j!=i) will be max(p_i, max(p_j for j!=i and p_j < p_i), n if n is in p_j for some j!=i).
        // More simply, if p_i is not n, then there is some p_k = n.
        // Then a[i][k] = min(p_i, p_k) = min(p_i, n) = p_i.
        // So, p_i is present in row i.
        // The maximum value in row i (excluding a[i][i]) will be p_i if p_i is not n,
        // or n-1 if p_i is n.
        // This means p_i = max(a[i][j] for j!=i) unless p_i = n.
        // If p_i = n, then max(a[i][j] for j!=i) = n-1.
        // So, if max(a[i][j] for j!=i) == n-1, then p_i = n.
        // Otherwise, p_i = max(a[i][j] for j!=i).
        for (int i = 0; i < n; ++i) {
            int current_row_max = 0;
            for (int j = 0; j < n; ++j) {
                if (i == j) continue;
                if (a[i][j] > current_row_max) {
                    current_row_max = a[i][j];
                }
            }
            if (current_row_max == n - 1) {
                p[i] = n;
            } else {
                p[i] = current_row_max;
            }
        }
    } else {
        // Case 2: The permutation does not contain n-1.
        // This implies that n is not present in the permutation, which is impossible
        // as it's a permutation of 1 to n.
        // This case should not be reachable based on problem constraints (permutation of 1 to n).
        // However, if the problem meant "permutation of some n distinct integers",
        // and the max value in the matrix is M, then the largest element in the permutation is M.
        // But the problem states "permutation of integers from 1 to n".
        // So, max_val_in_matrix must be n-1.
        // Let's re-evaluate.
        // If p_k = n, then for any j != k, a[k][j] = min(n, p_j) = p_j.
        // The maximum value among these p_j is n-1.
        // So, the maximum value in the entire matrix must be n-1.
        // The logic for max_val_in_matrix == n-1 should always apply.
        // The problem guarantees a solution exists and it's a permutation of 1 to n.
        // So, the largest value in the permutation is n.
        // If p_i = n, then max_{j!=i} a[i][j] = n-1.
        // If p_i < n, then there is some p_k = n. Then a[i][k] = min(p_i, n) = p_i.
        // So, p_i is present in row i.
        // Thus, p_i = max_{j!=i} a[i][j] if p_i < n.
        // And p_i = n if max_{j!=i} a[i][j] = n-1.
        // This logic is sound and covers all cases for a permutation of 1 to n.
        // The `else` branch here is technically unreachable given the problem statement.
        // But for completeness, if `max_val_in_matrix` was, for example, `n`, it would mean
        // some `p_i` is `n` and some `p_j` is also `n`, which is not a permutation.
        // Or if `max_val_in_matrix` was `n-2`, it would mean `n-1` and `n` are not in the permutation.
        // The only consistent scenario is `max_val_in_matrix == n-1`.
        // So the code inside the `if` block is the only path.
        // This `else` branch is just a placeholder, it should not be hit.
        for (int i = 0; i < n; ++i) {
            int current_row_max = 0;
            for (int j = 0; j < n; ++j) {
                if (i == j) continue;
                if (a[i][j] > current_row_max) {
                    current_row_max = a[i][j];
                }
            }
            // This branch should not be hit if max_val_in_matrix is always n-1.
            // But if it were, and current_row_max was, say, n, it would be p[i] = n.
            // If current_row_max was less than n-1, it would be p[i] = current_row_max.
            // The logic for `n-1` is specific to the permutation being 1..n.
            // If max_val_in_matrix is not n-1, it implies a contradiction with the problem statement.
            // However, to satisfy the "any permutation" requirement, we can just use the same logic.
            // The problem guarantees a solution consistent with 1..n.
            // So, max_val_in_matrix will always be n-1.
            // This `else` block is effectively dead code.
            p[i] = current_row_max;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

