int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // With 2n students, if we sort them as a_0, a_1, ..., a_{2n-1},
        // and partition them into two classes of odd sizes,
        // the optimal strategy to minimize the difference between medians
        // is to assign the first n students to one class and the next n students
        // to the other class.
        //
        // Specifically, if Class 1 takes students a_0, ..., a_{n-1}
        // and Class 2 takes students a_n, ..., a_{2n-1},
        // both classes will have exactly n students.
        //
        // If n is odd, then both classes have an odd number of students,
        // and this is a valid partition.
        // The median of Class 1 (a_0, ..., a_{n-1}) is a_{(n-1)/2}.
        // The median of Class 2 (a_n, ..., a_{2n-1}) is a_{n + (n-1)/2}.
        //
        // If n is even, this partition is not valid because classes must have odd sizes.
        // However, the problem statement implies that such a partition is always possible.
        // The key insight is that the median of a sorted array of $2k+1$ elements is $b_{k+1}$ (1-indexed)
        // or $b_k$ (0-indexed).
        // For $2n$ students, the optimal strategy to minimize the difference between medians
        // is to take the $n$-th element (0-indexed $a_{n-1}$) and the $(n+1)$-th element (0-indexed $a_n$).
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // The smallest possible median for any class will be $a_0$.
        // The largest possible median for any class will be $a_{2n-1}$.
        //
        // The crucial observation is that to minimize the difference between medians,
        // we should pick two medians that are as close as possible in the sorted array.
        // The two "middle" elements of the entire sorted array are $a_{n-1}$ and $a_n$.
        //
        // We can always form two classes of odd sizes such that $a_{n-1}$ is the median of one class
        // and $a_n$ is the median of the other class.
        //
        // For example, Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        // This partition has $n$ students in each class.
        // If $n$ is odd, this is a valid partition. The medians are $a_{(n-1)/2}$ and $a_{n+(n-1)/2}$.
        //
        // The problem is simpler than it seems. The minimum difference is always between $a_{n-1}$ and $a_n$.
        // This is because any class of odd size $2k+1$ must contain $k$ elements smaller than its median
        // and $k$ elements larger than its median.
        //
        // If we pick $a_{n-1}$ as the median of one class and $a_n$ as the median of the other,
        // we can always construct valid classes.
        // For example, Class A could be $\{a_0, a_1, \dots, a_{n-1}\}$ and Class B could be $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // If $n$ is odd, this is a valid partition, and the medians are $a_{(n-1)/2}$ and $a_{n+(n-1)/2}$.
        //
        // The problem statement implies that the minimum difference is achieved by taking the two middle elements
        // of the *entire* sorted array as the medians of the two classes.
        // The elements $a_{n-1}$ and $a_n$ are the two elements closest to the "center" of the $2n$ elements.
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // We want to pick two elements $m_1$ and $m_2$ from this array to be the medians of the two classes.
        // To minimize $|m_1 - m_2|$, we should pick $m_1$ and $m_2$ to be adjacent in the sorted array.
        //
        // Let's say we pick $a_i$ as the median of Class 1 and $a_j$ as the median of Class 2.
        // Without loss of generality, assume $i < j$.
        // Class 1 must have $2k_1+1$ students, with $k_1$ students smaller than $a_i$ and $k_1$ students larger than $a_i$.
        // Class 2 must have $2k_2+1$ students, with $k_2$ students smaller than $a_j$ and $k_2$ students larger than $a_j$.
        //
        // The smallest possible median for any class is $a_0$.
        // The largest possible median for any class is $a_{2n-1}$.
        //
        // The problem is a known trick: after sorting, the minimum difference between medians of two odd-sized partitions
        // is simply the difference between the two middle elements of the entire sorted array.
        // These are $a_{n-1}$ and $a_n$ (using 0-based indexing for an array of size $2n$).
        //
        // Example 1: n=1, a = [1, 1]. Sorted: [1, 1]. $a_{1-1}=a_0=1$, $a_1=1$. Difference = $|1-1|=0$.
        // Example 2: n=3, a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6]. $a_{3-1}=a_2=3$, $a_3=4$. Difference = $|4-3|=1$.
        // Example 3: n=5, a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16]. Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // $a_{5-1}=a_4=8$, $a_5=13$. Difference = $|13-8|=5$.
        //
        // This pattern holds for all examples.
        // The logic is that to minimize the difference, the two medians must be as close as possible.
        // The two "middle" elements of the entire sorted array are $a_{n-1}$ and $a_n$.
        // We can always construct two valid odd-sized classes such that $a_{n-1}$ is the median of one and $a_n$ is the median of the other.
        //
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        // This partition has $n$ students in each class.
        // If $n$ is odd, this is a valid partition. The medians are $a_{(n-1)/2}$ and $a_{n+(n-1)/2}$.
        // This is not what the problem asks for. The problem asks for the minimum difference between *any* two valid classes.
        //
        // The key is that if you pick $a_{n-1}$ as the median of one class and $a_n$ as the median of the other,
        // you can always form valid classes.
        // For example, Class A: $\{a_0, a_1, \dots, a_{n-2}, a_{n-1}\}$ (size $n$)
        // Class B: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$ (size $n$)
        // If $n$ is odd, this works.
        //
        // What if $n$ is even? Say $n=2$. $2n=4$. Sorted: $a_0, a_1, a_2, a_3$.
        // We want to find $|a_2 - a_1|$.
        // We need two odd-sized classes. Possible sizes: (1, 3) or (3, 1).
        // If Class A has 1 student, its median is that student.
        // If Class B has 3 students, its median is the middle student.
        //
        // Let's try to make $a_1$ the median of a class and $a_2$ the median of another.
        // Class A (median $a_1$): needs $2k_A+1$ students. $a_1$ is the $k_A$-th element (0-indexed).
        // Smallest $k_A=0$, so size 1. Class A = $\{a_1\}$.
        // Remaining students: $\{a_0, a_2, a_3\}$.
        // Class B (median $a_2$): needs $2k_B+1$ students. $a_2$ is the $k_B$-th element (0-indexed).
        // We need to pick $k_B$ elements smaller than $a_2$ and $k_B$ elements larger than $a_2$ from the remaining.
        // From $\{a_0, a_2, a_3\}$, we can form Class B as $\{a_0, a_2, a_3\}$. Size 3. Median is $a_2$.
        // This is a valid partition: Class A = $\{a_1\}$, Class B = $\{a_0, a_2, a_3\}$.
        // Medians are $a_1$ and $a_2$. Difference is $|a_2 - a_1|$.
        // This construction always works.
        // For Class A (median $a_{n-1}$): take $a_{n-1}$ itself. This is a class of size 1.
        // For Class B (median $a_n$): take all remaining $2n-1$ students.
        // The remaining students are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // This set has $2n-1$ elements. Its median would be the $(n-1)$-th element (0-indexed) if sorted.
        // If we take $a_n$ as the median of Class B, we need to pick $k_B$ elements smaller than $a_n$ and $k_B$ elements larger than $a_n$.
        // We can pick $a_0, \dots, a_{n-1}$ (excluding $a_{n-1}$ if it's in Class A) and $a_{n+1}, \dots, a_{2n-1}$.
        //
        // The simplest construction that always works to achieve $a_n - a_{n-1}$ as the difference:
        // Class 1: $\{a_{n-1}\}$ (size 1, median $a_{n-1}$)
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ (size $2n-1$, median $a_n$)
        // This is a valid partition. Both classes have odd sizes (1 and $2n-1$).
        // The median of Class 1 is $a_{n-1}$.
        // The median of Class 2 (which consists of all elements except $a_{n-1}$) is $a_n$.
        // To see this, consider the elements for Class 2: $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // There are $n-1$ elements smaller than $a_n$ ($a_0, \dots, a_{n-2}$).
        // There are $n-1$ elements larger than $a_n$ ($a_{n+1}, \dots, a_{2n-1}$).
        // So $a_n$ is indeed the median of this set of $2n-1$ elements.
        //
        // Therefore, the minimum possible absolute difference is $a_n - a_{n-1}$.

        long long result = a[n] - a[n - 1];
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            if (mid == 0) { // Handle the case where mid is 0, it's always possible to form 0 teams
                ans = std::max(ans, mid);
                low = mid + 1;
                continue;
            }
            // To form 'mid' teams, we need 'mid' coders, 'mid' mathematicians, and 'mid' additional students.
            // The additional students can be coders, mathematicians, or unspecialized.
            // Total students needed: 3 * mid
            // Coders needed: at least mid
            // Mathematicians needed: at least mid
            // Remaining students to fill up to 3*mid: (3*mid - mid - mid) = mid
            // These 'mid' remaining slots can be filled by any available student.
            // The minimum number of students required for the 'mid' additional slots is 'mid'.
            // These 'mid' additional slots can be filled by:
            // 1. Remaining coders (c - mid)
            // 2. Remaining mathematicians (m - mid)
            // 3. Unspecialized students (x)
            // So, we need (c - mid) + (m - mid) + x >= mid
            // Which simplifies to c + m + x >= 3 * mid
            // And also c >= mid and m >= mid

            // The conditions for forming 'mid' teams are:
            // 1. c >= mid
            // 2. m >= mid
            // 3. c + m + x >= 3 * mid (total students constraint)
            // The first two are implicitly handled by the high bound calculation.
            // The third one is the critical check.

            if (c >= mid && m >= mid && (c + m + x) >= (3 * mid)) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

