    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0 && result.length() > (k / 2 - open_needed)) {
            // The condition result.length() > (k / 2 - open_needed) ensures that
            // we have at least one unmatched '(' in the current `result` string
            // that this ')' can potentially match.
            // (k / 2 - open_needed) is the count of '(' already added to `result`.
            // So, result.length() is the total characters in `result`.
            // If result.length() > (k / 2 - open_needed), it means
            // result.length() - (k / 2 - open_needed) > 0,
            // which is the current balance of `result` (number of '(' minus number of ')').
            // This ensures we don't add a ')' if it would make the prefix invalid.
            result += ')';
            close_needed--;
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    std::vector<int> available_for_fill;

    p[0] = q[0];
    used_values.insert(q[0]);

    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            p[i] = q[i];
            if (used_values.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i is a new max.
                // But as a safeguard, if it does, it's an invalid state.
                std::cout << -1 << "\n";
                return;
            }
            used_values.insert(q[i]);
        } else { // q[i] == q[i-1]
            // This position p[i] needs to be filled with an unused value
            // that is less than or equal to q[i].
            // We'll fill these later with the smallest available unused values.
            p[i] = -1; // Mark as placeholder
        }
    }

    // Collect all numbers from 1 to n that have not been used yet.
    for (int i = 1; i <= n; ++i) {
        if (!used_values.count(i)) {
            available_for_fill.push_back(i);
        }
    }
    std::sort(available_for_fill.rbegin(), available_for_fill.rend()); // Sort descending

    int fill_idx = 0;
    for (int i = 0; i < n; ++i) {
        if (p[i] == -1) {
            if (fill_idx >= available_for_fill.size()) {
                // Not enough numbers to fill placeholders
                std::cout << -1 << "\n";
                return;
            }
            int val_to_fill = available_for_fill[fill_idx];
            if (val_to_fill > q[i]) {
                // The smallest available number is greater than q[i],
                // which means p[i] would violate p[i] <= q[i].
                std::cout << -1 << "\n";
                return;
            }
            p[i] = val_to_fill;
            fill_idx++;
        }
    }

    // Final check for validity (optional, but good for robustness)
    // This check is mostly covered by the construction logic, but ensures no edge cases were missed.
    std::set<int> final_check_set;
    int current_max = 0;
    for (int i = 0; i < n; ++i) {
        if (p[i] < 1 || p[i] > n || final_check_set.count(p[i])) {
            std::cout << -1 << "\n";
            return;
        }
        final_check_set.insert(p[i]);
        current_max = std::max(current_max, p[i]);
        if (current_max != q[i]) {
            std::cout << -1 << "\n";
            return;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

