int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int current_val = 1;
    int diff_val = k;
    int left = 1;
    int right = k + 1; // The largest number used to generate differences 1 to k

    // Generate the first k+1 elements to produce k distinct differences
    // The differences will be k, k-1, ..., 1
    // Example: k=2. Differences 2, 1.
    // p_1 = 1
    // p_2 = 1+2 = 3 (diff 2)
    // p_3 = 3-1 = 2 (diff 1)
    // Sequence: 1 3 2
    // This uses numbers 1, 2, 3.
    // In general, this uses numbers from 1 to k+1.

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index (0, 2, 4, ...)
            p[i] = left;
            left++;
        } else { // Odd index (1, 3, 5, ...)
            p[i] = right;
            right--;
        }
    }

    // The remaining n - (k+1) elements should produce a difference of 1
    // to avoid introducing new distinct differences.
    // The last number placed was either 'left-1' or 'right+1'.
    // If 'left-1' was placed, the next number should be 'left'.
    // If 'right+1' was placed, the next number should be 'right'.
    // In both cases, the next available number in increasing order is 'left'.
    // The numbers used so far are 1, ..., k+1.
    // So, 'left' is now k+2.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This is equivalent to p[i] = left; left++;
                      // Since left starts at k+2 for index k+1,
                      // p[k+1] = k+2, p[k+2] = k+3, etc.
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

