#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        std::string s;
        std::cin >> s;
        int countL = 0;
        int countR = 0;
        int countU = 0;
        int countD = 0;
        for (char c : s) {
            if (c == 'L') {
                countL++;
            } else if (c == 'R') {
                countR++;
            } else if (c == 'U') {
                countU++;
            } else if (c == 'D') {
                countD++;
            }
        }

        int minLR = std::min(countL, countR);
        int minUD = std::min(countU, countD);

        // If there are no horizontal moves possible, but vertical moves are,
        // we can only form a path if vertical moves are also zero.
        // Otherwise, we can't return to (0,0).
        // Example: "UU" -> minLR=0, minUD=1. If we take 2U, we end at (0,2).
        // If we take 0U, we end at (0,0).
        // The problem states "visits no cell (except (0,0)) twice and ends the path in the cell (0,0)".
        // If minLR is 0, we can't move horizontally. If minUD is > 0, we can't form a cycle.
        // So if minLR is 0, minUD must also be 0 to form a path of length > 0.
        // Same logic for minUD being 0.
        if (minLR == 0 && minUD > 0) {
            minUD = 0; // Cannot form a cycle if only vertical moves are available
        }
        if (minUD == 0 && minLR > 0) {
            minLR = 0; // Cannot form a cycle if only horizontal moves are available
        }

        int total_length = 2 * minLR + 2 * minUD;
        std::cout << total_length << "\n";
        if (total_length > 0) {
            std::string result = "";
            for (int i = 0; i < minLR; ++i) {
                result += 'L';
            }
            for (int i = 0; i < minUD; ++i) {
                result += 'U';
            }
            for (int i = 0; i < minR; ++i) { // minR is minLR
                result += 'R';
            }
            for (int i = 0; i < minD; ++i) { // minD is minUD
                result += 'D';
            }
            std::cout << result << "\n";
        } else {
            std::cout << "\n"; // Print empty line if length is 0
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    int k = n - 1; // Start from the rightmost element

    // Find the rightmost peak for the decreasing suffix
    while (k > 0 && a[k-1] >= a[k]) {
        k--;
    }

    // If k is 0, the entire array is non-increasing from right to left.
    // This means it's either sorted or like [5,4,3,2,1].
    // In such a case, the array is good.
    // Example: [1,2,3,4] -> k=0. Good.
    // Example: [4,3,2,1] -> k=0. Good.
    // Example: [1,1,1] -> k=0. Good.
    if (k == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // k now points to the first element from the right that breaks the non-increasing suffix.
    // Example: [1,3,1,4,5,3,2]
    // k=6 (a[6]=2)
    // a[5]=3 >= a[6]=2 -> k=5 (a[5]=3)
    // a[4]=5 >= a[5]=3 -> k=4 (a[4]=5)
    // a[3]=4 < a[4]=5 -> stop. k=4.
    // The suffix [a[4], ..., a[n-1]] is [5,3,2]. This is non-increasing.
    // The element a[k-1] = a[3] = 4.
    // So, we have [..., 4, 5, 3, 2].
    // The "valley" is at index k-1.
    // We need to find the rightmost peak for the increasing suffix before this valley.

    int j = k; // j starts at k, which is the start of the non-increasing suffix
    // Find the rightmost peak for the increasing suffix
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }

    // j now points to the first element from the right that breaks the non-decreasing suffix.
    // Example: [1,3,1,4,5,3,2]
    // k=4 (a[4]=5)
    // j starts at k=4.
    // a[3]=4 <= a[4]=5 -> j=3 (a[3]=4)
    // a[2]=1 < a[3]=4 -> stop. j=3.
    // The suffix [a[3], ..., a[n-1]] is [4,5,3,2]. This is not non-decreasing.
    // The element a[j-1] = a[2] = 1.
    // So, we have [..., 1, 4, 5, 3, 2].
    // The "peak" is at index j-1.
    // The prefix to remove is of length j.

    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

