#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // For m = 1, the segment is just [1] at pos[1].
    // min is 1, max is 1, length is 1. So 1 is beautiful.
    result[0] = '1';

    for (int m = 2; m <= n; ++m) {
        // Expand the current segment [current_min_idx, current_max_idx]
        // to include the number 'm'.
        // The number 'm' is at pos[m].
        // We need to extend the segment to cover pos[m].
        // This means the new segment will be from min(current_min_idx, pos[m])
        // to max(current_max_idx, pos[m]).

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Now, the segment p[current_min_idx ... current_max_idx]
        // contains all numbers from 1 to m.
        // Its length is (current_max_idx - current_min_idx + 1).
        // If this length is equal to m, then m is beautiful.
        if (current_max_idx - current_min_idx + 1 == m) {
            result[m - 1] = '1';
        }
    }

    std::cout << result << "\n";
}

