    for (int left_ptr = 0; left_ptr < n; ++left_ptr) {
        // Advance right_ptr until x[right_ptr] - x[left_ptr] > d
        // or until right_ptr reaches the end of the array.
        // The points from x[left_ptr] to x[right_ptr-1] are valid candidates
        // for the 'farthest' point relative to x[left_ptr].
        while (right_ptr < n && x[right_ptr] - x[left_ptr] <= d) {
            right_ptr++;
        }

        // Now, for the current x[left_ptr], all points x[k] where left_ptr < k < right_ptr
        // satisfy x[k] - x[left_ptr] <= d.
        // We need to choose two points x[j] and x[k] such that left_ptr < j < k < right_ptr.
        // The number of available points for j and k is (right_ptr - 1) - (left_ptr + 1) + 1
        // which simplifies to right_ptr - 1 - left_ptr.
        // Let m = right_ptr - 1 - left_ptr. These are the points strictly between x[left_ptr]
        // and x[right_ptr-1] (inclusive).
        // If m < 2, we cannot choose two distinct points.
        // If m >= 2, we can choose C(m, 2) pairs.
        // The number of points available to choose from (excluding x[left_ptr]) is
        // (right_ptr - 1) - (left_ptr + 1) + 1 = right_ptr - left_ptr - 1.
        // Let num_intermediate_points = right_ptr - left_ptr - 1.
        // These are the points x[left_ptr+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these num_intermediate_points.
        // The number of ways to choose 2 points from num_intermediate_points is
        // num_intermediate_points * (num_intermediate_points - 1) / 2.

        // The number of points in the valid range [left_ptr, right_ptr-1] is (right_ptr - left_ptr).
        // We need to choose 3 points. One is x[left_ptr].
        // We need to choose 2 more points from the remaining (right_ptr - left_ptr - 1) points.
        // Let k_count = right_ptr - left_ptr. This is the total number of points in the valid window.
        // If k_count < 3, we cannot form a triplet.
        // If k_count >= 3, we can choose C(k_count - 1, 2) pairs for the middle and rightmost points,
        // given x[left_ptr] is fixed as the leftmost.
        // The number of points available to choose from, *after* x[left_ptr], is (right_ptr - 1) - (left_ptr + 1) + 1 = right_ptr - left_ptr - 1.
        // Let's call this `num_candidates_for_j_k`.
        long long num_candidates_for_j_k = static_cast<long long>(right_ptr - 1 - left_ptr);

        if (num_candidates_for_j_k >= 2) {
            count += num_candidates_for_j_k * (num_candidates_for_j_k - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

