#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a sub-array is a permutation of 1 to len
// Uses a frequency array (or boolean array) for efficiency.
// Assumes elements are 1-indexed and within [1, len].
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) return true; // An empty sequence can be considered a permutation of length 0
    if (len > arr.size() - start_idx) return false; // Not enough elements

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len; // All numbers from 1 to len must be present
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_val_a = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_val_a) {
            max_val_a = a[i];
        }
    }

    // Precompute prefix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    // Precompute suffix maximums
    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 can range from 1 to n-1.
    // If l1 = n, p1 would need to contain 'n', but max_val_a <= n-1.
    // If l2 = n, p2 would need to contain 'n', but max_val_a <= n-1.
    // So, 1 <= l1 <= n-1 and 1 <= l2 <= n-1.
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if the first part (p1) can be a permutation of length l1
        // Condition 1: Max element in p1 must be l1
        // Condition 2: All elements in p1 must be distinct and within [1, l1]
        bool p1_is_candidate = (prefix_max[l1 - 1] == l1);

        // Check if the second part (p2) can be a permutation of length l2
        // Condition 1: Max element in p2 must be l2
        // Condition 2: All elements in p2 must be distinct and within [1, l2]
        bool p2_is_candidate = (suffix_max[l1] == l2);

        if (p1_is_candidate && p2_is_candidate) {
            // If both parts satisfy the max value condition,
            // we need to perform a full check for distinctness and presence of all numbers.
            // This is the expensive part, so we do it only if max value condition holds.
            if (is_permutation(a, 0, l1) && is_permutation(a, l1, l2)) {
                results.push_back({l1, l2});
            }
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

