// Function to determine if a box can be the special box
// A: count in (-inf, -1]
// B: count in (-1, 0)
// C: count in (0, 1)
// D: count in [1, inf)
// target_box: 1, 2, 3, or 4
bool can_be_special(long long A, long long B, long long C, long long D, int target_box) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // If only one toy, it is the super toy. Check if it's in the target box.
    if (total_toys == 1) {
        if (A == 1 && target_box == 1) return true;
        if (B == 1 && target_box == 2) return true;
        if (C == 1 && target_box == 3) return true;
        if (D == 1 && target_box == 4) return true;
        return false;
    }

    // Parity of negative numbers determines the final sign.
    // Parity of numbers with magnitude > 1 determines if final magnitude can be > 1.
    // Parity of numbers with magnitude < 1 determines if final magnitude can be < 1.

    // Let's analyze the possible final states based on the number of negative values and magnitudes.
    // We need to consider the parity of A and B for the final sign.
    // We need to consider the presence of A or D for final magnitude > 1.
    // We need to consider the presence of B or C for final magnitude < 1.

    // The core idea is that we can always arrange multiplications to achieve certain outcomes.
    // For example, if we have a toy with magnitude > 1 and a toy with magnitude < 1,
    // we can make the product > 1, < 1, or even = 1 (if we pick specific values).
    // The only thing that is fixed is the parity of negative numbers.

    // Number of negative toys: A + B
    // Number of positive toys: C + D

    // Final sign:
    // If (A + B) is even, final product can be positive.
    // If (A + B) is odd, final product can be negative.

    // Final magnitude:
    // If A + D > 0 (at least one toy with |val| >= 1), and B + C > 0 (at least one toy with |val| < 1),
    // then we can potentially make the final product's magnitude > 1, < 1, or = 1.
    // Example: (2 * 0.5 = 1), (2 * 0.1 = 0.2), (10 * 0.5 = 5).
    // If A + D == 0, all toys have magnitude < 1. Final product magnitude must be < 1.
    // If B + C == 0, all toys have magnitude >= 1. Final product magnitude must be >= 1.

    // Let's simplify the conditions for each target box.

    // Box 1: (-inf, -1] (Negative, magnitude >= 1)
    // Requires:
    // 1. Final sign is negative: (A + B) must be odd.
    // 2. Final magnitude is >= 1:
    //    - If B + C == 0 (all initial toys have magnitude >= 1), then final magnitude is >= 1.
    //    - If A + D > 0 (at least one initial toy has magnitude >= 1), and B + C > 0 (at least one initial toy has magnitude < 1),
    //      we can always arrange multiplications to make the final magnitude >= 1.
    //      (e.g., multiply all <1 toys together, then multiply all >=1 toys together, then multiply the two results.
    //      If the product of <1 toys is P_small and product of >=1 toys is P_large, we can pick values such that P_small * P_large >= 1).
    //      This is true unless A+D=0, which is covered by the first case.
    //      So, if A+D > 0, it's possible to get magnitude >= 1.
    //      The only case where it's impossible to get magnitude >= 1 is if A+D=0 (all toys are B or C).
    //      So, condition for magnitude >= 1 is A + D > 0.

    bool possible_box1 = false;
    if ((A + B) % 2 == 1) { // Final sign is negative
        if (A + D > 0) { // Possible to get magnitude >= 1
            possible_box1 = true;
        }
    }

    // Box 2: (-1, 0) (Negative, magnitude < 1)
    // Requires:
    // 1. Final sign is negative: (A + B) must be odd.
    // 2. Final magnitude is < 1:
    //    - If A + D == 0 (all initial toys have magnitude < 1), then final magnitude is < 1.
    //    - If A + D > 0 and B + C > 0, we can always arrange multiplications to make the final magnitude < 1.
    //      (e.g., multiply all >1 toys together, then multiply all <1 toys together, then multiply the two results.
    //      If the product of >1 toys is P_large and product of <1 toys is P_small, we can pick values such that P_large * P_small < 1).
    //      This is true unless B+C=0, which is covered by the first case.
    //      So, if B+C > 0, it's possible to get magnitude < 1.
    //      The only case where it's impossible to get magnitude < 1 is if B+C=0 (all toys are A or D).
    //      So, condition for magnitude < 1 is B + C > 0.

    bool possible_box2 = false;
    if ((A + B) % 2 == 1) { // Final sign is negative
        if (B + C > 0) { // Possible to get magnitude < 1
            possible_box2 = true;
        }
    }

    // Box 3: (0, 1) (Positive, magnitude < 1)
    // Requires:
    // 1. Final sign is positive: (A + B) must be even.
    // 2. Final magnitude is < 1: B + C > 0.

    bool possible_box3 = false;
    if ((A + B) % 2 == 0) { // Final sign is positive
        if (B + C > 0) { // Possible to get magnitude < 1
            possible_box3 = true;
        }
    }

    // Box 4: [1, inf) (Positive, magnitude >= 1)
    // Requires:
    // 1. Final sign is positive: (A + B) must be even.
    // 2. Final magnitude is >= 1: A + D > 0.

    bool possible_box4 = false;
    if ((A + B) % 2 == 0) { // Final sign is positive
        if (A + D > 0) { // Possible to get magnitude >= 1
            possible_box4 = true;
        }
    }

    // Edge case: If A+B+C+D = 1, the above logic might be slightly off for magnitude.
    // But we handled total_toys == 1 at the beginning.
    // For total_toys > 1, the logic holds.
    // For example, if A=1, B=0, C=0, D=0, total_toys=1.
    // can_be_special(1,0,0,0,1) -> true (handled by total_toys==1)
    // can_be_special(1,0,0,0,2) -> false (handled by total_toys==1)
    // If A=1, B=1, C=0, D=0, total_toys=2.
    // A+B=2 (even).
    // A+D=1 > 0. B+C=1 > 0.
    // Box1: (A+B)%2=0, so false.
    // Box2: (A+B)%2=0, so false.
    // Box3: (A+B)%2=0, B+C>0 -> true. (e.g., -2 * -0.1 = 0.2)
    // Box4: (A+B)%2=0, A+D>0 -> true. (e.g., -2 * -0.6 = 1.2)
    // This seems correct.

    // The only remaining subtlety is when A+D=0 (all toys are B or C) or B+C=0 (all toys are A or D).
    // If A+D=0, then A=0, D=0. All toys are B or C. All magnitudes are < 1.
    // In this case, final magnitude must be < 1.
    // So, possible_box1 and possible_box4 must be false.
    // Our conditions:
    // possible_box1: (A+B)%2==1 && (A+D>0). If A+D=0, this is false. Correct.
    // possible_box4: (A+B)%2==0 && (A+D>0). If A+D=0, this is false. Correct.

    // If B+C=0, then B=0, C=0. All toys are A or D. All magnitudes are >= 1.
    // In this case, final magnitude must be >= 1.
    // So, possible_box2 and possible_box3 must be false.
    // Our conditions:
    // possible_box2: (A+B)%2==1 && (B+C>0). If B+C=0, this is false. Correct.
    // possible_box3: (A+B)%2==0 && (B+C>0). If B+C=0, this is false. Correct.

    // The logic seems robust for all cases where total_toys > 1.

    if (target_box == 1) return possible_box1;
    if (target_box == 2) return possible_box2;
    if (target_box == 3) return possible_box3;
    if (target_box == 4) return possible_box4;
    return false; // Should not reach here
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::cout << (can_be_special(A, B, C, D, 1) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special(A, B, C, D, 2) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special(A, B, C, D, 3) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special(A, B, C, D, 4) ? "Ya" : "Tidak") << "\n";
    }
    return 0;
}

