#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    long long current_score = 0;
    int wins_count = 0;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            wins_count++;
            if (i > 0 && s[i-1] == 'W') {
                current_score += 2;
            } else {
                current_score += 1;
            }
        }
    }

    if (k == 0) {
        std::cout << current_score << std::endl;
        return;
    }

    if (wins_count == 0) { // All L's
        if (k > 0) {
            // Change k L's to W's. Maximize consecutive wins.
            // If k >= n, change all to W's. Score = 2n - 1.
            // Otherwise, change k L's to W's. Score = 2k - 1.
            std::cout << std::min((long long)n, k) * 2 - 1 << std::endl;
        } else { // k == 0, already handled
            std::cout << 0 << std::endl;
        }
        return;
    }

    // If there are already wins, we want to fill gaps between them.
    // Find the first and last 'W'.
    int first_w = -1, last_w = -1;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (first_w == -1) {
                first_w = i;
            }
            last_w = i;
        }
    }

    std::vector<int> gaps;
    int current_gap = 0;
    bool in_gap = false;
    for (int i = first_w + 1; i < last_w; ++i) {
        if (s[i] == 'L') {
            current_gap++;
            in_gap = true;
        } else { // s[i] == 'W'
            if (in_gap) {
                gaps.push_back(current_gap);
                current_gap = 0;
                in_gap = false;
            }
        }
    }
    std::sort(gaps.begin(), gaps.end());

    // Fill gaps
    for (int gap_len : gaps) {
        if (k >= gap_len) {
            k -= gap_len;
            current_score += gap_len * 2 + 1; // Each L becomes W, connects two W blocks.
                                              // gap_len L's become W's.
                                              // Each of these new W's gets 2 points.
                                              // The W after the gap now gets 2 points instead of 1.
                                              // The W before the gap already got 2 points if it was part of a block.
                                              // The +1 is for the W after the gap changing from 1 to 2 points.
                                              // Example: W L L W -> W W W W. Score change: 0 -> 2*2+1 = 5.
                                              // Initial: W(1) L(0) L(0) W(1) -> 2.
                                              // Final: W(1) W(2) W(2) W(2) -> 7. Diff = 5.
                                              // This is equivalent to (gap_len * 2) for the new W's + 1 for the W after the gap.
        } else {
            break;
        }
    }

    // Use remaining k for leading/trailing L's
    // Leading L's
    long long leading_l_count = first_w;
    long long trailing_l_count = n - 1 - last_w;

    long long additional_wins = std::min(k, leading_l_count + trailing_l_count);
    current_score += additional_wins * 2; // Each new W adds 2 points because it extends a block of wins.
                                          // The first W in the block already gives 1 point.
                                          // If we add a W before the first W, it becomes W W...
                                          // The new W gets 1 point, the old first W gets 2 points. Net +2.
                                          // If we add a W after the last W, it becomes ...W W.
                                          // The new W gets 2 points. Net +2.

    std::cout << current_score << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is optimal for Chanek
                    chanek_coins += 1;
                    n -= 1;
                } else {
                    // If N is even, Chanek can take N/2 or 1.
                    // If Chanek takes N/2, opponent gets to play on N/2.
                    // If Chanek takes 1, opponent gets to play on N-1 (odd).
                    // Chanek wants to maximize his coins.
                    // Opponent wants to maximize their coins.
                    //
                    // Consider the next state for the opponent:
                    // If Chanek takes N/2: Opponent faces N/2.
                    // If Chanek takes 1: Opponent faces N-1.
                    //
                    // If N/2 is odd, opponent will take 1, leaving N/2 - 1 for Chanek.
                    // If N/2 is even, opponent might take N/4 or 1.
                    //
                    // The strategy for Chanek when N is even:
                    // If N is a power of 2 (e.g., 4, 8, 16, ...), taking N/2 is generally good.
                    // If N is even but not a power of 2 (e.g., 6, 10, 12, ...),
                    // taking 1 might be better to make the opponent face an odd number.
                    //
                    // Let's analyze the opponent's optimal move if Chanek takes N/2:
                    // If N/2 is odd, opponent takes 1.
                    // If N/2 is even, opponent takes N/4 (if N/2 > 2) or 1 (if N/2 = 2).
                    //
                    // The key insight is that if N is even, Chanek can choose to make the next state N-1 (odd)
                    // or N/2.
                    // If N/2 is odd, Chanek takes N/2. The opponent will then take 1 from N/2, leaving N/2-1.
                    // If N/2 is even, Chanek takes 1. The opponent will then take 1 from N-1, leaving N-2.
                    //
                    // This logic is flawed. The opponent also plays optimally.
                    //
                    // Let's re-evaluate:
                    // If N is odd, Chanek must take 1.
                    // If N is even:
                    //   Option A: Chanek takes 1. Remaining N-1 (odd).
                    //   Option B: Chanek takes N/2. Remaining N/2.
                    //
                    // Chanek wants to maximize his coins.
                    // Opponent wants to maximize their coins.
                    //
                    // If N is even, and N is not a power of 2, then N has an odd factor.
                    // Example: N=6.
                    // Chanek takes 1. N=5. Chanek=1. Opponent faces 5. Opponent takes 1. N=4. Opponent=1. Chanek faces 4.
                    //   Chanek takes 2. N=2. Chanek=1+2=3. Opponent faces 2. Opponent takes 1. N=1. Opponent=1+1=2. Chanek faces 1.
                    //     Chanek takes 1. N=0. Chanek=3+1=4. Opponent=2. Total Chanek=4.
                    // Chanek takes 3. N=3. Chanek=3. Opponent faces 3. Opponent takes 1. N=2. Opponent=1. Chanek faces 2.
                    //   Chanek takes 1. N=1. Chanek=3+1=4. Opponent faces 1. Opponent takes 1. N=0. Opponent=1+1=2. Total Chanek=4.
                    //
                    // It seems for N=6, Chanek gets 4.
                    //
                    // The optimal strategy for Chanek when N is even:
                    // If N is a power of 2 (N = 2^k, k >= 1):
                    //   Chanek takes N/2. Opponent faces N/2 (which is 2^(k-1)).
                    //   This continues until N=2.
                    //   Example N=4: Chanek takes 2. N=2. Chanek=2. Opponent faces 2. Opponent takes 1. N=1. Opponent=1. Chanek faces 1.
                    //     Chanek takes 1. N=0. Chanek=2+1=3. Opponent=1.
                    //   Example N=8: Chanek takes 4. N=4. Chanek=4. Opponent faces 4. Opponent takes 2. N=2. Opponent=2. Chanek faces 2.
                    //     Chanek takes 1. N=1. Chanek=4+1=5. Opponent faces 1. Opponent takes 1. N=0. Opponent=2+1=3.
                    //   In general, for N=2^k, Chanek gets 2^k - (2^k/3) if k is odd, and 2^k - (2^k/3) if k is even.
                    //   This is not quite right.
                    //   For N=2^k, Chanek takes N/2. Opponent takes N/4. Chanek takes N/8. Opponent takes N/16...
                    //   This continues until N=2.
                    //   Chanek's coins: N/2 + N/8 + N/32 + ...
                    //   Opponent's coins: N/4 + N/16 + N/64 + ...
                    //   The last two coins:
                    //   If N=2, Chanek takes 1, Opponent takes 1.
                    //   If N=4, Chanek takes 2. Opponent faces 2. Opponent takes 1. Chanek faces 1. Chanek takes 1.
                    //     Chanek: 2+1=3. Opponent: 1.
                    //   If N=8, Chanek takes 4. Opponent faces 4. Opponent takes 2. Chanek faces 2. Chanek takes 1. Opponent faces 1. Opponent takes 1.
                    //     Chanek: 4+1=5. Opponent: 2+1=3.
                    //   If N=16, Chanek takes 8. Opponent faces 8. Opponent takes 4. Chanek faces 4. Chanek takes 2. Opponent faces 2. Opponent takes 1. Chanek faces 1. Chanek takes 1.
                    //     Chanek: 8+2+1=11. Opponent: 4+1=5.
                    //   This pattern is: Chanek gets sum of 2^k, 2^(k-3), 2^(k-5), ... until 1.
                    //   Opponent gets sum of 2^(k-1), 2^(k-4), 2^(k-6), ... until 1.
                    //   This is for powers of 2.
                    //
                    // If N is even and not a power of 2:
                    //   Chanek takes 1. N becomes N-1 (odd).
                    //   Opponent faces N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                    //   Chanek faces N-2 (even).
                    //   This strategy ensures that Chanek always faces an even number (if N was initially even and not a power of 2)
                    //   and the opponent always faces an odd number.
                    //   When opponent faces an odd number, they can only take 1.
                    //   So, if Chanek takes 1, opponent takes 1. N decreases by 2.
                    //   Chanek gets 1, opponent gets 1.
                    //   This continues until N becomes a power of 2 or 0.
                    //   Example N=6:
                    //   Chanek takes 1. N=5. Chanek=1. Opponent faces 5.
                    //   Opponent takes 1. N=4. Opponent=1. Chanek faces 4.
                    //   Now N=4 (power of 2). Chanek applies power of 2 strategy.
                    //   Chanek takes 2. N=2. Chanek=1+2=3. Opponent faces 2.
                    //   Opponent takes 1. N=1. Opponent=1+1=2. Chanek faces 1.
                    //   Chanek takes 1. N=0. Chanek=3+1=4. Opponent=2.
                    //   Total Chanek = 4.
                    //
                    // This strategy seems to be:
                    // If N is odd: Chanek takes 1.
                    // If N is even:
                    //   If N is a power of 2: Chanek takes N/2.
                    //   If N is even but not a power of 2: Chanek takes 1.
                    //
                    // Let's test this strategy.
                    // N=5 (odd): Chanek takes 1. N=4. Chanek=1. Opponent faces 4.
                    //   Opponent (faces 4, power of 2): Opponent takes 2. N=2. Opponent=2. Chanek faces 2.
                    //   Chanek (faces 2, power of 2): Chanek takes 1. N=1. Chanek=1+1=2. Opponent faces 1.
                    //   Opponent (faces 1, odd): Opponent takes 1. N=0. Opponent=2+1=3.
                    //   Chanek=2. Opponent=3. This matches example output.
                    //
                    // N=6 (even, not power of 2): Chanek takes 1. N=5. Chanek=1. Opponent faces 5.
                    //   Opponent (faces 5, odd): Opponent takes 1. N=4. Opponent=1. Chanek faces 4.
                    //   Chanek (faces 4, power of 2): Chanek takes 2. N=2. Chanek=1+2=3. Opponent faces 2.
                    //   Opponent (faces 2, power of 2): Opponent takes 1. N=1. Opponent=1+1=2. Chanek faces 1.
                    //   Chanek (faces 1, odd): Chanek takes 1. N=0. Chanek=3+1=4. Opponent=2.
                    //   Chanek=4. Opponent=2. This matches example output.

                    // Check if N is a power of 2
                    if ((n & (n - 1)) == 0) { // N is a power of 2
                        chanek_coins += n / 2;
                        n /= 2;
                    } else { // N is even but not a power of 2
                        chanek_coins += 1;
                        n -= 1;
                    }
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is optimal for opponent
                    opponent_coins += 1;
                    n -= 1;
                } else {
                    // Opponent's strategy is symmetric to Chanek's, but they want to maximize their own coins.
                    // If N is a power of 2, opponent takes N/2.
                    // If N is even but not a power of 2, opponent takes 1.
                    if ((n & (n - 1)) == 0) { // N is a power of 2
                        opponent_coins += n / 2;
                        n /= 2;
                    } else { // N is even but not a power of 2
                        opponent_coins += 1;
                        n -= 1;
                    }
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

