#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // If the array is already good, append 0 elements.
    if (current_sum == 2 * current_xor) {
        std::cout << 0 << "\n\n";
        return;
    }

    // We need to append at most 3 elements.
    // Let's try to append 2 elements.
    // We want to find b1, b2 such that:
    // (current_sum + b1 + b2) = 2 * (current_xor ^ b1 ^ b2)
    // Let b1 = current_xor.
    // Then the XOR sum becomes current_xor ^ current_xor ^ b2 = b2.
    // The sum becomes current_sum + current_xor + b2.
    // So we need:
    // current_sum + current_xor + b2 = 2 * b2
    // current_sum + current_xor = b2
    // So, b2 = current_sum + current_xor.

    // Let's verify this.
    // Appended elements: b1 = current_xor, b2 = current_sum + current_xor.
    // New sum: S' = current_sum + current_xor + (current_sum + current_xor) = 2 * current_sum + 2 * current_xor.
    // New XOR sum: X' = current_xor ^ current_xor ^ (current_sum + current_xor) = current_sum + current_xor.
    // Check condition: S' = 2 * X'
    // (2 * current_sum + 2 * current_xor) = 2 * (current_sum + current_xor)
    // This is always true.

    // The problem states that appended elements don't have to be different.
    // The problem states that appended elements can be up to 10^18.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor can be up to 2^60 (approx 10^18).
    // So current_sum + current_xor can be up to 10^14 + 10^18, which fits in long long.

    long long b1 = current_xor;
    long long b2 = current_sum + current_xor;

    std::cout << 2 << "\n";
    std::cout << b1 << " " << b2 << "\n";
}

