    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end());

        long long total_happiness = 0;

        // Friends who receive w_i = 1 integers
        // These friends get 2 * a_j. To maximize, they should get the largest available numbers.
        // Since we sorted 'a' ascending, the largest numbers are at the end.
        // Since we sorted 'w' ascending, w_0, w_1, ... are the smallest w_i values.
        // So, friends with w_i = 1 will be at the beginning of the sorted 'w' array.
        // We assign the largest available numbers from 'a' to these friends.
        int a_ptr_max = n - 1;
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] == 1) {
                total_happiness += 2 * a[a_ptr_max];
                a_ptr_max--;
            } else {
                // All remaining w[i] will be > 1, as w is sorted.
                // We can break here because we'll handle these in the next loop.
                break;
            }
        }

        // Friends who receive w_i > 1 integers
        // For these friends, happiness is max_val + min_val.
        // To maximize, they should get the largest available max_val and smallest available min_val.
        // The largest available max_val should come from the remaining largest numbers in 'a'.
        // The smallest available min_val should come from the smallest numbers in 'a'.
        // We iterate through w from smallest to largest (w_0, w_1, ...).
        // These friends will take w_i numbers.
        // The largest w_i values (which are at the end of the sorted 'w' array)
        // should be paired with the largest remaining numbers from 'a' for their max_val.
        // The smallest w_i values (which are at the beginning of the sorted 'w' array)
        // should be paired with the smallest remaining numbers from 'a' for their min_val.

        int a_ptr_min = 0;
        for (int i = 0; i < k; ++i) {
            if (w[i] > 1) {
                // This friend gets w[i] numbers.
                // Their max_val should be one of the largest remaining numbers.
                // Their min_val should be one of the smallest remaining numbers.
                // We assign a[a_ptr_max] as their max_val.
                total_happiness += a[a_ptr_max];
                a_ptr_max--;

                // They also need w[i] - 1 more numbers.
                // These w[i] - 1 numbers, plus the min_val, will be taken from the smallest available numbers.
                // The min_val for this friend will be a[a_ptr_min].
                total_happiness += a[a_ptr_min];
                a_ptr_min += (w[i] - 1); // Move a_ptr_min past the w[i]-1 smallest numbers
                a_ptr_min++; // Move a_ptr_min past the min_val itself
            }
        }
        std::cout << total_happiness << "\n";
    }
    return 0;
}

