#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int consecutive_ones = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        if (chain[0] == 1) {
            // This chain starts with 1.
            // We need to find how many consecutive numbers from 1 are in this chain.
            int current_consecutive = 0;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == j + 1) {
                    current_consecutive++;
                } else {
                    break;
                }
            }
            consecutive_ones = current_consecutive;
        }
    }

    // Operations to disassemble:
    // Each chain of length m_i requires m_i - 1 "get out" operations to fully disassemble it
    // into individual dolls.
    // Total dolls = n. Total chains = k.
    // Total "get out" operations if all chains were fully disassembled: n - k.
    // However, we don't need to disassemble the "good" part of the chain starting with 1.
    // The "good" part is 1 -> 2 -> ... -> consecutive_ones.
    // This part has (consecutive_ones - 1) existing nestings that we want to keep.
    // So, we save (consecutive_ones - 1) "get out" operations.
    // The number of "get out" operations is (n - k) - (consecutive_ones - 1).
    // If consecutive_ones is 0, it means no chain starts with 1, or 1 is not followed by 2.
    // In this case, consecutive_ones - 1 would be -1, which is incorrect.
    // The number of existing nestings we want to keep is max(0, consecutive_ones - 1).
    // So, disassembly cost = (n - k) - max(0, consecutive_ones - 1).
    // This simplifies to n - k - consecutive_ones + 1.
    total_operations += (n - k); // Initial disassembly cost if all chains were length 1
    total_operations -= (consecutive_ones - 1); // Savings from the good part of the 1-chain

    // Operations to assemble:
    // We need to form the chain 1 -> 2 -> ... -> n. This requires n - 1 total nestings.
    // We already have (consecutive_ones - 1) nestings in place (1->2, 2->3, ..., (consecutive_ones-1)->consecutive_ones).
    // So, we need to perform (n - 1) - (consecutive_ones - 1) new "put in" operations.
    // This simplifies to n - consecutive_ones.
    total_operations += (n - consecutive_ones);

    std::cout << total_operations << std::endl;

    return 0;
}

