int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        std::string current_coloring(n, ' ');
        char last_char_1 = '0' - 1; // Smaller than any digit
        char first_char_2 = '9' + 1; // Larger than any digit
        bool possible_for_pivot = true;

        // First pass: assign digits strictly less than pivot to color 1,
        // strictly greater than pivot to color 2.
        // Digits equal to pivot are temporarily unassigned.
        for (int i = 0; i < n; ++i) {
            if (s[i] < (char)('0' + pivot_digit)) {
                current_coloring[i] = '1';
                if (s[i] < last_char_1) {
                    possible_for_pivot = false;
                    break;
                }
                last_char_1 = s[i];
            } else if (s[i] > (char)('0' + pivot_digit)) {
                current_coloring[i] = '2';
            }
        }

        if (!possible_for_pivot) {
            continue;
        }

        // Second pass: assign digits equal to pivot.
        // Those appearing before the first '2' (from a digit > pivot) go to '1'.
        // Those appearing after or at the first '2' (from a digit > pivot) go to '2'.
        // This ensures that all '1's are <= pivot_digit and all '2's are >= pivot_digit.
        // And also maintains non-decreasing order for '1's and '2's separately.

        // Find the first position where a '2' was assigned due to s[i] > pivot_digit
        int first_two_idx = n;
        for(int i = 0; i < n; ++i) {
            if (current_coloring[i] == '2') {
                first_two_idx = i;
                break;
            }
        }

        for (int i = 0; i < n; ++i) {
            if (s[i] == (char)('0' + pivot_digit)) {
                if (i < first_two_idx) {
                    current_coloring[i] = '1';
                    if (s[i] < last_char_1) { // This check is redundant if last_char_1 is updated correctly
                        possible_for_pivot = false;
                        break;
                    }
                    last_char_1 = s[i];
                } else {
                    current_coloring[i] = '2';
                }
            }
        }

        if (!possible_for_pivot) {
            continue;
        }

        // Final check for the constructed coloring
        std::string s1_str = "";
        std::string s2_str = "";
        for (int i = 0; i < n; ++i) {
            if (current_coloring[i] == '1') {
                s1_str += s[i];
            } else { // current_coloring[i] == '2'
                s2_str += s[i];
            }
        }

        bool s1_sorted = true;
        for (size_t i = 0; i + 1 < s1_str.length(); ++i) {
            if (s1_str[i] > s1_str[i+1]) {
                s1_sorted = false;
                break;
            }
        }
        if (!s1_sorted) continue;

        bool s2_sorted = true;
        for (size_t i = 0; i + 1 < s2_str.length(); ++i) {
            if (s2_str[i] > s2_str[i+1]) {
                s2_sorted = false;
                break;
            }
        }
        if (!s2_sorted) continue;

        if (!s1_str.empty() && !s2_str.empty() && s1_str.back() > s2_str.front()) {
            continue;
        }

        result = current_coloring;
        found_solution = true;
        break; // Found a solution, no need to check other pivot_digits
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>
#include <map>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    // p is divisible by q. We need to find a divisor of p, say x, such that x is not divisible by q.
    // We want the largest such x.
    // This means we need to "remove" some factors from p such that the resulting number is no longer divisible by q.
    // To maximize x, we should remove as few factors as possible, and specifically,
    // remove factors that are "critical" for q's divisibility.

    // Factorize q into its prime factors.
    std::map<long long, int> q_prime_factors;
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            while (temp_q % i == 0) {
                q_prime_factors[i]++;
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        q_prime_factors[temp_q]++;
    }

    long long max_x = 0;

    // For each prime factor f of q, we try to construct a candidate x.
    // A candidate x is formed by taking p and dividing it by f until it's no longer divisible by q.
    // Specifically, for each prime factor f of q, we find the highest power of f that divides p.
    // Let p = f^a * R, where R is not divisible by f.
    // Let q = f^b * S, where S is not divisible by f.
    // Since p is divisible by q, we must have a >= b.
    // To make x not divisible by q, we need to reduce the power of f in x to be less than b.
    // The largest such x would be p / f^b.
    // However, this is not quite right. We need to ensure x is not divisible by q.
    // If we divide p by f, we get p/f. If p/f is still divisible by q, we divide again.
    // We keep dividing p by f until p is no longer divisible by q.
    // The largest such value would be p / f^(k+1) where f^k is the highest power of f that divides p/q.
    // No, this is also not quite right.

    // Let's rephrase: we want to find the largest divisor x of p such that x % q != 0.
    // Since p % q == 0, p is not a valid x.
    // We iterate through all prime factors `f` of `q`.
    // For each `f`, we consider `p / f`. If `p / f` is still divisible by `q`, we divide by `f` again.
    // We continue this until `p / f^k` is not divisible by `q`.
    // The largest such `p / f^k` is a candidate for `max_x`.
    // We do this for each distinct prime factor of `q`.

    for (auto const& [factor, count] : q_prime_factors) {
        long long current_p = p;
        // While current_p is divisible by q, and current_p is also divisible by factor,
        // divide current_p by factor.
        // This ensures that we remove just enough factors of 'factor' from 'p'
        // to make it not divisible by 'q', while keeping it as large as possible.
        while (current_p % q == 0) {
            current_p /= factor;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

