void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?'); // Stores the determined character for each position modulo k

    // Step 1: Propagate known characters and check for conflicts
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            int remainder = i % k;
            if (fixed_chars[remainder] == '?') {
                fixed_chars[remainder] = s[i];
            } else if (fixed_chars[remainder] != s[i]) {
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Count '0's and '1's among the fixed characters in the first k positions
    int count0 = 0;
    int count1 = 0;
    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            count0++;
        } else if (fixed_chars[i] == '1') {
            count1++;
        }
    }

    // Step 3: Check if it's possible to satisfy the k/2 condition for the first block
    // The remaining '?'s in fixed_chars can be filled to balance counts.
    // The number of '?'s is k - count0 - count1.
    // We need k/2 zeros and k/2 ones.
    // If count0 > k/2 or count1 > k/2, it's impossible.
    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // If we reach here, it means:
    // 1. No direct conflicts (s[i] != s[i+k] if both are known).
    // 2. The counts of '0's and '1's in the first k positions (after propagation)
    //    do not exceed k/2 for either character.
    // This implies that we can always fill the '?'s in fixed_chars to satisfy the k/2 condition
    // for the first block s[0...k-1].
    // For example, fill (k/2 - count0) '?'s with '0' and (k/2 - count1) '?'s with '1'.
    // The total '?'s needed is (k/2 - count0) + (k/2 - count1) = k - count0 - count1,
    // which is exactly the number of '?'s available in fixed_chars.

    // Since fixed_chars[i] determines s[i], s[i+k], s[i+2k], etc.,
    // and we've ensured consistency for fixed_chars,
    // and we've ensured that the first block s[0...k-1] can be made k-balanced,
    // then all subsequent blocks s[j...j+k-1] will also be k-balanced.
    // This is because s[i] == s[i+k] property ensures that if s[0...k-1] is k-balanced,
    // then s[1...k] will also be k-balanced (by removing s[0] and adding s[k], which are identical).
    // This extends to all substrings of length k.

    std::cout << "YES\n";
}

