int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    // If b = 1, mod(x, 1) is always 0, so no nice integers.
    // The sum of r from 1 to b-1 would be 0.
    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r = (b-1) * b * inv(2) mod MOD
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;

    // Modular inverse of 2 modulo 10^9 + 7
    // Since 10^9 + 7 is prime, inv(2) = 2^(MOD-2) mod MOD
    // Or simply (MOD + 1) / 2 = (1000000007 + 1) / 2 = 1000000008 / 2 = 500000004
    long long inv2 = 500000004;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Sum of (k * b + 1) from k=1 to a:
    // sum_k = sum_{k=1 to a} (k*b + 1)
    //       = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    //       = b * (a * (a+1) / 2) + a
    long long sum_k_term = (a * (a + 1)) % MOD;
    sum_k_term = (sum_k_term * inv2) % MOD; // (a * (a+1) / 2)
    sum_k_term = (sum_k_term * b) % MOD;    // b * (a * (a+1) / 2)
    sum_k_term = (sum_k_term + a) % MOD;    // + a

    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

