#include <cmath>

long long solve() {
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 1) {
        return (h[0] + 1) / 2;
    }

    std::vector<long long> left_max(n);
    std::vector<long long> right_max(n);

    left_max[0] = 0;
    for (int i = 1; i < n; ++i) {
        left_max[i] = std::max(left_max[i - 1] - 1, 0LL);
        left_max[i] = std::max(left_max[i], h[i - 1]);
    }

    right_max[n - 1] = 0;
    for (int i = n - 2; i >= 0; --i) {
        right_max[i] = std::max(right_max[i + 1] - 1, 0LL);
        right_max[i] = std::max(right_max[i], h[i + 1]);
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        long long current_h = h[i];
        long long required_from_sides = std::max(left_max[i], right_max[i]);

        long long ops_for_tower;
        if (current_h <= required_from_sides) {
            ops_for_tower = required_from_sides;
        } else {
            long long diff = current_h - required_from_sides;
            ops_for_tower = required_from_sides + (diff + 1) / 2;
        }
        max_ops = std::max(max_ops, ops_for_tower);
    }

    return max_ops;
}

