#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 2) {
            a[i] = -1; // Blueberry jam
        } else {
            a[i] = 1; // Strawberry jam
        }
    }

    // Calculate prefix sums for the left side (jars n down to 1)
    // left_sums[k] = sum of jars n, n-1, ..., n-k+1
    std::vector<int> left_sums(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        left_sums[i + 1] = left_sums[i] + a[n - 1 - i];
    }

    // Calculate prefix sums for the right side (jars n+1 up to 2n)
    // right_sums[k] = sum of jars n+1, n+2, ..., n+k
    std::vector<int> right_sums(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        right_sums[i + 1] = right_sums[i] + a[n + i];
    }

    // Map to store the minimum number of jars eaten from the left
    // to achieve a certain balance sum.
    // key: balance sum, value: number of jars eaten from left
    std::map<int, int> left_balance_to_eaten_count;
    for (int k = 0; k <= n; ++k) {
        int balance = left_sums[k];
        if (left_balance_to_eaten_count.find(balance) == left_balance_to_eaten_count.end()) {
            left_balance_to_eaten_count[balance] = k;
        }
    }

    int min_eaten = 2 * n; // Initialize with max possible eaten jars

    // Iterate through possible number of jars eaten from the right (R)
    for (int R = 0; R <= n; ++R) {
        int current_right_balance = right_sums[R];
        int target_left_balance = -current_right_balance;

        if (left_balance_to_eaten_count.count(target_left_balance)) {
            int L = left_balance_to_eaten_count[target_left_balance];
            min_eaten = std::min(min_eaten, L + R);
        }
    }

    std::cout << min_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

