int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For each bit position (0-9):
    // bit_val_0[bit_pos] stores the final value of bit_pos if initial x_bit_pos was 0.
    // bit_val_1[bit_pos] stores the final value of bit_pos if initial x_bit_pos was 1.
    // Initially, if x_bit_pos is 0, it remains 0. If x_bit_pos is 1, it remains 1.
    std::vector<int> bit_val_0(10); // Stores the state of bit_pos if initial x_bit_pos was 0
    std::vector<int> bit_val_1(10); // Stores the state of bit_pos if initial x_bit_pos was 1

    for (int i = 0; i < 10; ++i) {
        bit_val_0[i] = 0; // If initial bit is 0, it's 0
        bit_val_1[i] = 1; // If initial bit is 1, it's 1
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x_const;
        std::cin >> op_char >> x_const;

        for (int bit_pos = 0; bit_pos < 10; ++bit_pos) {
            int const_bit = (x_const >> bit_pos) & 1;

            if (op_char == '&') {
                bit_val_0[bit_pos] &= const_bit;
                bit_val_1[bit_pos] &= const_bit;
            } else if (op_char == '|') {
                bit_val_0[bit_pos] |= const_bit;
                bit_val_1[bit_pos] |= const_bit;
            } else if (op_char == '^') {
                bit_val_0[bit_pos] ^= const_bit;
                bit_val_1[bit_pos] ^= const_bit;
            }
        }
    }

    // Now, reconstruct the equivalent operations.
    // We need to find A, B, C such that:
    // (x & A | B) ^ C = final_result(x) for all x.
    // This is equivalent to:
    // (x_bit & A_bit | B_bit) ^ C_bit = final_result_bit(x_bit) for each bit.

    // Let's analyze the four possible functions for each bit:
    // 1. x_bit -> 0 (always 0)
    // 2. x_bit -> 1 (always 1)
    // 3. x_bit -> x_bit (identity)
    // 4. x_bit -> ~x_bit (NOT)

    // We need to find A_bit, B_bit, C_bit for each bit_pos.
    // (0 & A_bit | B_bit) ^ C_bit = bit_val_0[bit_pos]
    // (1 & A_bit | B_bit) ^ C_bit = bit_val_1[bit_pos]

    // Let's try to find A, B, C.
    // A_bit, B_bit, C_bit can be 0 or 1.
    // There are 2^3 = 8 combinations for each bit.
    // We need to find a combination that satisfies the two equations.

    // Initialize A, B, C to represent (x & 1023 | 0) ^ 0, which is just x.
    // This means A_bit = 1, B_bit = 0, C_bit = 0 for all bits.
    int final_A = 1023; // All bits 1
    int final_B = 0;    // All bits 0
    int final_C = 0;    // All bits 0

    for (int bit_pos = 0; bit_pos < 10; ++bit_pos) {
        int target_0 = bit_val_0[bit_pos];
        int target_1 = bit_val_1[bit_pos];

        // Iterate through all 8 possibilities for (a, b, c) for this bit
        bool found = false;
        for (int a = 0; a <= 1; ++a) {
            for (int b = 0; b <= 1; ++b) {
                for (int c = 0; c <= 1; ++c) {
                    int res_0 = (0 & a | b) ^ c;
                    int res_1 = (1 & a | b) ^ c;
                    if (res_0 == target_0 && res_1 == target_1) {
                        // Found the (a, b, c) for this bit_pos
                        if (a == 0) final_A &= ~(1 << bit_pos); // Set A_bit to 0
                        if (b == 1) final_B |= (1 << bit_pos);  // Set B_bit to 1
                        if (c == 1) final_C |= (1 << bit_pos);  // Set C_bit to 1
                        found = true;
                        break;
                    }
                }
                if (found) break;
            }
            if (found) break;
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_A != 1023) { // If A is not all 1s, we need an AND operation
        result_ops.push_back({'&', final_A});
    }
    if (final_B != 0) { // If B is not all 0s, we need an OR operation
        result_ops.push_back({'|', final_B});
    }
    if (final_C != 0) { // If C is not all 0s, we need an XOR operation
        result_ops.push_back({'^', final_C});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm>

long long sum_arithmetic_series(long long k) {
    if (k <= 0) return 0;
    return k * (k + 1) / 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = sum_arithmetic_series(n);

        long long num_zeros = n - m;

        if (num_zeros == 0) {
            std::cout << total_substrings << "\n";
            continue;
        }

        // To minimize the number of substrings consisting only of '0's,
        // we need to distribute the '0's as evenly as possible.
        // This means placing '1's to break up long blocks of '0's.
        // With m '1's, we can create m+1 potential blocks of '0's.
        // For example, 10101 has 3 '1's and 4 blocks of '0's (including empty ones).
        // _ 1 _ 1 _ 1 _
        // The number of blocks of zeros is m + 1.
        // We have num_zeros '0's to distribute into these m + 1 blocks.

        long long k = num_zeros / (m + 1); // Base length for each block of zeros
        long long r = num_zeros % (m + 1); // Number of blocks that get an extra zero

        long long sum_zero_substrings = 0;

        // r blocks will have length k+1
        sum_zero_substrings += r * sum_arithmetic_series(k + 1);

        // (m+1 - r) blocks will have length k
        sum_zero_substrings += (m + 1 - r) * sum_arithmetic_series(k);

        long long max_f_s = total_substrings - sum_zero_substrings;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
