#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> adj_matrix(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> adj_matrix[i][j];
        }
    }

    std::vector<int> removal_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> removal_order[i];
        removal_order[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Iterate through the removal order in reverse
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = removal_order[k_idx]; // The vertex being added back

        active_vertices[k] = true; // Mark vertex k as active

        // Update shortest paths using vertex k as an intermediate node
        // This is the core Floyd-Warshall step
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue; // Only consider active vertices
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue; // Only consider active vertices

                // Path i -> k -> j
                if (adj_matrix[i][k] != -1 && adj_matrix[k][j] != -1) { // Check for reachability if needed, though problem implies all paths exist
                    if (adj_matrix[i][j] == -1 || adj_matrix[i][j] > adj_matrix[i][k] + adj_matrix[k][j]) {
                        adj_matrix[i][j] = adj_matrix[i][k] + adj_matrix[k][j];
                    }
                }
            }
        }

        // Also update paths involving k as source or destination
        // This is crucial because k itself is now active
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;

                // Path i -> k -> j (already handled above, but ensures k is fully integrated)
                if (adj_matrix[i][k] != -1 && adj_matrix[k][j] != -1) {
                    if (adj_matrix[i][j] == -1 || adj_matrix[i][j] > adj_matrix[i][k] + adj_matrix[k][j]) {
                        adj_matrix[i][j] = adj_matrix[i][k] + adj_matrix[k][j];
                    }
                }
                // Path k -> i -> j (using k as source, i as intermediate)
                if (adj_matrix[k][i] != -1 && adj_matrix[i][j] != -1) {
                    if (adj_matrix[k][j] == -1 || adj_matrix[k][j] > adj_matrix[k][i] + adj_matrix[i][j]) {
                        adj_matrix[k][j] = adj_matrix[k][i] + adj_matrix[i][j];
                    }
                }
                // Path i -> j -> k (using k as destination, j as intermediate)
                if (adj_matrix[i][j] != -1 && adj_matrix[j][k] != -1) {
                    if (adj_matrix[i][k] == -1 || adj_matrix[i][k] > adj_matrix[i][j] + adj_matrix[j][k]) {
                        adj_matrix[i][k] = adj_matrix[i][j] + adj_matrix[j][k];
                    }
                }
            }
        }


        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += adj_matrix[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (reverse of how they were calculated)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, or any positive number.
                               // This will be the minimum element in the current block.

    while (X > 0) {
        long long k = 0;
        // Find the largest k such that 2^k - 1 <= X
        // This is equivalent to finding k such that 2^k <= X + 1
        // k = floor(log2(X + 1))
        // We need to be careful with X=0, but loop condition X>0 handles it.
        // For X=1, k=1 (2^1-1=1).
        // For X=2, k=1 (2^1-1=1).
        // For X=3, k=2 (2^2-1=3).
        // For X=4, k=2 (2^2-1=3).
        // For X=7, k=3 (2^3-1=7).

        // Iterate k from 60 down to 1 to find the largest k such that (1LL << k) - 1 <= X
        // (1LL << k) - 1 is the number of subsequences from k identical elements.
        // Max X is 10^9, so max k is around 30. 60 is safe for long long.
        for (int i = 60; i >= 1; --i) {
            if (((1LL << i) - 1) <= X) {
                k = i;
                break;
            }
        }

        // If X is 1, k will be 1. (1LL << 1) - 1 = 1.
        // If X is 2, k will be 1. (1LL << 1) - 1 = 1.
        // If X is 3, k will be 2. (1LL << 2) - 1 = 3.

        // Add k elements of current_val to the array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }

        // Subtract the count of subsequences generated by these k elements
        X -= ((1LL << k) - 1);

        // Prepare for the next block of elements
        // The next block's minimum element must be at least current_val + d
        // to ensure that any subsequence combining elements from different blocks
        // will have max_element - min_element >= d.
        // We add 1 to current_val + d to ensure strict inequality.
        current_val += d + 1; 

        // Check for overflow for current_val, though 10^18 limit is generous.
        // Max n is 10000. If k is always 1, current_val could reach 1 + 10000 * (d+1).
        // If d=10^9, current_val could be 10^4 * 10^9 = 10^13, which is fine.
    }

    if (result_array.size() > 10000) {
        // This case should ideally not be reached given the constraints.
        // Max X is 10^9. Smallest k is 1. So max n is 10^9.
        // But k is usually larger. For X=10^9, k is around 30.
        // The number of elements is sum of k's.
        // For X=10^9, the sum of k's is roughly log2(X) * (number of bits in X).
        // E.g., X = 2^30 - 1, n=30.
        // X = 2^30 - 2, n=30+1=31.
        // Max n is around 60 (for X=2^60-1) if X was that large.
        // For X=10^9, max n is around 30 * log2(10^9) ~ 30 * 30 = 900.
        // This is well within 10000.
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable by definition
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_zeros(n, 0); // left_zeros[i] = count of consecutive zeros ending at i
    std::vector<int> left_ones(n, 0);  // left_ones[i] = count of consecutive ones ending at i
    std::vector<int> right_zeros(n, 0); // right_zeros[i] = count of consecutive zeros starting at i
    std::vector<int> right_ones(n, 0);  // right_ones[i] = count of consecutive ones starting at i

    // Calculate left counts
    if (a[0] == 0) left_zeros[0] = 1; else left_ones[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = left_zeros[i - 1] + 1;
            left_ones[i] = 0;
        } else {
            left_ones[i] = left_ones[i - 1] + 1;
            left_zeros[i] = 0;
        }
    }

    // Calculate right counts
    if (a[n - 1] == 0) right_zeros[n - 1] = 1; else right_ones[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zeros[i] = right_zeros[i + 1] + 1;
            right_ones[i] = 0;
        } else {
            right_ones[i] = right_ones[i + 1] + 1;
            right_zeros[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // Current element is 0
            // Check for 1s to its left and right
            // If a[i-1] is 1 and a[i+1] is 1, then a[i] will become 1.
            // This happens if left_ones[i-1] >= k and right_ones[i+1] >= k
            // The number of steps for a[i] to flip to 1 is min(left_ones[i-1], right_ones[i+1])
            // If a[i] is 0, it can flip to 1 if it's surrounded by 1s.
            // The number of steps for it to flip is min(left_ones[i-1], right_ones[i+1])
            // If it's not surrounded by 1s (i.e., left_ones[i-1]==0 or right_ones[i+1]==0), it won't flip to 1.
            // In this case, min(0, X) = 0, so it won't affect max_k.
            max_k = std::max(max_k, std::min(left_ones[i - 1], right_ones[i + 1]));
        } else { // Current element is 1
            // Check for 0s to its left and right
            // If a[i-1] is 0 and a[i+1] is 0, then a[i] will become 0.
            // The number of steps for it to flip is min(left_zeros[i-1], right_zeros[i+1])
            max_k = std::max(max_k, std::min(left_zeros[i - 1], right_zeros[i + 1]));
        }
    }

    std::cout << max_k << "\n";

    std::vector<int> b = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            if (left_ones[i - 1] >= max_k && right_ones[i + 1] >= max_k) {
                b[i] = 1;
            }
        } else { // a[i] == 1
            if (left_zeros[i - 1] >= max_k && right_zeros[i + 1] >= max_k) {
                b[i] = 0;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y and intermediate sums to prevent overflow
// Using int for x and array indices as n is up to 2*10^5

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a is 1-indexed. a[0] is unused.
    // a[1] will be set for each run.
    // a[2] to a[n] are read from input.
    std::vector<long long> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp[i][0] stores the final y value if starting at x=i and performing step 2 (x+a[i], y+a[i])
    // dp[i][1] stores the final y value if starting at x=i and performing step 3 (x-a[i], y+a[i])
    // dp[i][0] and dp[i][1] also store -1 if it's an infinite loop.
    // We need to store the next x position as well to detect cycles.
    // dp[i][0] = {next_x, total_y_change}
    // dp[i][1] = {next_x, total_y_change}
    // Initialize with {0, 0} to indicate not computed yet.
    // A value of {0, -1} can indicate an infinite loop.
    std::vector<std::pair<int, long long>> dp_plus(n + 1, {0, 0});
    std::vector<std::pair<int, long long>> dp_minus(n + 1, {0, 0});

    // Iterate backwards from n to 1 to fill DP table
    for (int i = n; i >= 1; --i) {
        // Calculate dp_plus[i]
        long long val_a_i = a[i];
        int next_x_plus = i + val_a_i;
        long long current_y_plus = val_a_i;

        if (next_x_plus <= 0 || next_x_plus > n) {
            dp_plus[i] = {next_x_plus, current_y_plus};
        } else {
            // We need to transition to dp_minus[next_x_plus]
            // This is where the cycle detection logic is crucial.
            // If dp_minus[next_x_plus] is not yet computed (0,0), it means we are in a cycle.
            // If dp_minus[next_x_plus] is (-1,-1), it means it leads to an infinite loop.
            // If dp_minus[next_x_plus] is computed, use its value.

            // To detect cycles, we can use a temporary state or rely on the backward iteration.
            // Since we iterate backwards, if next_x_plus is within bounds, it must be > i.
            // So dp_minus[next_x_plus] would have already been computed.
            // This is incorrect. next_x_plus can be less than i if a[i] is negative, but a[i] is positive.
            // So next_x_plus is always > i.
            // This means dp_minus[next_x_plus] is always computed when we compute dp_plus[i].
            // This is the key insight for the DP approach.

            std::pair<int, long long> res_from_next = dp_minus[next_x_plus];
            if (res_from_next.second == -1) { // Leads to infinite loop
                dp_plus[i] = {0, -1};
            } else {
                dp_plus[i] = {res_from_next.first, current_y_plus + res_from_next.second};
            }
        }

        // Calculate dp_minus[i]
        int next_x_minus = i - val_a_i;
        long long current_y_minus = val_a_i;

        if (next_x_minus <= 0 || next_x_minus > n) {
            dp_minus[i] = {next_x_minus, current_y_minus};
        } else {
            // We need to transition to dp_plus[next_x_minus]
            // Similar logic: next_x_minus is always < i.
            // So dp_plus[next_x_minus] would have already been computed.
            std::pair<int, long long> res_from_next = dp_plus[next_x_minus];
            if (res_from_next.second == -1) { // Leads to infinite loop
                dp_minus[i] = {0, -1};
            } else {
                dp_minus[i] = {res_from_next.first, current_y_minus + res_from_next.second};
            }
        }
    }

    // Now, for each starting value i (1 to n-1), run the simulation
    for (int start_val_a1 = 1; start_val_a1 < n; ++start_val_a1) {
        a[1] = start_val_a1; // Set a[1] for this run

        // Initial state: x=1, y=0. First step is always step 2 (x+a[x], y+a[x])
        long long current_y = a[1];
        int current_x = 1 + a[1];

        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
        } else {
            // After the first step, we are at (current_x, current_y) and the next step is step 3 (x-a[x], y+a[x])
            // This corresponds to using dp_minus[current_x]
            std::pair<int, long long> result = dp_minus[current_x];
            if (result.second == -1) {
                std::cout << -1 << "\n";
            } else {
                std::cout << current_y + result.second << "\n";
            }
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // This child is now being treated

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;
        long long v_cry_decay = 0;

        std::vector<int> crying_children_queue; // Stores indices of children who just dropped below 0 confidence

        // Apply initial cry from the treated child
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply v_cry from the treated child
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply d_cry from previously leaving children
            children[j].p -= total_d_cry_from_leaving;

            if (children[j].p < 0) {
                if (children[j].in_line) { // Ensure not already processed in this chain reaction
                    children[j].in_line = false;
                    crying_children_queue.push_back(j);
                }
            }
        }

        // Process chain reactions
        int queue_ptr = 0;
        while(queue_ptr < crying_children_queue.size()){
            int crying_child_idx = crying_children_queue[queue_ptr++];
            total_d_cry_from_leaving += children[crying_child_idx].d;

            for (int j = crying_child_idx + 1; j < n; ++j) {
                if (!children[j].in_line) {
                    continue;
                }

                children[j].p -= children[crying_child_idx].d;

                if (children[j].p < 0) {
                    if (children[j].in_line) {
                        children[j].in_line = false;
                        crying_children_queue.push_back(j);
                    }
                }
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_array_upper_bound(n, std::numeric_limits<long long>::max());

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_max_val = ops[i].val;
            long long current_delta_sum = 0;
            for (int j = 0; j < i; ++j) {
                if (ops[j].type == 1) {
                    if (ops[j].l <= ops[i].r && ops[j].r >= ops[i].l) { // Overlap
                        current_delta_sum += ops[j].val;
                    }
                }
            }
            // For each element k in [ops[i].l, ops[i].r], its initial value a_k_0
            // must satisfy a_k_0 + current_delta_sum <= current_max_val
            // So, a_k_0 <= current_max_val - current_delta_sum
            long long bound_for_initial_val = current_max_val - current_delta_sum;
            for (int k = ops[i].l; k <= ops[i].r; ++k) {
                initial_array_upper_bound[k] = std::min(initial_array_upper_bound[k], bound_for_initial_val);
            }
        }
    }

    // Initialize the candidate array with the upper bounds
    std::vector<long long> candidate_initial_array = initial_array_upper_bound;
    for (int i = 0; i < n; ++i) {
        if (candidate_initial_array[i] == std::numeric_limits<long long>::max()) {
            candidate_initial_array[i] = 0; // Default to 0 if no upper bound from type 2 ops
        }
    }

    // Verify the candidate array
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_max_val = ops[i].val;
            long long max_in_range = std::numeric_limits<long long>::min();
            bool found_max_val = false;

            for (int k = ops[i].l; k <= ops[i].r; ++k) {
                long long current_element_val = candidate_initial_array[k];
                for (int j = 0; j < i; ++j) {
                    if (ops[j].type == 1) {
                        if (ops[j].l <= k && k <= ops[j].r) {
                            current_element_val += ops[j].val;
                        }
                    }
                }
                max_in_range = std::max(max_in_range, current_element_val);
                if (current_element_val == current_max_val) {
                    found_max_val = true;
                }
            }

            if (max_in_range != current_max_val || !found_max_val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraints
    for (int i = 0; i < n; ++i) {
        if (candidate_initial_array[i] < -1000000000LL || candidate_initial_array[i] > 1000000000LL) {
            // This case should ideally not be hit if bounds are correctly derived and
            // problem guarantees a solution within 10^9 if one exists.
            // However, it's good to have as a final check.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << candidate_initial_array[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1: Try all possible single cuts
    // A single cut divides s into s1 and s2.
    // We can reorder them to s2s1.
    // We need s2s1 to be a palindrome and s2s1 != s.
    // The cut cannot be at index 0 or n, as that would mean s1 or s2 is empty,
    // resulting in s2s1 == s.
    for (int i = 1; i < n; ++i) { // i is the length of the first part s1
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2:
    // If k=1 didn't work, we need to check if k=2 is always possible,
    // or if there are cases where it's impossible.
    //
    // The problem statement guarantees s is a palindrome.
    // If all characters in s are the same (e.g., "aaaa"), then any permutation
    // of its substrings will result in the same string "aaaa".
    // In this case, it's impossible to form a new string s' != s.
    //
    // Check if all characters in s are the same.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }

    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 must be the answer.
        //
        // Why k=2 is always possible if not all chars are same?
        // Consider the string s. Since it's a palindrome and not all chars are same,
        // there must be at least two distinct characters.
        //
        // If n is odd, say n = 2m + 1.
        // s = c_0 c_1 ... c_{m-1} c_m c_{m-1} ... c_1 c_0
        //
        // If n is even, say n = 2m.
        // s = c_0 c_1 ... c_{m-1} c_{m-1} ... c_1 c_0
        //
        // Since not all characters are the same, there exists some i such that s[i] != s[0].
        //
        // Consider cutting s into three pieces:
        // s1 = s.substr(0, 1) (first character)
        // s2 = s.substr(1, n-2) (middle part)
        // s3 = s.substr(n-1, 1) (last character)
        //
        // Since s is a palindrome, s[0] == s[n-1]. So s1 == s3.
        //
        // We can reorder them as s1 s3 s2. This would be s[0] s[n-1] s.substr(1, n-2).
        // This is just s[0] s[0] s.substr(1, n-2). This is not necessarily a palindrome.
        //
        // A simpler argument for k=2:
        // If s is a palindrome and not all characters are the same,
        // then s.substr(0, n-1) (s without its last character) is not a palindrome.
        // (e.g., "nolon", "nolo" is not a palindrome)
        //
        // Consider cutting s into s.substr(0, n/2) and s.substr(n/2).
        // Let s_prefix = s.substr(0, n/2).
        // Let s_suffix = s.substr(n/2).
        //
        // If n is even, s = s_prefix + s_prefix_reversed.
        // If n is odd, s = s_prefix + s[n/2] + s_prefix_reversed.
        //
        // The problem states that if k=1 doesn't work, and not all characters are the same,
        // then k=2 is the answer. This is a known property for this type of problem.
        //
        // Example: "nolon"
        // k=1:
        // "o|lon" -> "lono" (not pal)
        // "no|lon" -> "lonno" (not pal)
        // "nol|on" -> "onnol" (pal, but == "nolon" reversed, which is "nolon")
        // "nolo|n" -> "nnolo" (not pal)
        //
        // The example output for "nolon" is 2.
        // The example output for "otto" is 1.
        // "otto" -> "ot|to" -> "toot" (pal, != "otto")
        //
        // The logic seems to be:
        // 1. Try k=1. If successful, print 1.
        // 2. If k=1 fails, check if all characters are the same.
        //    If yes, print "Impossible".
        //    If no, print 2.
        //
        // This covers all cases and matches the examples.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_a = elements[0].value;
    long long max_a = elements[n - 1].value;
    long long second_min_a = elements[1].value;
    long long second_max_a = elements[n - 2].value;

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // f values are only a_i + a_j.
    // min_f = min_a + second_min_a
    // max_f = max_a + second_max_a
    // Goodness = (max_a + second_max_a) - (min_a + second_min_a)
    long long goodness_all_same = (max_a + second_max_a) - (min_a + second_min_a);
    std::vector<int> partition_all_same(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences.
    // The minimum possible f value is min_a + second_min_a.
    // The maximum possible f value is max_a + second_max_a + h.
    // This occurs if min_a and second_min_a are in the same group,
    // and max_a and second_max_a are in different groups, or vice versa.
    // Or if min_a and max_a are in different groups, then min_f could be min_a + min_other + h.
    //
    // Let's consider the structure of min/max f values.
    // min_f is always min_a + second_min_a (if they are in the same group)
    // OR min_a + some_other_a + h (if min_a is in one group and some_other_a is in another).
    // The smallest possible sum a_i + a_j is min_a + second_min_a.
    // The smallest possible sum a_i + a_j + h is min_a + second_min_a + h.
    // So, the overall minimum f value is min(min_a + second_min_a, min_a + elements[1].value + h, ...).
    // It's always min_a + second_min_a if min_a and second_min_a are in the same group.
    // If min_a and second_min_a are in different groups, then min_f = min_a + second_min_a + h.
    //
    // The overall maximum f value is max_a + second_max_a + h (if max_a and second_max_a are in different groups).
    // OR max_a + second_max_a (if max_a and second_max_a are in the same group).
    //
    // The critical observation is that to minimize the range, we want the min_f and max_f to be as close as possible.
    //
    // Consider placing min_a in S1 and max_a in S2.
    // All other elements can be placed in S1 or S2.
    //
    // Option A: min_a in S1, max_a in S2. All other elements in S1.
    // S1 = {min_a, a_1, ..., a_{n-2}}
    // S2 = {max_a}
    // f_same: min_a + second_min_a, ..., max_a_S1 + second_max_a_S1
    // f_diff: min_a + max_a + h, ..., max_a_S1 + max_a + h
    //
    // The minimum f value will be min_a + second_min_a (from S1).
    // The maximum f value will be max_a_S1 + max_a + h = elements[n-2].value + max_a + h.
    // Goodness = (elements[n-2].value + max_a + h) - (min_a + second_min_a).
    long long goodness_option_A = (elements[n - 2].value + max_a + h) - (min_a + second_min_a);
    std::vector<int> partition_option_A(n);
    partition_option_A[elements[0].original_index] = 1; // min_a
    for (int i = 1; i < n - 1; ++i) { // a_1 to a_{n-2}
        partition_option_A[elements[i].original_index] = 1;
    }
    partition_option_A[elements[n - 1].original_index] = 2; // max_a

    // Option B: min_a in S1, max_a in S2. All other elements in S2.
    // S1 = {min_a}
    // S2 = {a_1, ..., a_{n-2}, max_a}
    // f_same: second_min_a_S2 + third_min_a_S2, ..., max_a + second_max_a_S2
    // f_diff: min_a + second_min_a_S2 + h, ..., min_a + max_a + h
    //
    // The minimum f value will be min_a + second_min_a_S2 + h = min_a + elements[1].value + h.
    // The maximum f value will be max_a + second_max_a_S2 = max_a + elements[n-2].value.
    // Goodness = (max_a + elements[n-2].value) - (min_a + elements[1].value + h).
    // This can be negative if h is large, meaning min_f_diff is very large.
    // This case is only valid if S2 has at least 2 elements.
    // If n=2, S2 has only max_a. This option is not valid.
    // If n > 2, S2 has at least elements[1] and max_a.
    long long goodness_option_B = -1; // Sentinel for invalid/not computed
    std::vector<int> partition_option_B(n);
    if (n > 2) {
        goodness_option_B = (max_a + elements[n - 2].value) - (min_a + elements[1].value + h);
        partition_option_B[elements[0].original_index] = 1; // min_a
        for (int i = 1; i < n - 1; ++i) { // a_1 to a_{n-2}
            partition_option_B[elements[i].original_index] = 2;
        }
        partition_option_B[elements[n - 1].original_index] = 2; // max_a
    }

    // Compare the goodness values
    long long min_goodness = goodness_all_same;
    std::vector<int> best_partition = partition_all_same;

    if (goodness_option_A < min_goodness) {
        min_goodness = goodness_option_A;
        best_partition = partition_option_A;
    }

    if (n > 2 && goodness_option_B < min_goodness) {
        min_goodness = goodness_option_B;
        best_partition = partition_option_B;
    }

    // Special case for n=2:
    // Only two elements a_0, a_1.
    // Option 1: Both in S1. f(a_0, a_1) = a_0 + a_1. Goodness = 0.
    // Option 2: a_0 in S1, a_1 in S2. f(a_0, a_1) = a_0 + a_1 + h. Goodness = 0.
    // In both cases, there's only one f value, so max-min = 0.
    // The logic above handles this:
    // goodness_all_same = (max_a + second_max_a) - (min_a + second_min_a)
    // For n=2, second_max_a is not well-defined as elements[n-2] would be elements[0].
    // This means elements[n-2] == elements[0] and elements[n-1] == elements[1].
    // So, max_a + second_max_a = elements[1].value + elements[0].value
    // and min_a + second_min_a = elements[0].value + elements[1].value.
    // Thus, goodness_all_same = 0.
    //
    // goodness_option_A = (elements[n-2].value + max_a + h) - (min_a + second_min_a)
    // For n=2, elements[n-2] is elements[0].
    // goodness_option_A = (elements[0].value + elements[1].value + h) - (elements[0].value + elements[1].value) = h.
    //
    // So for n=2, min_goodness will be 0, and partition_all_same (1 1) will be chosen.
    // This is correct.

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // dp[i] will store the smallest r such that the substring s[i...r]
    // contains a 3-AP, or n+1 if no such r exists starting at i.
    // We are looking for l, r pairs where 1 <= l <= r <= n.
    // In 0-based indexing, 0 <= l_idx <= r_idx < n.
    // The problem asks for l, r such that l <= x and r >= x+2k.
    // So, for a given l_idx, we need to find r_idx >= min_r_idx(l_idx).
    // min_r_idx(l_idx) is the smallest r_idx such that s[l_idx...r_idx] contains a 3-AP.
    // If no such 3-AP exists for any l_idx, then min_r_idx(l_idx) = n.

    // Initialize dp array. dp[i] = n means no 3-AP starting at or after i
    // has been found yet that would make s[i...r] valid.
    // We want to find the minimum r_idx for each l_idx.
    // Let's define `min_valid_r[l_idx]` as the smallest `r_idx` such that
    // the substring `s[l_idx...r_idx]` contains at least one 3-AP.
    // If no such `r_idx` exists for a given `l_idx`, `min_valid_r[l_idx]` will be `n`.
    std::vector<int> min_valid_r(n, n);

    // Iterate through all possible x and k to find 3-APs.
    // x is 0-based index, k is distance.
    // s[x] == s[x+k] == s[x+2k]
    // x+2k must be < n.
    // So x can go from 0 to n-1.
    // k can go from 1 up to (n-1-x)/2.
    for (int x = 0; x < n; ++x) {
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a 3-AP: s[x], s[x+k], s[x+2k]
                // This 3-AP covers the range [x, x+2k].
                // Any substring s[l_idx...r_idx] where l_idx <= x and r_idx >= x+2k
                // will contain this 3-AP.
                // For any l_idx from 0 to x, the minimum r_idx required is x+2k.
                // We want to update min_valid_r[l_idx] for l_idx from 0 to x.
                // Since we are iterating x from left to right, and k from small to large,
                // we might find multiple 3-APs for a given l_idx.
                // We need the *minimum* r_idx.
                // So, for each l_idx from 0 to x, update min_valid_r[l_idx] = min(min_valid_r[l_idx], x+2k).
                // This can be done efficiently.
                // The current 3-AP ends at x+2k.
                // For any l_idx from 0 to x, this 3-AP makes s[l_idx ... x+2k] valid.
                // So, we update min_valid_r[l_idx] to be at most x+2k.
                // Since we want the minimum r_idx for each l_idx, we take min.
                // The crucial observation is that if min_valid_r[l_idx] is updated to R,
                // then for any l_idx' < l_idx, min_valid_r[l_idx'] must be <= R.
                // This means min_valid_r is a non-increasing sequence.
                // We can update min_valid_r[x] = min(min_valid_r[x], x+2k).
                // Then, for l_idx = x-1 down to 0, min_valid_r[l_idx] = min(min_valid_r[l_idx], min_valid_r[l_idx+1]).
                // This ensures the non-increasing property and propagates the minimum r_idx.

                // Update min_valid_r[x] with the current 3-AP's end point.
                min_valid_r[x] = std::min(min_valid_r[x], x + 2 * k);
            }
        }
    }

    // After finding all direct 3-APs, propagate the minimum r_idx backwards.
    // If s[l_idx...r_idx] is valid, then s[l_idx-1...r_idx] is also valid.
    // So, min_valid_r[l_idx-1] <= min_valid_r[l_idx].
    // This means min_valid_r is a non-increasing sequence.
    for (int l_idx = n - 2; l_idx >= 0; --l_idx) {
        min_valid_r[l_idx] = std::min(min_valid_r[l_idx], min_valid_r[l_idx + 1]);
    }

    long long total_pairs = 0;
    for (int l_idx = 0; l_idx < n; ++l_idx) {
        // For a given l_idx, we need to count r_idx such that l_idx <= r_idx < n
        // AND r_idx >= min_valid_r[l_idx].
        // The number of such r_idx values is (n - 1) - min_valid_r[l_idx] + 1,
        // provided min_valid_r[l_idx] < n.
        // If min_valid_r[l_idx] == n, it means no 3-AP exists for this l_idx,
        // so 0 pairs are counted for this l_idx.
        if (min_valid_r[l_idx] < n) {
            total_pairs += (n - min_valid_r[l_idx]);
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> head_reach_left(n);
    std::vector<long long> head_reach_right(n);
    for (int i = 0; i < n; ++i) {
        head_reach_left[i] = h[i] - T;
        head_reach_right[i] = h[i] + T;
    }

    int p_idx = 0;
    int h_idx = 0;

    while (p_idx < m) {
        if (h_idx >= n) {
            return false; // No more heads to cover remaining tracks
        }

        // Find the first track p[p_idx] that needs to be covered
        // If p[p_idx] is already covered by a head h[h_idx-1] (if h_idx > 0)
        // that moved to cover a previous track, we need to advance p_idx.
        // This is handled by the loop below.

        // Find the first head h[h_idx] that can potentially cover p[p_idx]
        // A head h[i] can cover p[p_idx] if h[i] - T <= p[p_idx] <= h[i] + T.
        // Since h and p are sorted, we can advance h_idx.
        while (h_idx < n && head_reach_right[h_idx] < p[p_idx]) {
            h_idx++;
        }
        if (h_idx >= n) {
            return false; // No head can reach p[p_idx]
        }

        // Now h[h_idx] is the first head that can potentially reach p[p_idx]
        // (i.e., p[p_idx] <= h[h_idx] + T).
        // We need to find the leftmost track p[p_idx] that is not yet covered.
        // If p[p_idx] < h[h_idx] - T, then h[h_idx] cannot cover p[p_idx] by moving right.
        // It must move left.
        // The strategy is to use the current head h[h_idx] to cover p[p_idx]
        // and as many subsequent tracks as possible.

        long long current_head_pos = h[h_idx];
        long long current_head_left_reach = current_head_pos - T;
        long long current_head_right_reach = current_head_pos + T;

        // If p[p_idx] is to the left of what this head can reach by moving left,
        // then this head cannot cover p[p_idx]. We need to try the next head.
        // This case should be handled by the outer while loop advancing h_idx.
        // Specifically, if p[p_idx] < head_reach_left[h_idx], then h[h_idx] cannot cover p[p_idx].
        // This means we need to find a head h[k] such that h[k] - T <= p[p_idx].
        // The current h_idx is the first head such that h[h_idx] + T >= p[p_idx].
        // If h[h_idx] - T > p[p_idx], then this head cannot cover p[p_idx] by moving left.
        // This implies that p[p_idx] is too far left for h[h_idx] to cover it.
        // This is a problem.
        // The correct logic for `check` is to iterate through `p` and assign heads.

        // Let's restart the check logic.
        // We iterate through the target tracks `p`.
        // For each `p[i]`, we need to find a head that covers it.
        // We use a greedy approach: assign the leftmost available head that can cover `p[i]`.
        // Or, more precisely, we try to cover `p[i]` with the current head `h[h_idx]`.
        // If `h[h_idx]` cannot cover `p[i]`, we advance `h_idx`.
        // If `h[h_idx]` can cover `p[i]`, we use it, and then advance `p_idx` as far as possible.

        // The current head h[h_idx] can cover the range [h[h_idx] - T, h[h_idx] + T].
        // We need to cover p[p_idx].
        // If p[p_idx] is outside the range [h[h_idx] - T, h[h_idx] + T],
        // then h[h_idx] cannot cover p[p_idx].
        // We must use a different head.
        // Since h and p are sorted, if h[h_idx] cannot cover p[p_idx],
        // then either p[p_idx] is too far left for h[h_idx] (p[p_idx] < h[h_idx] - T),
        // or p[p_idx] is too far right for h[h_idx] (p[p_idx] > h[h_idx] + T).
        // The second case (p[p_idx] > h[h_idx] + T) means we need to advance h_idx.
        // The first case (p[p_idx] < h[h_idx] - T) means that even if h[h_idx] moves as far left as possible,
        // it cannot reach p[p_idx]. This implies that no head to the right of h[h_idx] can reach p[p_idx] either.
        // So, if p[p_idx] < h[h_idx] - T, it's impossible to cover p[p_idx] with any remaining head.

        // Correct greedy strategy:
        // For each head h[h_idx], it can cover a range [h[h_idx]-T, h[h_idx]+T].
        // We want to cover as many p_j's as possible with each head.
        // We iterate through heads. For each head h[h_idx]:
        // 1. Find the first p[p_idx] that is not yet covered.
        // 2. If p[p_idx] is too far left for h[h_idx] (i.e., p[p_idx] < h[h_idx] - T),
        //    then it's impossible to cover p[p_idx] with any subsequent head either. Return false.
        // 3. If p[p_idx] is too far right for h[h_idx] (i.e., p[p_idx] > h[h_idx] + T),
        //    then h[h_idx] cannot cover p[p_idx]. We must use the next head. Advance h_idx and continue.
        // 4. If h[h_idx] can cover p[p_idx] (i.e., h[h_idx] - T <= p[p_idx] <= h[h_idx] + T),
        //    then we use h[h_idx] to cover p[p_idx] and all subsequent tracks
        //    that are within its reach. Advance p_idx past all covered tracks.
        //    Then advance h_idx to use the next head.

        // This is the standard interval covering problem.
        // `p_idx` tracks the first *uncovered* target track.
        // `h_idx` tracks the current head we are considering.

        // While there are still tracks to cover:
        // If we run out of heads, it's impossible.
        if (h_idx >= n) return false;

        // The current head h[h_idx] can cover the range [h[h_idx] - T, h[h_idx] + T].
        // We need to cover p[p_idx].
        // If p[p_idx] is to the left of what h[h_idx] can reach (even by moving left),
        // then it's impossible.
        if (p[p_idx] < h[h_idx] - T) {
            return false;
        }

        // If p[p_idx] is to the right of what h[h_idx] can reach (even by moving right),
        // then h[h_idx] cannot cover p[p_idx]. We must use the next head.
        // We don't advance p_idx here, as p[p_idx] is still uncovered.
        if (p[p_idx] > h[h_idx] + T) {
            h_idx++;
            continue; // Try again with the next head
        }

        // At this point, h[h_idx] can cover p[p_idx].
        // We use h[h_idx] to cover p[p_idx] and all subsequent tracks
        // that are within its reach.
        long long current_head_max_reach = h[h_idx] + T;
        while (p_idx < m && p[p_idx] <= current_head_max_reach) {
            p_idx++;
        }
        // After covering, move to the next head.
        h_idx++;
    }

    return true; // All tracks covered
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance: (10^10 - 1) + (10^10 - 1) approx 2*10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

