#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        int min_idx = 0;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < a[min_idx]) {
                min_idx = i;
            }
        }

        long long min_val = a[min_idx];
        long long total_spells = 0;

        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue;
            }
            // For each other pile a[i], we can add min_val to it
            // until a[i] + X * min_val > k
            // So, a[i] + X * min_val <= k
            // X * min_val <= k - a[i]
            // X <= (k - a[i]) / min_val
            // Since X must be an integer, X = floor((k - a[i]) / min_val)
            if (min_val > 0) { // Should always be true as a_i >= 1
                total_spells += (k - a[i]) / min_val;
            }
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

