    } else if (a[0] == -1) {
        has_neg_one = true;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) { // Can only increase if there's a 1 to add
                std::cout << "NO\n";
