int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) { // Exclude a[i][i] which is 0
                max_in_row = std::max(max_in_row, a[i][j]);
            }
        }
        p[i] = max_in_row;
    }

    // Check if any element in p is n-1 and if n is not present.
    // If so, it means the actual value for that p[i] should be n.
    // This happens if p[i] is the largest element in the permutation.
    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found in the reconstructed p, it means the largest element
        // in the original permutation was n, and its corresponding p[i] was
        // calculated as max(p_j for j!=i) which is n-1.
        // We need to find one such p[i] that is n-1 and change it to n.
        // Any p[i] that is n-1 would be a candidate.
        // Since the problem guarantees a solution, there must be exactly one such case.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; // Only one such element needs to be changed
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

