int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting cell 0.
                             // If last_R_pos is -1, it means the frog is at cell 0.

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The distance from the previous 'R' (or 0) to this 'R' is (i+1) - (last_R_pos + 1) + 1
                // which simplifies to (i+1) - last_R_pos.
                // Example: last_R_pos = -1 (cell 0), current 'R' at s[0] (cell 1). Gap = 1 - (-1) = 2.
                // Example: last_R_pos = 2 (cell 3), current 'R' at s[4] (cell 5). Gap = 5 - 3 = 2.
                max_gap = std::max(max_gap, (i + 1) - (last_R_pos + 1) + 1);
                last_R_pos = i;
            }
        }
        // After iterating through the string, consider the gap from the last 'R' to cell n+1.
        // The last 'R' was at index `last_R_pos` (cell `last_R_pos + 1`).
        // The target is cell `s.length() + 1`.
        // The distance is (s.length() + 1) - (last_R_pos + 1) + 1.
        max_gap = std::max(max_gap, (static_cast<int>(s.length()) + 1) - (last_R_pos + 1) + 1);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for a staircase with 1 stair (n=1)
        long long n_val = 1;        // Number of stairs for the current staircase type
        while (x >= current_cost) {
            x -= current_cost;
            count++;
            // Calculate cost for the next nice staircase type
            // The next nice staircase has n_val' = 2 * n_val + 1 stairs.
            // Its cost is (n_val' * (n_val' + 1)) / 2.
            // This can be derived from the previous cost:
            // cost(2n+1) = cost(n) * 4 + (n+1)
            // Or more directly:
            // n_val_next = 2 * n_val + 1
            // current_cost_next = (n_val_next * (n_val_next + 1)) / 2
            // This simplifies to current_cost_next = 2 * current_cost + (n_val + 1) * (n_val + 1)
            // Or even simpler: current_cost_next = 2 * current_cost + (n_val + 1)^2
            // Let's use the direct formula for n_val_next and then calculate its cost.
            // n_val_next = 2 * n_val + 1;
            // current_cost_next = (n_val_next * (n_val_next + 1)) / 2;
            // This is equivalent to:
            // current_cost = current_cost * 2 + (n_val + 1) * (n_val + 1);
            // n_val = 2 * n_val + 1;
            // This is the recurrence relation for the cost of the next nice staircase.
            // The cost of a staircase with n stairs is n*(n+1)/2.
            // The sequence of n for nice staircases is 1, 3, 7, 15, ... (2^k - 1)
            // Let n_k = 2^k - 1.
            // Cost_k = n_k * (n_k + 1) / 2 = (2^k - 1) * 2^k / 2 = (2^k - 1) * 2^(k-1).
            //
            // Let's use the recurrence:
            // n_val_new = 2 * n_val + 1;
            // current_cost_new = current_cost * 2 + (n_val + 1) * (n_val + 1);
            //
            // Example:
            // n=1, cost=1
            // n_new = 2*1+1 = 3
            // cost_new = 1*2 + (1+1)*(1+1) = 2 + 4 = 6. Correct.
            //
            // n=3, cost=6
            // n_new = 2*3+1 = 7
            // cost_new = 6*2 + (3+1)*(3+1) = 12 + 16 = 28. Correct.
            //
            // So, update n_val and current_cost for the next iteration.
            current_cost = current_cost * 2 + (n_val + 1) * (n_val + 1);
            n_val = 2 * n_val + 1;
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i from 1 to n-1 (p_i+1)
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i was not a prefix max before.
                // But it's good to check for robustness.
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some unused number less than q_i.
            // We need to pick the smallest available number to maximize chances for future elements.
            // The largest available number less than q_i is q_i - 1, then q_i - 2, etc.
            // We need to find the smallest number not yet used, that is also less than q_i.
            // This is equivalent to finding the smallest number in [1, n] that is not in used_numbers.
            // We can iterate from 1 upwards or use a data structure.
            // A set of available numbers would be efficient.
            // Let's find the smallest available number.
            // The numbers that are NOT used are candidates.
            // We need to find the smallest number `x` such that `x < q[i]` and `x` is not in `used_numbers`.
            // A more direct approach: find the largest number `x` such that `x < q[i]` and `x` is not in `used_numbers`.
            // This is because we want to leave larger numbers for later if they become new maximums.
            // However, the problem asks for *any* suitable permutation.
            // The strategy of picking the smallest available number for p_i when q_i == q_{i-1}
            // is generally a good greedy approach.
            // Let's maintain a set of available numbers.
            // Or, more simply, iterate downwards from q[i]-1.

            int current_val = q[i-1]; // q[i] == q[i-1]
            int found_val = -1;
            for (int k = current_val - 1; k >= 1; --k) {
                if (!used_numbers.count(k)) {
                    found_val = k;
                    break;
                }
            }

            if (found_val != -1) {
                p[i] = found_val;
                used_numbers.insert(found_val);
            } else {
                possible = false;
                break;
            }
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        // Final check: ensure all numbers from 1 to n are used exactly once.
        // This is implicitly handled by the logic if `possible` is true.
        // If `possible` is true, `used_numbers` will contain `n` distinct elements.
        // Since all `p_i` are chosen from `[1, n]`, and `used_numbers` contains `n` distinct elements,
        // it must be that `used_numbers` contains exactly `[1, 2, ..., n]`.
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

