#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used for the k distinct differences

    // Generate the first k+1 elements to produce k distinct differences
    // The differences will be k, k-1, ..., 1
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left++;
        } else {
            p[i] = right--;
        }
    }

    // Fill the remaining elements in increasing order
    // This will produce a difference of 1 with the previous element
    // (since right is now left-1, or left is now right+1, depending on parity)
    // and subsequent differences will also be 1.
    // These differences are already covered by the '1' difference generated
    // in the first part (if k >= 1).
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This will be the next available number in sequence
                      // If k is even, p[k] = left, so next is left+1.
                      // If k is odd, p[k] = right, so next is right+1.
                      // In both cases, the next number is the one that continues the sequence.
                      // The numbers used so far are 1, 2, ..., (k+1).
                      // The next available number is k+2.
                      // So, p[k+1] should be k+2, p[k+2] should be k+3, etc.
                      // This is equivalent to p[i] = i + 1.
    }

    // Correcting the fill for remaining elements:
    // After the zigzag, 'left' holds the smallest unused number,
    // and 'right' holds the largest unused number.
    // The numbers used are 1, 2, ..., k+1.
    // The next available number is k+2.
    // So, we just append k+2, k+3, ..., n.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }


    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

