#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. It's always beautiful.
        // For m > 1, we need to expand the current segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from min(pos[1]...pos[m]) to max(pos[1]...pos[m]).
        // We maintain current_min_idx and current_max_idx for numbers 1 to (m-1).
        // When considering 'm', we update these bounds to include pos[m].

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // contains exactly the numbers 1, 2, ..., m.
        // This implies two conditions:
        // 1. The length of the subsegment must be 'm'.
        // 2. The minimum value in the subsegment must be 1, and the maximum must be m.
        //    (This is implicitly handled by how current_min_idx and current_max_idx are updated,
        //     as they track the span of 1 to m. If the length matches, then all numbers
        //     1 to m must be present and no other numbers outside this range can be present
        //     if the length is exactly m).

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

