// Function to determine if a box can be the special box
// Parameters:
// a, b, c, d: initial counts of toys in boxes 1, 2, 3, 4
// target_box: the box we are checking (1, 2, 3, or 4)
//
// The logic is based on the parity of negative numbers and the ability to control magnitude.
//
// Box 1: (-inf, -1] (Negative, Large magnitude)
// Box 2: (-1, 0)    (Negative, Small magnitude)
// Box 3: (0, 1)     (Positive, Small magnitude)
// Box 4: [1, inf)   (Positive, Large magnitude)
//
// Key observations:
// 1. The final sign depends on the parity of negative numbers multiplied.
//    (A + B) is the initial count of negative numbers.
//    Each multiplication of two numbers can change the count of negative numbers by 0 or 2.
//    So, the parity of negative numbers (A+B) remains invariant throughout the process.
//    If (A+B) is odd, the final super toy must be negative.
//    If (A+B) is even, the final super toy must be positive.
//
// 2. Magnitude control:
//    - To get a large magnitude (>=1), we need at least one toy with magnitude >=1 (from Box 1 or Box 4)
//      to be multiplied by other toys, or we need to multiply many small magnitude toys
//      in a way that their product becomes large (e.g., 0.5 * 0.5 * ... * 0.5 can become small,
//      but 2 * 2 * ... * 2 can become large).
//      More precisely, if we have at least one toy with magnitude >= 1, we can potentially keep the magnitude >= 1.
//      If all initial toys have magnitude < 1 (B+C > 0, A+D == 0), then the final product will always have magnitude < 1.
//    - To get a small magnitude (<1), we need at least one toy with magnitude <1 (from Box 2 or Box 3)
//      to be multiplied by other toys, or we need to multiply many large magnitude toys
//      in a way that their product becomes small (e.g., 2 * 0.1 = 0.2).
//      More precisely, if we have at least one toy with magnitude < 1, we can potentially keep the magnitude < 1.
//      If all initial toys have magnitude >= 1 (A+D > 0, B+C == 0), then the final product will always have magnitude >= 1.
//
// Edge case: If N=1, the single toy is the super toy. Its box is the special box.

bool can_be_special(long long a, long long b, long long c, long long d, int target_box) {
    long long total_toys = a + b + c + d;

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        return false;
    }

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (a == 1 && target_box == 1) return true;
        if (b == 1 && target_box == 2) return true;
        if (c == 1 && target_box == 3) return true;
        if (d == 1 && target_box == 4) return true;
        return false;
    }

    // Determine final sign based on parity of negative numbers
    bool final_is_negative_possible;
    bool final_is_positive_possible;

    // The parity of (A+B) is invariant.
    // If (A+B) is odd, the final product must be negative.
    // If (A+B) is even, the final product must be positive.
    if ((a + b) % 2 != 0) { // Odd number of negatives
        final_is_negative_possible = true;
        final_is_positive_possible = false;
    } else { // Even number of negatives
        final_is_negative_possible = false;
        final_is_positive_possible = true;
    }

    // Determine final magnitude based on presence of large/small magnitude toys
    bool final_is_large_magnitude_possible; // >= 1
    bool final_is_small_magnitude_possible; // < 1

    // If all initial toys have magnitude < 1 (B+C > 0, A+D == 0), then final product must be < 1.
    if (a == 0 && d == 0) {
        final_is_large_magnitude_possible = false;
        final_is_small_magnitude_possible = true;
    }
    // If all initial toys have magnitude >= 1 (A+D > 0, B+C == 0), then final product must be >= 1.
    else if (b == 0 && c == 0) {
        final_is_large_magnitude_possible = true;
        final_is_small_magnitude_possible = false;
    }
    // Otherwise, we have a mix of magnitudes.
    // We can always achieve a large magnitude (>=1) if there's at least one large magnitude toy (A or D).
    // We can always achieve a small magnitude (<1) if there's at least one small magnitude toy (B or C).
    // The only exception is if we have only one large magnitude toy and all others are small.
    // E.g., {2, 0.1, 0.1}. We can multiply 0.1*0.1=0.01, then 2*0.01=0.02 (small).
    // Or we can multiply 2*0.1=0.2, then 0.2*0.1=0.02 (small).
    // It seems if there's any small magnitude toy, we can make the final product small.
    // If there's any large magnitude toy, we can make the final product large.
    // This is because we can choose the order of multiplication.
    // To make it large: multiply all small magnitude toys together first, then multiply by large ones.
    // If the product of small ones is P_s < 1, and we have L_1, L_2... large ones.
    // P_s * L_1 * L_2 ... can be made large if L_1 * L_2 ... is large enough.
    // To make it small: multiply a large magnitude toy by a small magnitude toy, then multiply by others.
    // L * S = S' (can be <1 or >=1). If S' < 1, then S' * other_toys will likely be small.
    //
    // Let's refine magnitude control:
    //
    // Can we get magnitude < 1?
    // Yes, if there is at least one toy in Box 2 or Box 3 (b > 0 or c > 0).
    // We can always pick a toy from B or C, and multiply it by any other toy.
    // If we have a toy with value X from B or C (so |X| < 1), and any other toy Y.
    // We can multiply X * Y. If |Y| is large, |X*Y| can be large or small.
    // But we can always choose to multiply X by some other toy, and then keep multiplying by small numbers.
    // Example: {2, 0.1, 0.1}.
    // To get small: (2 * 0.1) * 0.1 = 0.2 * 0.1 = 0.02 (small)
    //
    // Can we get magnitude >= 1?
    // Yes, if there is at least one toy in Box 1 or Box 4 (a > 0 or d > 0).
    // We can always pick a toy with value X from A or D (so |X| >= 1).
    // If we have a toy with value X from A or D, and any other toy Y.
    // We can multiply X * Y. If |Y| is small, |X*Y| can be large or small.
    // But we can always choose to multiply all small magnitude toys together first.
    // Example: {2, 0.1, 0.1}.
    // Product of small toys: 0.1 * 0.1 = 0.01.
    // Then 2 * 0.01 = 0.02 (small). This strategy doesn't guarantee large.
    //
    // The key is that we can choose the order of operations.
    //
    // If there are any toys in Box 2 or Box 3 (b > 0 or c > 0), we can always make the final product have magnitude < 1.
    // To do this, pick one toy from B or C (say, value `s` where |s|<1).
    // Multiply all other `total_toys - 1` toys together to get a product `P`.
    // Then multiply `s * P`. We can choose `s` to be arbitrarily close to 0 (e.g., 0.00001).
    // So `s * P` can be made arbitrarily small, thus < 1.
    // So, if (b > 0 || c > 0), then final_is_small_magnitude_possible = true.
    //
    // If there are any toys in Box 1 or Box 4 (a > 0 or d > 0), we can always make the final product have magnitude >= 1.
    // To do this, pick one toy from A or D (say, value `L` where |L|>=1).
    // Multiply all other `total_toys - 1` toys together to get a product `P`.
    // Then multiply `L * P`. We can choose `L` to be arbitrarily large (e.g., 1000000).
    // So `L * P` can be made arbitrarily large, thus >= 1.
    // So, if (a > 0 || d > 0), then final_is_large_magnitude_possible = true.
    //
    // This simplified logic holds because we can choose specific values for the toys.
    // For example, if we want a small magnitude, we can pick one toy from B or C to be very close to 0.
    // If we want a large magnitude, we can pick one toy from A or D to be very large.

    // Refined magnitude logic:
    // Can we make the final product's magnitude < 1?
    // Yes, if there is at least one toy in Box 2 or Box 3 (b > 0 or c > 0).
    // We can pick one such toy with value epsilon (e.g., 0.00001).
    // Multiply all other toys to get some product P. Then multiply P * epsilon. This will be small.
    final_is_small_magnitude_possible = (b > 0 || c > 0);

    // Can we make the final product's magnitude >= 1?
    // Yes, if there is at least one toy in Box 1 or Box 4 (a > 0 or d > 0).
    // We can pick one such toy with value M (e.g., 1000000).
    // Multiply all other toys to get some product P. Then multiply P * M. This will be large.
    final_is_large_magnitude_possible = (a > 0 || d > 0);

    // Special case for magnitude: If all toys are from B and C (a=0, d=0), then the product must be < 1.
    if (a == 0 && d == 0) {
        final_is_large_magnitude_possible = false;
    }
    // Special case for magnitude: If all toys are from A and D (b=0, c=0), then the product must be >= 1.
    if (b == 0 && c == 0) {
        final_is_small_magnitude_possible = false;
    }

    // Now combine sign and magnitude possibilities for each target box.
    if (target_box == 1) { // Negative, Large magnitude
        return final_is_negative_possible && final_is_large_magnitude_possible;
    } else if (target_box == 2) { // Negative, Small magnitude
        return final_is_negative_possible && final_is_small_magnitude_possible;
    } else if (target_box == 3) { // Positive, Small magnitude
        return final_is_positive_possible && final_is_small_magnitude_possible;
    } else if (target_box == 4) { // Positive, Large magnitude
        return final_is_positive_possible && final_is_large_magnitude_possible;
    }
    return false; // Should not reach here
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::cout << (can_be_special(A, B, C, D, 1) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special(A, B, C, D, 2) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special(A, B, C, D, 3) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special(A, B, C, D, 4) ? "Ya" : "Tidak") << "\n";
    }
    return 0;
}

#include <iostream>
