int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need k * y sticks.
        // Total sticks required: k (for torches) + k * y (for coal)
        // Let total_sticks_for_coal_and_torches = k * y + k;

        // We start with 1 stick.
        // So, we need to acquire (k * y + k) - 1 additional sticks.
        // Let sticks_to_acquire = (k * y + k) - 1;

        // Each trade of type 1 (1 stick -> x sticks) gives a net gain of (x - 1) sticks.
        // Number of type 1 trades needed: ceil(sticks_to_acquire / (x - 1))
        // Using integer division: (sticks_to_acquire + (x - 1) - 1) / (x - 1)
        // which simplifies to (sticks_to_acquire - 1) / (x - 1) + 1 if sticks_to_acquire > 0
        // or (sticks_to_acquire + x - 2) / (x - 1)

        // Let's calculate the total sticks needed for coal and torches.
        // This is k * y sticks for coal, plus k sticks for the torches themselves.
        // So, total_sticks_required = k * y + k.
        // We start with 1 stick.
        // The number of sticks we need to *produce* via trades is total_sticks_required - 1.
        // Let sticks_to_produce = total_sticks_required - 1;

        // Each trade of type 1 (1 stick -> x sticks) effectively increases our stick count by (x - 1).
        // Number of type 1 trades = ceil(sticks_to_produce / (x - 1)).
        // Using integer division: (sticks_to_produce + (x - 1) - 1) / (x - 1)
        // This is equivalent to (sticks_to_produce - 1) / (x - 1) + 1 if sticks_to_produce > 0.
        // Or more generally, (sticks_to_produce + x - 2) / (x - 1) for positive sticks_to_produce.
        // If sticks_to_produce is 0, then 0 trades are needed.
        // The formula (A + B - 1) / B for ceil(A/B) works for A >= 0, B > 0.
        // Here A = sticks_to_produce, B = x - 1.

        long long sticks_needed_for_coal = k * y;
        long long total_sticks_to_have = sticks_needed_for_coal + k; // k for torches, k*y for coal

        // We start with 1 stick. So we need to gain (total_sticks_to_have - 1) sticks.
        // Each trade of type 1 (1 stick -> x sticks) gives a net gain of (x - 1) sticks.
        // Number of type 1 trades = ceil((total_sticks_to_have - 1) / (x - 1))
        long long num_type1_trades = (total_sticks_to_have - 1 + (x - 1) - 1) / (x - 1);

        // Number of type 2 trades (y sticks -> 1 coal) is exactly k.
        long long num_type2_trades = k;

        long long total_trades = num_type1_trades + num_type2_trades;
        std::cout << total_trades << "\n";
    }
    return 0;
}

