    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    int k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Handle friends with w_i = 1 first.
    // These friends get 2 * largest_available_number.
    // They should take the largest numbers from 'a'.
    int a_ptr_max = n - 1;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_max];
            a_ptr_max--;
        } else {
            // Since w is sorted, all remaining w[i] will be > 1.
            // Break and handle them in the next loop.
            break;
        }
    }

    // Handle friends with w_i > 1.
    // These friends get max_val + min_val.
    // To maximize, they should take the largest available number for max_val,
    // and the smallest available number for min_val.
    // The largest available numbers are already taken by w_i=1 friends or will be taken by these friends.
    // The smallest available numbers are from the beginning of 'a'.
    // The friends with larger w_i values will consume more numbers from the middle,
    // leaving the smallest numbers for friends with smaller w_i values (but still > 1).
    // To maximize sum of min_val, we should give the smallest available numbers to friends who need them.
    // The friends with w_i > 1 will take one largest remaining number (for their max_val)
    // and one smallest remaining number (for their min_val).
    // The remaining w_i - 2 numbers they take don't affect their happiness.
    // We pair the largest remaining numbers with the smallest remaining numbers.
    // The k friends with w_i > 1 will each take one of the k largest remaining numbers.
    // The k friends with w_i > 1 will each take one of the k smallest remaining numbers.
    // The largest numbers are already handled by a_ptr_max.
    // The smallest numbers are from a_ptr_min.

    int a_ptr_min = 0;
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            // This friend takes one largest available number (from a_ptr_max)
            // and one smallest available number (from a_ptr_min).
            total_happiness += a[a_ptr_max]; // Max value for this friend
            total_happiness += a[a_ptr_min]; // Min value for this friend

            // The friend also takes w[i] - 2 numbers from the middle.
            // These numbers are consumed from the 'a' array, moving a_ptr_min forward.
            a_ptr_min += (w[i] - 1); // w[i]-1 because one number is already taken by a_ptr_min
            a_ptr_max--; // One largest number is taken
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

