void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_pattern(k, '?');
    bool possible = true;

    for (int i = 0; i < n; ++i) {
        char current_char = s[i];
        int pattern_idx = i % k;

        if (current_char != '?') {
            if (fixed_pattern[pattern_idx] == '?') {
                fixed_pattern[pattern_idx] = current_char;
            } else if (fixed_pattern[pattern_idx] != current_char) {
                possible = false;
                break;
            }
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    int zeros = 0;
    int ones = 0;
    int question_marks = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_pattern[i] == '0') {
            zeros++;
        } else if (fixed_pattern[i] == '1') {
            ones++;
        } else {
            question_marks++;
        }
    }

    if (zeros > k / 2 || ones > k / 2) {
        possible = false;
    } else {
        // We need to fill (k/2 - zeros) '0's and (k/2 - ones) '1's
        // The remaining question_marks must be exactly (k/2 - zeros) + (k/2 - ones)
        // which simplifies to k - zeros - ones.
        // This is always true by definition of question_marks.
        // So, as long as zeros <= k/2 and ones <= k/2, it's possible to fill the pattern.
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

