int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, which fits in long long.
    // We need to perform division by 2.
    // If b is even, b/2 is integer.
    // If b is odd, (b-1)/2 is integer.
    // (b-1) * b is always even, so (b-1)*b/2 is always an integer.
    // We need to compute this modulo MOD.
    // (X * Y / 2) % MOD = (X % MOD * Y % MOD * inv(2) % MOD) % MOD
    // inv(2) modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004
    long long inv2 = 500000004;

    long long sum_r_term1 = (b - 1) % MOD;
    long long sum_r_term2 = b % MOD;
    long long sum_r = (sum_r_term1 * sum_r_term2) % MOD;
    sum_r = (sum_r * inv2) % MOD;

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // sum_k_b_plus_1 = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_{k=1 to a} k = a * (a + 1) / 2
    // sum_{k=1 to a} 1 = a
    // So, sum_k_b_plus_1 = b * a * (a + 1) / 2 + a

    long long sum_k_term1 = a % MOD;
    long long sum_k_term2 = (a + 1) % MOD;
    long long sum_k = (sum_k_term1 * sum_k_term2) % MOD;
    sum_k = (sum_k * inv2) % MOD;

    long long sum_k_b_plus_1_part1 = (b % MOD * sum_k) % MOD;
    long long sum_k_b_plus_1_part2 = a % MOD;
    long long sum_k_b_plus_1 = (sum_k_b_plus_1_part1 + sum_k_b_plus_1_part2) % MOD;

    // Total sum S = sum_r * sum_k_b_plus_1
    long long total_sum = (sum_r * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

