int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    std::deque<std::pair<long long, int>> dq; // {height, index}
    std::vector<long long> p(n); // p[i] = min_ops to destroy tower i from left/right

    // Calculate p[i] from left
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
        long long current_p = 0;
        if (i > 0) {
            current_p = p[i-1] + 1;
        }

        // Maintain a monotonic deque of increasing heights
        // When a new tower h[i] comes, pop towers from the back of dq that are taller than h[i]
        // These popped towers cannot be limited by h[i] from the left, but h[i] might be limited by them.
        // The current tower h[i] can be limited by its own height or by a previous tower.
        // If dq is not empty, the last element dq.back().first is the height of the tallest tower to the left
        // that could potentially limit h[i].
        // The number of operations for h[i] is at least its own height.
        // It's also at least 1 + operations for h[i-1].
        // It's also at least 1 + operations for any h[j] where j < i, if h[j] is taller than h[i].
        // The actual value is min(h[i], 1 + p[i-1]).
        // The deque helps find the minimum of (h[j] + (i-j)) for j < i.

        // The value p[i] represents the minimum number of operations to destroy the block at (i, y)
        // considering only blocks to its left (including itself).
        // This is equivalent to min(h[i], 1 + p[i-1]).
        // The deque stores pairs {height, index} in increasing order of height.
        // When we process h[i], we want to find the minimum of h[i] and (h[j] + (i-j)) for j < i.
        // The deque helps find the minimum of (h[j] + (i-j)) efficiently.
        // For a new h[i], we pop elements from the back of dq if their height is greater than h[i].
        // This is because if dq.back().first > h[i], then h[i] will be a better candidate for future towers
        // than dq.back().first, as h[i] is smaller and closer.
        while (!dq.empty() && dq.back().first >= h[i]) {
            dq.pop_back();
        }
        dq.push_back({h[i], i});

        // Now dq contains elements {h[j], j} such that h[j] is increasing.
        // We want to find min(h[j] + (i-j)) for j in dq.
        // This is equivalent to min(h[j] - j) + i.
        // The deque stores (h[j] - j) values in increasing order.
        // So, the minimum is at the front of the deque.
        while (!dq.empty() && dq.front().first + (i - dq.front().second) < current_p) {
            current_p = dq.front().first + (i - dq.front().second);
            dq.pop_front();
        }

        p[i] = current_p;
    }

    dq.clear();
    std::vector<long long> s(n); // s[i] = min_ops to destroy tower i from right/left
    long long max_ops = 0;

    // Calculate s[i] from right
    for (int i = n - 1; i >= 0; --i) {
        long long current_s = 0;
        if (i < n - 1) {
            current_s = s[i+1] + 1;
        }

        while (!dq.empty() && dq.back().first >= h[i]) {
            dq.pop_back();
        }
        dq.push_back({h[i], i});

        while (!dq.empty() && dq.front().first + (dq.front().second - i) < current_s) {
            current_s = dq.front().first + (dq.front().second - i);
            dq.pop_front();
        }
        s[i] = current_s;

        max_ops = std::max(max_ops, std::min(p[i], s[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

