        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: Do nothing
        std::cout << "1 1\n";
        std::cout << "0\n";

        // Operation 3: Do nothing
        std::cout << "1 1\n";
        std::cout << "0\n";
    } else {
        // Operation 1: Handle all elements except the last one (a[0] to a[n-2])
        // For each a[i], we want to add b[i] such that (a[i] + b[i]) % n == 0.
        // We can achieve this by adding (n - (a[i] % n)) % n.
        // Let x_i = (n - (a[i] % n)) % n.
        // Then a[i] + x_i is a multiple of n.
        // We need to add b_i such that b_i is a multiple of n-1.
        // This is not the strategy.

        // Strategy:
        // 1. Make a[0]...a[n-2] multiples of n.
        //    Segment [1, n-1] (0-indexed: [0, n-2]), length n-1.
        //    For each a[i] in this segment, we want to add b_i such that b_i is a multiple of (n-1).
        //    We want a[i] + b_i to be 0 eventually.
        //    Let's make a[i] a multiple of n.
        //    For each a[i] (0 <= i < n-1), calculate `rem = a[i] % n`.
        //    If `rem` is negative, add `n` to make it positive.
        //    `add_val = (n - rem) % n`.
        //    This `add_val` is what we need to add to `a[i]` to make it a multiple of `n`.
        //    We need `add_val` to be a multiple of `n-1`. This is not guaranteed.

        // Let's use the property that we can add a multiple of `len`.
        // Operation 1: Segment [1, n] (0-indexed: [0, n-1]), length n.
        // For each a[i], we want to add b_i such that b_i is a multiple of n.
        // We want a[i] + b_i to be 0 eventually.
        // Let's make a[i] a multiple of n.
        // For each a[i], calculate `rem = a[i] % n`.
        // If `rem` is negative, add `n` to make it positive.
        // `add_val = (n - rem) % n`.
        // This `add_val` is what we need to add to `a[i]` to make it a multiple of `n`.
        // Since `add_val` is in [0, n-1], it is already a multiple of `n` only if `add_val == 0`.
        // This is not the right approach.

        // The problem states "add a multiple of len".
        // So, `b_i` must be a multiple of `len`.
        // We want `a_i + b_i = 0`. So `b_i = -a_i`.
        // This means `-a_i` must be a multiple of `len`.
        // Or `a_i` must be a multiple of `len`.

        // Let's use the strategy from a known solution for this problem type.
        // The trick is to use `n` and `n-1` as lengths.

        // Operation 1: Segment [1, n-1] (0-indexed: [0, n-2]), length n-1.
        // For each a[i] in this segment, we want to add b_i such that b_i is a multiple of (n-1).
        // We want to make a[i] a multiple of n.
        // For each a[i] (0 <= i < n-1):
        //   Let `rem = a[i] % n`.
        //   If `rem` is negative, `rem += n`.
        //   We need to add `x` such that `(a[i] + x) % n == 0` and `x % (n-1) == 0`.
        //   This means `x = k * (n-1)` for some integer `k`.
        //   And `a[i] + k * (n-1)` must be a multiple of `n`.
        //   `a[i] + k * (n-1) = a[i] + k * (-1) (mod n)`
        //   So, `a[i] - k = 0 (mod n)`.
        //   `k = a[i] (mod n)`.
        //   Let `k_val = a[i] % n`. If `k_val` is negative, `k_val += n`.
        //   Then `b_i = k_val * (n-1)`.
        //   After this operation, `a[i]` becomes `a[i] + k_val * (n-1)`.
        //   This new `a[i]` is a multiple of `n`.

        std::cout << "1 " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long rem = a[i] % n;
            if (rem < 0) {
                rem += n;
            }
            long long b_i = rem * (n - 1);
            std::cout << b_i << (i == n - 2 ? "" : " ");
            a[i] += b_i; // Update a[i]
        }
        std::cout << "\n";

        // Operation 2: Handle the last element a[n-1].
        // Segment [n, n] (0-indexed: [n-1, n-1]), length 1.
        // We can add any multiple of 1. So we can make a[n-1] zero directly.
        std::cout << n << " " << n << "\n";
        std::cout << -a[n - 1] << "\n";
        a[n - 1] = 0; // Update a[n-1]

        // Operation 3: Segment [1, n] (0-indexed: [0, n-1]), length n.
        // Now, for 0 <= i < n-1, a[i] is a multiple of n.
        // And a[n-1] is 0, which is also a multiple of n.
        // So all a[i] are multiples of n.
        // We want to add b_i such that b_i is a multiple of n, and a[i] + b_i = 0.
        // So, b_i = -a[i].
        // Since a[i] is a multiple of n, -a[i] is also a multiple of n.
        // This operation makes all elements zero.
        std::cout << "1 " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
