int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val_0 = 0;    // Value if input is 0
    int current_val_1023 = 1023; // Value if input is 1023 (all 1s for 10 bits)

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_0 &= x;
            current_val_1023 &= x;
        } else if (op_char == '|') {
            current_val_0 |= x;
            current_val_1023 |= x;
        } else if (op_char == '^') {
            current_val_0 ^= x;
            current_val_1023 ^= x;
        }
    }

    // Now we have the final state for input 0 and input 1023.
    // Let f(0) = current_val_0 and f(1023) = current_val_1023.
    // We need to find a minimal sequence of operations that achieves this.
    // For each bit position i (0 to 9):
    // Let x_i be the i-th bit of the input.
    // Let f(x)_i be the i-th bit of the output.
    // We know f(0)_i and f(1)_i (from current_val_0 and current_val_1023).
    //
    // Case 1: f(0)_i = 0, f(1)_i = 0  =>  f(x)_i = 0 for all x_i. This means the bit is always 0.
    // Case 2: f(0)_i = 0, f(1)_i = 1  =>  f(x)_i = x_i for all x_i. This means the bit is unchanged.
    // Case 3: f(0)_i = 1, f(1)_i = 0  =>  f(x)_i = !x_i for all x_i. This means the bit is flipped.
    // Case 4: f(0)_i = 1, f(1)_i = 1  =>  f(x)_i = 1 for all x_i. This means the bit is always 1.

    int final_and_mask = 1023; // Bits that become 0 must be ANDed with 0
    int final_or_mask = 0;     // Bits that become 1 must be ORed with 1
    int final_xor_mask = 0;    // Bits that are flipped must be XORed with 1

    for (int i = 0; i < 10; ++i) {
        int bit_0 = (current_val_0 >> i) & 1;
        int bit_1 = (current_val_1023 >> i) & 1;

        if (bit_0 == 0 && bit_1 == 0) { // Case 1: f(x)_i = 0
            final_and_mask &= ~(1 << i); // Force this bit to 0
        } else if (bit_0 == 0 && bit_1 == 1) { // Case 2: f(x)_i = x_i
            // No change needed for this bit by AND, OR, XOR
        } else if (bit_0 == 1 && bit_1 == 0) { // Case 3: f(x)_i = !x_i
            final_xor_mask |= (1 << i); // Flip this bit
        } else if (bit_0 == 1 && bit_1 == 1) { // Case 4: f(x)_i = 1
            final_or_mask |= (1 << i); // Force this bit to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_or_mask != 0) {
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_and_mask != 1023) {
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_xor_mask != 0) {
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

