#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> val(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        val[i] = (a[i] == 1 ? 1 : -1);
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // S_L[k] = sum(val[0]...val[k-1])
    std::vector<int> s_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        s_left[i + 1] = s_left[i] + val[i];
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // S_R[k] = sum(val[2n-1]...val[2n-k])
    std::vector<int> s_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        s_right[i + 1] = s_right[i] + val[2 * n - 1 - i];
    }

    // Map to store the minimum number of jars removed from the left half
    // to achieve a certain balance difference.
    // key: balance difference (S-B)
    // value: number of jars removed (k_L)
    std::map<int, int> left_diff_to_kL;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff = s_left[n] - s_left[k_L]; // Balance of remaining jars on left
        if (left_diff_to_kL.find(current_diff) == left_diff_to_kL.end()) {
            left_diff_to_kL[current_diff] = k_L;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible removed jars

    // Iterate through possible number of jars removed from the right half (k_R)
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_diff_right = s_right[n] - s_right[k_R]; // Balance of remaining jars on right
        int target_diff_left = -current_diff_right; // We need S_L_rem - B_L_rem = -(S_R_rem - B_R_rem)

        if (left_diff_to_kL.count(target_diff_left)) {
            int k_L = left_diff_to_kL[target_diff_left];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

