int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with a small positive number

    while (X > 0) {
        long long k = 0;
        // Find the largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        // We want to find the largest k such that (1LL << (k+1)) - 1 <= X
        // This means (1LL << (k+1)) <= X + 1
        // So k+1 <= log2(X+1)
        // k <= log2(X+1) - 1
        // Or, more simply, find largest k such that 2^k - 1 <= X.
        // This means we want to find the largest k such that X has at least k set bits from the right.
        // Or, find the largest k such that (1LL << k) - 1 <= X.
        // This is equivalent to finding the largest k such that X has at least k bits set from the right.
        // Example: X = 10 (1010_2).
        // k=0: 2^0-1 = 0 <= 10.
        // k=1: 2^1-1 = 1 <= 10.
        // k=2: 2^2-1 = 3 <= 10.
        // k=3: 2^3-1 = 7 <= 10.
        // k=4: 2^4-1 = 15 > 10.
        // So k=3.
        // The number of subsequences we can form with k identical elements is 2^k - 1.
        // We want to use the largest possible k such that 2^k - 1 <= X.
        // This is equivalent to finding the highest set bit in X+1, and k is its position.
        // Or, more simply, iterate k from 60 down to 0.
        for (int i = 60; i >= 0; --i) {
            if (((1LL << (i + 1)) - 1) <= X) {
                k = i + 1;
                break;
            }
        }

        // If X is 0, k will be 0.
        // If X is 1, k will be 1. (2^1-1 = 1 <= 1)
        // If X is 2, k will be 1. (2^1-1 = 1 <= 2, 2^2-1 = 3 > 2)
        // If X is 3, k will be 2. (2^2-1 = 3 <= 3)
        // This logic for k is correct.

        // Add k copies of current_val to the result array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }

        // Subtract the count of subsequences formed by these k elements
        X -= ((1LL << k) - 1);

        // Increment current_val for the next block
        // The next block of elements must be at least d greater than current_val
        // to ensure that any subsequence combining elements from different blocks
        // will have max_element - min_element >= d.
        // We add 1 to d to ensure strict inequality.
        current_val += (d + 1);
    }

    if (result_array.size() > 10000) {
        // This case should ideally not be reached given X <= 10^9.
        // Max k is around 60. X = 10^9.
        // 10^9 in binary is roughly 2^30.
        // So k will be at most 30.
        // The number of elements added is sum of k's.
        // X = (2^k1-1) + (2^k2-1) + ...
        // The sum of k's is roughly sum of log2(X_i).
        // Max X is 10^9. Max k is 30.
        // If X = 10^9, and we always pick k=1 (2^1-1=1), then we add 10^9 elements, which is too many.
        // But we pick the largest k.
        // The number of elements is sum of bits in X's binary representation.
        // For X = 10^9, max number of set bits is 30. So max elements is 30.
        // This is well within 10000.
        // The problem statement implies that X is the number of subsequences, not the sum of k's.
        // The number of elements is the sum of k's.
        // X = 10^9.
        // 10^9 = 536870912 + 268435456 + 134217728 + 67108864 + 33554432 + 16777216 + 8388608 + 4194304 + 2097152 + 1048576 + 524288 + 262144 + 131072 + 65536 + 32768 + 16384 + 8192 + 4096 + 2048 + 1024 + 512 + 256 + 128 + 64 + 32 + 16 + 8 + 4 + 2 + 1
        // This is 30 terms. So 30 elements.
        // The maximum number of elements is the number of set bits in X.
        // For X = 10^9, this is 30.
        // So the size constraint of 10^4 is always satisfied.
        // No need for -1 check here.
    }

    std::cout << result_array.size() << "\n";
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        char last1 = '0';
        char last2 = '0';
        bool possible_with_pivot = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < pivot_digit + '0') {
                // Must be color 1
                if (current_digit < last1) {
                    possible_with_pivot = false;
                    break;
                }
                result[i] = '1';
                last1 = current_digit;
            } else if (current_digit > pivot_digit + '0') {
                // Must be color 2
                if (current_digit < last2) {
                    possible_with_pivot = false;
                    break;
                }
                result[i] = '2';
                last2 = current_digit;
            } else { // current_digit == pivot_digit + '0'
                // Can be color 1 or 2
                // Prioritize color 2 if it maintains non-decreasing order
                if (current_digit >= last2) {
                    result[i] = '2';
                    last2 = current_digit;
                } else if (current_digit >= last1) {
                    result[i] = '1';
                    last1 = current_digit;
                } else {
                    possible_with_pivot = false;
                    break;
                }
            }
        }

        if (possible_with_pivot) {
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

