int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (b_1=a_1, b_n=a_n, no middle elements)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> first_zero_block_end(n, -1); // Stores the rightmost index of a 0-block ending at or before i
    std::vector<int> first_one_block_end(n, -1);  // Stores the rightmost index of a 1-block ending at or before i

    int current_zero_block_end = -1;
    int current_one_block_end = -1;

    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            current_zero_block_end = i;
        } else {
            current_one_block_end = i;
        }
        first_zero_block_end[i] = current_zero_block_end;
        first_one_block_end[i] = current_one_block_end;
    }

    std::vector<int> last_zero_block_start(n, -1); // Stores the leftmost index of a 0-block starting at or after i
    std::vector<int> last_one_block_start(n, -1);  // Stores the leftmost index of a 1-block starting at or after i

    int current_zero_block_start = -1;
    int current_one_block_start = -1;

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            current_zero_block_start = i;
        } else {
            current_one_block_start = i;
        }
        last_zero_block_start[i] = current_zero_block_start;
        last_one_block_start[i] = current_one_block_start;
    }

    int max_steps = 0;
    std::vector<int> b = a; // The final stable sequence

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // Current element is 0, it can become 1 if it's part of a 011 or 110 pattern
            // Find the nearest 1 to the left (first_one_block_end[i-1])
            // Find the nearest 1 to the right (last_one_block_start[i+1])
            if (first_one_block_end[i - 1] != -1 && last_one_block_start[i + 1] != -1) {
                int dist_left = i - first_one_block_end[i - 1];
                int dist_right = last_one_block_start[i + 1] - i;
                int steps = std::min(dist_left, dist_right);
                max_steps = std::max(max_steps, steps);
                if (dist_left == dist_right) {
                    b[i] = 0; // Stays 0 if equidistant
                } else if (dist_left < dist_right) {
                    b[i] = 1; // Becomes 1 if left 1 is closer
                } else { // dist_right < dist_left
                    b[i] = 1; // Becomes 1 if right 1 is closer
                }
            } else if (first_one_block_end[i - 1] != -1) { // Only 1s to the left
                int steps = i - first_one_block_end[i - 1];
                max_steps = std::max(max_steps, steps);
                b[i] = 1;
            } else if (last_one_block_start[i + 1] != -1) { // Only 1s to the right
                int steps = last_one_block_start[i + 1] - i;
                max_steps = std::max(max_steps, steps);
                b[i] = 1;
            } else { // No 1s around, stays 0
                b[i] = 0;
            }
        } else { // Current element is 1, it can become 0 if it's part of a 100 or 001 pattern
            // Find the nearest 0 to the left (first_zero_block_end[i-1])
            // Find the nearest 0 to the right (last_zero_block_start[i+1])
            if (first_zero_block_end[i - 1] != -1 && last_zero_block_start[i + 1] != -1) {
                int dist_left = i - first_zero_block_end[i - 1];
                int dist_right = last_zero_block_start[i + 1] - i;
                int steps = std::min(dist_left, dist_right);
                max_steps = std::max(max_steps, steps);
                if (dist_left == dist_right) {
                    b[i] = 1; // Stays 1 if equidistant
                } else if (dist_left < dist_right) {
                    b[i] = 0; // Becomes 0 if left 0 is closer
                } else { // dist_right < dist_left
                    b[i] = 0; // Becomes 0 if right 0 is closer
                }
            } else if (first_zero_block_end[i - 1] != -1) { // Only 0s to the left
                int steps = i - first_zero_block_end[i - 1];
                max_steps = std::max(max_steps, steps);
                b[i] = 0;
            } else if (last_zero_block_start[i + 1] != -1) { // Only 0s to the right
                int steps = last_zero_block_start[i + 1] - i;
                max_steps = std::max(max_steps, steps);
                b[i] = 0;
            } else { // No 0s around, stays 1
                b[i] = 1;
            }
        }
    }

    std::cout << max_steps << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
    long long max_val_at_op_time; // For type 2, this is the m_i
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> a(n);
    std::vector<long long> current_delta(n, 0);

    // Step 1: Determine upper bounds for a[i]
    // For each type 2 operation (2 l r m), it implies a[j] + delta[j] <= m for l <= j <= r.
    // This means a[j] <= m - delta[j].
    // We want to find the largest possible a[j] that satisfies all constraints.
    // So, a[j] must be <= min(m - delta[j]) over all relevant type 2 operations.
    // Initialize a[i] to a very large value (effectively infinity)
    for (int i = 0; i < n; ++i) {
        a[i] = std::numeric_limits<long long>::max();
    }

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a[j] = std::min(a[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Step 2: Verify the solution and adjust a[i] if necessary
    // After step 1, a[i] contains the maximum possible initial value for each index
    // that satisfies all type 2 upper bound constraints.
    // Now, we need to check if these values actually work.
    // For each type 2 operation (2 l r m), we must have max(a[j] + delta[j]) = m.
    // If max(a[j] + delta[j]) < m, then no solution exists.
    // If max(a[j] + delta[j]) > m, then our a[j] values are too high, which contradicts
    // how we derived them (they are already the maximum possible). This case should not happen
    // if the problem is well-posed and a solution exists.

    // Reset current_delta for verification
    std::fill(current_delta.begin(), current_delta.end(), 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long current_max = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_max = std::max(current_max, a[j] + current_delta[j]);
            }
            if (current_max != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial array elements
    for (int i = 0; i < n; ++i) {
        if (std::abs(a[i]) > 1000000000LL) {
            // This case should ideally be caught by the current_max != ops[i].val check
            // if the problem guarantees a solution within bounds.
            // However, if a[i] was initialized to max_long_long and never constrained,
            // it might remain too large.
            // The problem statement says "Levko clearly remembers that all numbers in his array didn't exceed 10^9 in their absolute value"
            // This implies that if a solution exists, it must satisfy this.
            // Our construction finds the largest possible a[i]. If this largest possible a[i]
            // is out of bounds, then no solution exists within bounds.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v;
    long long d;
    long long p;
    int original_idx;
    bool active; // To mark if child is still in line

    Child(long long v_val, long long d_val, long long p_val, int idx)
        : v(v_val), d(d_val), p(p_val), original_idx(idx), active(true) {}
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children_data;
    children_data.reserve(n);
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_data.emplace_back(v_val, d_val, p_val, i + 1);
    }

    std::vector<int> treated_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children_data[i].active) {
            continue; // This child has already left
        }

        // Child i goes to the dentist
        treated_children_indices.push_back(children_data[i].original_idx);
        children_data[i].active = false; // Mark as treated

        long long current_v_cry = children_data[i].v;
        long long cumulative_d_cry = 0;

        // Apply initial cry from child i
        for (int j = i + 1; j < n; ++j) {
            if (!children_data[j].active) {
                continue;
            }

            // Apply cry from child i
            if (current_v_cry > 0) {
                children_data[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply cumulative cry from children who left earlier in this chain reaction
            children_data[j].p -= cumulative_d_cry;
        }

        // Chain reaction loop
        bool chain_reaction_happened;
        do {
            chain_reaction_happened = false;
            for (int j = i + 1; j < n; ++j) {
                if (children_data[j].active && children_data[j].p < 0) {
                    children_data[j].active = false; // Child j leaves
                    cumulative_d_cry += children_data[j].d; // Add to cumulative cry
                    chain_reaction_happened = true;

                    // Apply this child's d_cry to all subsequent active children
                    for (int k = j + 1; k < n; ++k) {
                        if (children_data[k].active) {
                            children_data[k].p -= children_data[j].d;
                        }
                    }
                }
            }
        } while (chain_reaction_happened);
    }

    std::cout << treated_children_indices.size() << "\n";
    for (size_t i = 0; i < treated_children_indices.size(); ++i) {
        std::cout << treated_children_indices[i] << (i == treated_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

bool is_permutation_prefix(const std::vector<int>& a, int len) {
    if (len == 0) return false;
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (a[i] <= 0 || a[i] > len) {
            return false;
        }
        if (seen[a[i]]) {
            return false;
        }
        seen[a[i]] = true;
        if (a[i] > max_val) {
            max_val = a[i];
        }
    }
    return max_val == len;
}

bool is_permutation_suffix(const std::vector<int>& a, int start_idx, int len) {
    if (len == 0) return false;
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (a[start_idx + i] <= 0 || a[start_idx + i] > len) {
            return false;
        }
        if (seen[a[start_idx + i]]) {
            return false;
        }
        seen[a[start_idx + i]] = true;
        if (a[start_idx + i] > max_val) {
            max_val = a[start_idx + i];
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_is_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max = 0;
    bool current_prefix_valid = true;
    for (int i = 0; i < n; ++i) {
        if (current_prefix_valid) {
            if (a[i] <= 0 || a[i] > i + 1 || seen_prefix[a[i]]) {
                current_prefix_valid = false;
            } else {
                seen_prefix[a[i]] = true;
                if (a[i] > current_max) {
                    current_max = a[i];
                }
                if (current_max == i + 1) {
                    prefix_is_perm[i + 1] = true;
                }
            }
        }
    }

    std::vector<bool> suffix_is_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    current_max = 0;
    bool current_suffix_valid = true;
    for (int i = n - 1; i >= 0; --i) {
        int len = n - i;
        if (current_suffix_valid) {
            if (a[i] <= 0 || a[i] > len || seen_suffix[a[i]]) {
                current_suffix_valid = false;
            } else {
                seen_suffix[a[i]] = true;
                if (a[i] > current_max) {
                    current_max = a[i];
                }
                if (current_max == len) {
                    suffix_is_perm[len] = true;
                }
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

