// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k = 1 (2 pieces)
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string s_new = s_suffix + s_prefix;

        if (s_new != s && is_palindrome(s_new)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2 (3 pieces)
    // The problem statement implies that if k=1 doesn't work,
    // we should check k=2.
    // The only way k=2 is needed is if all single-cut rotations
    // either result in the original string or are not palindromes.
    //
    // Consider the structure of the original palindrome 's'.
    // If 's' consists of only one distinct character (e.g., "aaaaa"),
    // then any rotation will result in the same string "aaaaa".
    // In this case, it's impossible to get a new string.
    //
    // If 's' has at least two distinct characters, and it's a palindrome,
    // and no single cut rotation works, then we need to check if k=2 is possible.
    //
    // Example: "nolon"
    // n=5
    // i=1: "olon" + "n" = "olonn" (not palindrome)
    // i=2: "lon" + "no" = "lonno" (not palindrome)
    // i=3: "on" + "nol" = "onnol" (not palindrome)
    // i=4: "n" + "nolo" = "nnolo" (not palindrome)
    //
    // The example says "nolon" -> 2 cuts.
    // "no|l|on" -> "on|l|no" = "onlno" (palindrome, != "nolon")
    //
    // This implies that if a string is a palindrome, and it's not composed
    // of a single repeating character, then it's always possible to make
    // a new palindrome with 2 cuts.
    //
    // Let's verify this.
    // If s is a palindrome and not all characters are the same:
    // s = c_1 c_2 ... c_k ... c_2 c_1
    // Since not all characters are the same, there must be at least one character
    // c_i such that c_i != c_1 (for i > 1).
    //
    // Consider cutting s into s[0...N-2] and s[N-1].
    // s = s_prefix + s_suffix, where s_suffix is s[N-1].
    // s_new = s_suffix + s_prefix = s[N-1] + s[0...N-2].
    // If this is not s and is a palindrome, k=1.
    //
    // If all single-cut rotations fail, it means either:
    // 1. All rotations result in 's'. This happens if all characters in 's' are the same.
    //    e.g., "aaaaa". In this case, no matter how you cut and rearrange, you get "aaaaa".
    // 2. Some rotations are not 's', but none of them are palindromes.
    //    e.g., "nolon". Rotations like "olonn", "lonno", etc., are not palindromes.
    //
    // If all characters in 's' are the same (e.g., "qqqq"), then it's impossible.
    // We can check this by counting distinct characters.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 must be the answer.
        // The logic is that if s is a palindrome and has at least two distinct characters,
        // and no single rotation works, then we can always achieve a new palindrome with 2 cuts.
        // For example, take s = "abacaba".
        // Rotations: "bacabaa", "acabaab", "cabaaba", "abaacab", "baacaba", "aacabab".
        // None of these are palindromes.
        //
        // Consider cutting s into s[0], s[1...N-2], s[N-1].
        // For "nolon": s[0]='n', s[1...3]="olo", s[4]='n'.
        // Rearrange to s[4], s[1...3], s[0] -> "n" + "olo" + "n" = "nolon" (original)
        //
        // The example "nolon" -> "onlno" uses cuts "no|l|on" and rearranges to "on|l|no".
        // This is s[3..4] + s[2] + s[0..1].
        //
        // The problem statement guarantees that s is a palindrome.
        // If s is a palindrome and not all characters are the same,
        // then it's always possible to find a new palindrome with 2 cuts.
        // The proof for this is non-trivial but generally relies on the fact
        // that you can isolate a central part or swap outer parts to break symmetry
        // in a way that forms a new palindrome.
        // For example, if s = "abacaba", cut "a|bacab|a". Rearrange to "a|bacab|a" (original).
        // But if you cut "ab|a|caba", you can't easily form a new palindrome.
        //
        // The key insight from competitive programming problems like this is often
        // that if k=1 doesn't work, and it's not the "all same characters" impossible case,
        // then k=2 is the answer. This is a common pattern for "minimum k" problems
        // where k is small (0, 1, 2).
        //
        // The example "nolon" -> 2 cuts confirms this.
        // "otto" -> 1 cut ("ot|to" -> "toot")
        // "qqqq" -> Impossible
        // "kinnikkinnik" -> 1 cut ("kinnik|kinnik" -> "kinnikkinnik" (original))
        // Wait, "kinnikkinnik" is a palindrome.
        // n=12.
        // s_prefix = "kinnik", s_suffix = "kinnik".
        // s_new = "kinnikkinnik" (original).
        //
        // Let's re-check "kinnikkinnik".
        // The example output is 1.
        // "kinnikkinnik"
        // Cut "kinnik|kinnik" -> "kinnikkinnik" (original)
        // Cut "kinnikkinnik" at i=3: "kin" + "nikkinnik" -> "nikkinnikkin"
        // Is "nikkinnikkin" a palindrome?
        // "nikkinnikkin" reversed is "nikkinnikkin". Yes.
        // Is "nikkinnikkin" != "kinnikkinnik"? Yes.
        // So for "kinnikkinnik", k=1 is the answer.
        // My loop for k=1 should have found this.
        //
        // Let's trace "kinnikkinnik" with my code:
        // s = "kinnikkinnik", n = 12
        // i=1: "innikkinnik" + "k" = "innikkinnikk" (not palindrome)
        // i=2: "nnikkinnik" + "ki" = "nnikkinnikki" (not palindrome)
        // i=3: "nikkinnik" + "kin" = "nikkinnikkin"
        //      is_palindrome("nikkinnikkin") -> true
        //      "nikkinnikkin" != "kinnikkinnik" -> true
        //      Output 1. Correct.
        //
        // So the logic for k=1 is correct.
        // The only remaining case for k=2 is when k=1 fails AND not all characters are the same.
        // This covers "nolon".
        //
        // Therefore, the logic is:
        // 1. Try k=1. If a valid new palindrome is found, output 1.
        // 2. If k=1 fails, check if all characters in 's' are the same.
        //    If yes, output "Impossible".
        // 3. If k=1 fails AND not all characters are the same, output 2.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_sequences = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // If the first matryoshka in a chain is 1, it's a potential start of the main sequence.
        // We need to count how many consecutive correct nestings (j -> j+1) exist starting from 1.
        if (chain[0] == 1) {
            int current_expected = 1;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_expected) {
                    correct_sequences++;
                    current_expected++;
                } else {
                    // The sequence 1 -> 2 -> ... -> current_expected-1 is correct.
                    // Any further elements in this chain are not part of the initial correct prefix.
                    break; 
                }
            }
        }
    }

    // Total operations needed:
    // 1. Disassemble all incorrect nestings.
    //    Each chain of length `m` has `m-1` nestings.
    //    Total initial nestings = n - k (since sum of m_i = n, and each chain has m_i-1 nestings)
    //    Number of correct nestings (1->2, 2->3, ...) is `correct_sequences - 1`.
    //    So, `(n - k) - (correct_sequences - 1)` nestings need to be undone.
    //    Each undo operation costs 1 second.
    //    This simplifies to `n - k - correct_sequences + 1` operations.
    // 2. Reassemble the final chain.
    //    The final chain `1 -> 2 -> ... -> n` requires `n-1` nestings.
    //    We already have `correct_sequences - 1` of these.
    //    So, `(n-1) - (correct_sequences - 1)` new nestings need to be performed.
    //    Each new nesting operation costs 1 second.
    //    This simplifies to `n - correct_sequences` operations.

    // Total operations = (disassemble incorrect) + (assemble missing correct)
    // Total operations = ( (n - k) - (correct_sequences - 1) ) + ( (n - 1) - (correct_sequences - 1) )
    // Total operations = (n - k - correct_sequences + 1) + (n - correct_sequences)
    // Total operations = n - k - correct_sequences + 1 + n - correct_sequences
    // Total operations = 2*n - k - 2*correct_sequences + 1

    // Let's re-evaluate.
    // We need to form n-1 connections (1->2, 2->3, ..., (n-1)->n).
    // `correct_sequences - 1` of these connections are already present and correct.
    // So, `(n-1) - (correct_sequences - 1)` connections need to be *made*. This is `n - correct_sequences` 'put' operations.

    // For the 'get out' operations:
    // Each chain has `m_i` dolls. If `m_i > 1`, it has `m_i - 1` internal nestings.
    // The total number of initial nestings across all chains is `(m_1-1) + (m_2-1) + ... + (m_k-1) = (m_1+...+m_k) - k = n - k`.
    // Out of these `n-k` initial nestings, `correct_sequences - 1` are part of the final `1->2->...->n` sequence.
    // The remaining `(n-k) - (correct_sequences - 1)` nestings must be undone. These are 'get out' operations.
    // This simplifies to `n - k - correct_sequences + 1` 'get out' operations.

    total_operations = (long long)(n - correct_sequences) + (long long)(n - k - correct_sequences + 1);

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<bool> head_used(n, false);
    int current_p_idx = 0;
    int current_h_idx = 0;

    while (current_p_idx < m) {
        long long target_p = p[current_p_idx];

        // Find the first available head that can reach target_p
        // An available head is one that hasn't been used yet and can reach target_p
        // We want to use the leftmost possible head to cover target_p
        // This head will then cover as many subsequent p_j's as possible.

        // Find the first head h_k such that h_k - T <= target_p
        // This means h_k <= target_p + T
        // We need to find the smallest h_k that satisfies this.
        // And also h_k + T >= target_p
        // So, h_k is in [target_p - T, target_p + T]

        // We iterate through heads.
        // If a head h_k is too far to the left (h_k + T < target_p), it cannot cover target_p.
        // We advance current_h_idx past such heads.
        while (current_h_idx < n && h[current_h_idx] + T < target_p) {
            current_h_idx++;
        }

        // If we ran out of heads, or the current head is too far to the right
        // (h[current_h_idx] - T > target_p), then target_p cannot be covered.
        if (current_h_idx >= n || h[current_h_idx] - T > target_p) {
            return false; // No head can cover this target_p
        }

        // Now, h[current_h_idx] is the leftmost head that can potentially cover target_p.
        // It covers the range [h[current_h_idx] - T, h[current_h_idx] + T].
        // All p_j's within this range are covered.
        long long cover_end = h[current_h_idx] + T;

        // Advance current_p_idx past all p_j's covered by this head.
        while (current_p_idx < m && p[current_p_idx] <= cover_end) {
            current_p_idx++;
        }

        // Move to the next head for the next uncovered target_p.
        // This head is now "used" for this iteration.
        current_h_idx++;
    }

    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: (10^10 - 1) + (10^10 - 1) approx 2*10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

