    // The total number of good pairs is sum(last_bad_start[r] - 1) for r from 1 to n.

    // Initialize `last_bad_start[0]` to 1 (meaning s[0...-1] is good, or no bad triplet ends at index -1)
    // `last_bad_start[i]` will store the minimum `l` (1-indexed) such that `s[l-1 ... i-1]` contains a bad triplet.
    // If no such `l` exists, it's `i+1`.
    std::vector<int> last_bad_start(n + 1);
    last_bad_start[0] = 1; // Base case: before any characters, the "start" of a bad segment is 1.

    for (int r_idx = 0; r_idx < n; ++r_idx) { // r_idx is 0-indexed, corresponds to r-1
        int current_min_l = last_bad_start[r_idx]; // Inherit from previous r

        // Check for bad triplets ending at r_idx
