        int min_idx = 0;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < a[min_idx]) {
                min_idx = i;
            }
        }

        long long min_val = a[min_idx];
        long long total_spells = 0;

        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue;
            }
            // For each other pile a[i], we can add min_val to it
            // until a[i] + X * min_val > k
            // So, a[i] + X * min_val <= k
            // X * min_val <= k - a[i]
            // X <= (k - a[i]) / min_val
