#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    if (a[0] == 1) {
        has_pos_one = true;
    } else if (a[0] == -1) {
        has_neg_one = true;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) { // Can only increase if there's a 1 to add
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) { // Can only decrease if there's a -1 to add
                std::cout << "NO\n";
                return;
            }
        }
    }

    std::cout << "YES\n";
}

