#include <iostream>
#include <string>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    int horz_moves = std::min(counts['L'], counts['R']);
    int vert_moves = std::min(counts['U'], counts['D']);

    std::string result_path = "";
    int total_length = 0;

    if (horz_moves == 0 && vert_moves == 0) {
        // No moves possible
        total_length = 0;
        result_path = "";
    } else if (horz_moves == 0) {
        // Only vertical moves possible, e.g., UUDD.
        // To be valid, it must be U then D, or D then U.
        // If we have only U and D, and we want to return to (0,0),
        // we must have at least one U and one D.
        // The path UUDD is invalid because (0,1) is visited twice.
        // The only valid path with only U/D moves is UD or DU.
        // So, if horz_moves is 0, we can only use 2 moves: UD or DU.
        // This is only possible if vert_moves >= 1.
        total_length = 2;
        result_path = "UD";
    } else if (vert_moves == 0) {
        // Only horizontal moves possible, e.g., LLRR.
        // Similar to vertical, only LR or RL is valid.
        // This is only possible if horz_moves >= 1.
        total_length = 2;
        result_path = "LR";
    } else {
        // Both horizontal and vertical moves are available.
        // We can construct a path like U...UR...RD...DL...L
        // or L...LU...UR...RD...D
        // The structure L...LU...UR...RD...D is valid.
        // Example: L U R D
        // The path will be:
        // horz_moves 'L's
        // vert_moves 'U's
        // horz_moves 'R's
        // vert_moves 'D's
        // This forms a rectangle.
        // The length will be 2 * horz_moves + 2 * vert_moves.
        total_length = 2 * horz_moves + 2 * vert_moves;

        for (int i = 0; i < horz_moves; ++i) result_path += 'L';
        for (int i = 0; i < vert_moves; ++i) result_path += 'U';
        for (int i = 0; i < horz_moves; ++i) result_path += 'R';
        for (int i = 0; i < vert_moves; ++i) result_path += 'D';
    }

    std::cout << total_length << std::endl;
    std::cout << result_path << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // min_idx = pos[1], max_idx = pos[1].
        // Length is 1. Max value is 1.
        // This is always beautiful.

        // For m > 1, we expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from min(pos[1]...pos[m]) to max(pos[1]...pos[m]).
        // We maintain current_min_idx and current_max_idx as the minimum and maximum
        // indices encountered so far for numbers 1 to (m-1).
        // When considering 'm', we update these bounds to include pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // is a permutation of 1, 2, ..., m.
        // This means two conditions must be met:
        // 1. The length of the subsegment must be exactly 'm'.
        //    Length = current_max_idx - current_min_idx + 1.
        // 2. The maximum value in this subsegment must be 'm'.
        //    This is implicitly handled by the way we expand the segment.
        //    Since we are considering numbers 1 to m, and we expand the segment
        //    to cover all their positions, the maximum value in this segment
        //    will be 'm' (assuming all numbers 1 to m are distinct and present, which they are).
        //    The minimum value will be '1'.
        // So, we only need to check the length.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

