        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return;
    }

    std::vector<int> result;
    result.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum
        // p[i] is a local maximum if p[i-1] < p[i] and p[i] > p[i+1]
        // p[i] is a local minimum if p[i-1] > p[i] and p[i] < p[i+1]
        bool is_local_max = (p[i-1] < p[i] && p[i] > p[i+1]);
        bool is_local_min = (p[i-1] > p[i] && p[i] < p[i+1]);

        if (is_local_max || is_local_min) {
            result.push_back(p[i]);
        }
    }
    result.push_back(p[n-1]);

    std::cout << result.size() << "\n";
    for (size_t i = 0; i < result.size(); ++i) {
        std::cout << result[i] << (i == result.size() - 1 ? "" : " ");
