#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    // If we remove a prefix of length `p`, the remaining array starts at `a[p]`.
    // This is the first part of the "good" array condition.
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }

    // Now, `a[p...n-1]` is non-decreasing.
    // We need to find the rightmost index `q` such that `a[q...p-1]` is non-increasing.
    // This means a[q] >= a[q+1] >= ... >= a[p-1].
    // The "good" array would be `a[q...n-1]`.
    // The elements `a[q...p-1]` would be taken from the left, and `a[p...n-1]` from the right.
    // The condition for a good array is that there exists an index `p` such that
    // `a[0...p-1]` is non-increasing and `a[p...m-1]` is non-decreasing.
    // In our case, we are looking for the smallest prefix to remove.
    // Let the remaining array be `a[k...n-1]`.
    // We need to find the smallest `k` such that `a[k...n-1]` is good.
    // A good array `b` has a split point `s` such that `b[0...s-1]` is non-increasing
    // and `b[s...m-1]` is non-decreasing.
    // The elements `b[0...s-1]` are taken from the left, and `b[s...m-1]` from the right.
    // The elements taken from the left are `b_0, b_1, ..., b_{s-1}`.
