#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a sub-array is a permutation of length k
// `arr` is the original array, `start_idx` is the starting index of the sub-array,
// `k` is the expected length of the permutation.
// This function assumes elements are 1-indexed.
bool is_permutation(const std::vector<int>& arr, int start_idx, int k) {
    if (k <= 0) { // Permutations must have non-zero length
        return false;
    }
    if (start_idx + k > arr.size()) { // Sub-array out of bounds
        return false;
    }

    std::vector<bool> seen(k + 1, false); // Use 1-indexed for values 1 to k
    int max_val = 0;

    for (int i = 0; i < k; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > k || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == k; // All numbers from 1 to k must be present
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_val_a = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_val_a) {
            max_val_a = a[i];
        }
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix max and suffix max
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i-1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i+1], a[i]);
    }

    // Check all possible split points l1
    // l1 is the length of p1, so p1 is a[0...l1-1]
    // l2 is the length of p2, so p2 is a[l1...n-1]
    // l1 ranges from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Optimization: Check if max element in p1 is l1 and max element in p2 is l2
        // If not, it cannot be a permutation.
        // This is a necessary but not sufficient condition.
        if (prefix_max[l1-1] == l1 && suffix_max[l1] == l2) {
            // Now perform the full check using frequency arrays/sets
            // Check p1
            std::vector<bool> seen_p1(l1 + 1, false);
            bool p1_is_perm = true;
            for (int i = 0; i < l1; ++i) {
                int val = a[i];
                if (val <= 0 || val > l1 || seen_p1[val]) {
                    p1_is_perm = false;
                    break;
                }
                seen_p1[val] = true;
            }

            if (!p1_is_perm) {
                continue;
            }

            // Check p2
            std::vector<bool> seen_p2(l2 + 1, false);
            bool p2_is_perm = true;
            for (int i = 0; i < l2; ++i) {
                int val = a[l1 + i];
                if (val <= 0 || val > l2 || seen_p2[val]) {
                    p2_is_perm = false;
                    break;
                }
                seen_p2[val] = true;
            }

            if (p2_is_perm) {
                results.push_back({l1, l2});
            }
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

