#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This will be 'k' in the explanation, but it's the rightmost point in the window

    for (int i = 0; i < n; ++i) { // 'i' is the leftmost point of the triplet
        // Advance right_ptr (k) until x[right_ptr] - x[i] > d or right_ptr reaches end
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, all points from x[i+1] to x[right_ptr-1] satisfy x[k] - x[i] <= d
        // The number of points in this range (excluding x[i]) is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i
        // Let m = right_ptr - 1 - i. This is the number of points available to be the second and third points (j and k)
        // if x[i] is the first point.
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = right_ptr - 1 - i;
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

