#include <numeric>
#include <functional>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end(), std::greater<int>());

        long long total_happiness = 0;
        int a_ptr_left = 0;
        int a_ptr_right = n - 1;

        // First, handle friends with w_i = 1.
        // These friends should get the largest remaining numbers.
        // Their happiness will be 2 * number.
        for (int i = 0; i < k; ++i) {
            if (w[i] == 1) {
                total_happiness += 2 * a[a_ptr_right];
                a_ptr_right--;
            } else {
                // Since w is sorted in descending order, all subsequent w_i will also be > 1.
                // We can break here and handle the rest.
                // Or, more robustly, just continue the loop.
                // The problem statement guarantees sum(w_i) = n, so we will use all numbers.
                // The logic below will handle w_i > 1 correctly.
            }
        }

        // Now, handle friends with w_i > 1.
        // These friends need one max and one min.
        // The largest remaining numbers should be assigned as max values.
        // The smallest remaining numbers should be assigned as min values.
        // The numbers in between are just fillers.
        // Since w is sorted descending, friends with larger w_i (and thus needing more fillers)
        // are processed first.
        for (int i = 0; i < k; ++i) {
            if (w[i] > 1) {
                // This friend gets the current largest available number as their max.
                total_happiness += a[a_ptr_right];
                a_ptr_right--;

                // This friend gets the current smallest available number as their min.
                total_happiness += a[a_ptr_left];
                a_ptr_left += (w[i] - 1); // Consume w_i - 1 smallest numbers as fillers
                                          // and one smallest number as the min.
                                          // So, a_ptr_left moves by w_i - 1 positions.
            }
        }

        std::cout << total_happiness << "\n";
    }
    return 0;
}

