// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x such that p % x == 0 and x % q != 0.
        // This means x cannot be a multiple of q.
        // The largest possible x is p. If p is a multiple of q, it's not valid.
        // We need to reduce p by removing some factors such that the new number is not a multiple of q.
        // To maximize x, we should remove as few factors as possible, or factors that are "small" relative to p.

        // Let q = q1^a1 * q2^a2 * ... * qk^ak be the prime factorization of q.
        // If x is a multiple of q, then x must be a multiple of q1^a1, q2^a2, ..., qk^ak.
        // To make x not a multiple of q, we need to make x not a multiple of at least one q_i^a_i.
        // More precisely, we need to make x not a multiple of q.
        // If x is a divisor of p, and x is a multiple of q, then p/x must be an integer.
        // We are looking for max x such that p % x == 0 and x % q != 0.
        // This is equivalent to finding max x such that p % x == 0 and (p/x) * q is not an integer. (This is wrong logic)

        // Correct logic:
        // We want to find the largest divisor x of p such that x is not divisible by q.
        // Since p is divisible by q, p itself is not a valid answer.
        // We need to find a divisor x of p that is not divisible by q.
        // Consider all prime factors of q. Let them be f1, f2, ..., fk.
        // For each prime factor f_i of q, we can try to divide p by f_i repeatedly until p is no longer divisible by q.
        // Example: p=12, q=6. Prime factors of q are 2, 3.
        // Try f=2: p=12. While (12 % 6 == 0) { 12 /= 2 -> 6. 6 % 6 == 0. 6 /= 2 -> 3. 3 % 6 != 0. Candidate x=3. }
        // Try f=3: p=12. While (12 % 6 == 0) { 12 /= 3 -> 4. 4 % 6 != 0. Candidate x=4. }
        // Max of (3, 4) is 4.

        std::vector<long long> prime_factors_of_q = get_prime_factors(q);
        long long max_x = 0;

        for (long long factor : prime_factors_of_q) {
            long long current_p = p;
            // Divide current_p by 'factor' until it's no longer divisible by q.
            // Or until current_p is no longer divisible by 'factor'.
            while (current_p % q == 0) {
                current_p /= factor;
            }
            // After the loop, current_p is a divisor of original p, and current_p is not divisible by q.
            // This current_p is a candidate for x.
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

