        int max_x = 100000;
        int min_y = -100000;
        int max_y = 100000;

        for (int i = 0; i < n; ++i) {
            int x, y, f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1: can move left (x-1, y)
            // If f1 is 0, robot cannot move left. So target X must be >= current x.
            // This means X must be >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }

            // f2: can move up (x, y+1)
            // If f2 is 0, robot cannot move up. So target Y must be <= current y.
            // This means Y must be <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }

            // f3: can move right (x+1, y)
            // If f3 is 0, robot cannot move right. So target X must be <= current x.
            // This means X must be <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }

            // f4: can move down (x, y-1)
            // If f4 is 0, robot cannot move down. So target Y must be >= current y.
            // This means Y must be >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
