#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_s(k, '?'); // Stores the determined characters for each position modulo k

    bool possible = true;

    // First pass: Propagate known characters and check for conflicts
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            int remainder = i % k;
            if (fixed_s[remainder] == '?') {
                fixed_s[remainder] = s[i];
            } else if (fixed_s[remainder] != s[i]) {
                possible = false; // Conflict detected
                break;
            }
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Second pass: Check if the first k characters can form a k-balanced string
    // and if the fixed_s pattern is consistent.
    int zeros = 0;
    int ones = 0;
    int questions = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_s[i] == '0') {
            zeros++;
        } else if (fixed_s[i] == '1') {
            ones++;
        } else { // fixed_s[i] == '?'
            questions++;
        }
    }

    // Check if it's possible to fill '?'s in the first k positions to get k/2 zeros and k/2 ones
    if (zeros > k / 2 || ones > k / 2) {
        possible = false;
    } else {
        // We need (k/2 - zeros) more zeros and (k/2 - ones) more ones.
        // The total number of '?'s must be exactly (k/2 - zeros) + (k/2 - ones).
        // This is equivalent to checking if (k/2 - zeros) <= questions and (k/2 - ones) <= questions
        // and (k/2 - zeros) + (k/2 - ones) == questions.
        // The last condition simplifies to k - (zeros + ones) == questions, which is always true by definition of questions.
        // So we only need to check if we have enough '?'s for the required 0s and 1s.
        // Since zeros + ones + questions = k, and we need k/2 zeros and k/2 ones,
        // the number of '?'s that must become '0' is (k/2 - zeros)
        // the number of '?'s that must become '1' is (k/2 - ones)
        // The sum of these must be <= questions.
        // (k/2 - zeros) + (k/2 - ones) = k - (zeros + ones) = questions.
        // So if zeros <= k/2 and ones <= k/2, it's always possible to fill the '?'s in the first k positions.
        // The only remaining check is that the total count of 0s and 1s in the first k positions
        // (after filling '?'s optimally) must be k/2 each.
        // This is guaranteed if zeros <= k/2 and ones <= k/2, because we can always fill the remaining '?'s
        // to reach exactly k/2 zeros and k/2 ones.
        // For example, if zeros < k/2, we can change (k/2 - zeros) '?'s to '0'.
        // If ones < k/2, we can change (k/2 - ones) '?'s to '1'.
        // The total '?'s used will be (k/2 - zeros) + (k/2 - ones) = k - (zeros + ones) = questions.
        // So it's always possible to make the first k positions k-balanced if zeros <= k/2 and ones <= k/2.
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

