        // The parity of the final coordinates (abs_n, abs_m) must match the parity of k.
        // Specifically, (abs_n % 2) == (k % 2) and (abs_m % 2) == (k % 2) is not strictly required.
        // What is required is that (abs_n + abs_m) % 2 == (k % 2) if we only consider moves that change parity.
        // However, we can always make two moves that cancel out parity changes (e.g., (0,0)->(1,0)->(0,0)).
        // The key is that each move changes the parity of (x+y) by 1 or -1.
        // So, (x_final + y_final) % 2 must be equal to (k % 2).
        // (abs_n + abs_m) % 2 must be equal to (k % 2).
        // This is equivalent to (abs_n % 2) == (k % 2) if and only if (abs_m % 2) == 0.
        // Or (abs_n % 2) != (k % 2) if and only if (abs_m % 2) == 1.
        // A simpler way: (k - abs_n) must be even if (abs_n - abs_m) is even.
        // (k - abs_n) must be odd if (abs_n - abs_m) is odd.
        // This is equivalent to (k - abs_n) % 2 == (abs_n - abs_m) % 2.
        // Which simplifies to k % 2 == abs_m % 2.
        // Or, (k - abs_n) % 2 == 0 if (abs_n % 2) == (abs_m % 2)
        // And (k - abs_n) % 2 == 1 if (abs_n % 2) != (abs_m % 2)

        // Let's re-evaluate the parity condition.
        // Each move changes the sum of coordinates (x+y) by -2, -1, 0, 1, or 2.
        // The parity of (x+y) changes by 0 or 1.
        // A diagonal move changes (x+y) by 2, 0, or -2. Parity of (x+y) does not change.
        // A non-diagonal move changes (x+y) by 1 or -1. Parity of (x+y) changes.
        // Let D be diagonal moves, ND be non-diagonal moves.
        // (abs_n + abs_m) % 2 must be equal to (ND % 2).
        // Since ND = k - D, (abs_n + abs_m) % 2 must be equal to (k - D) % 2.
        // This means (abs_n + abs_m) % 2 == (k % 2) if D is even.
        // And (abs_n + abs_m) % 2 != (k % 2) if D is odd.
        // This is not simple enough.

        // A simpler parity check:
        // The parity of the final coordinates (n, m) must match the parity of k.
        // If n and m have the same parity (n%2 == m%2), then (n+m) is even.
        // To reach (n,m) in k moves, (k - n) must be even and (k - m) must be even.
        // This means k must have the same parity as n (and m).
        // If n and m have different parities (n%2 != m%2), then (n+m) is odd.
        // To reach (n,m) in k moves, (k - n) must be odd and (k - m) must be odd.
        // This means k must have a different parity than n (and m).
        // This is incorrect. Consider (1,0) in 1 move. k=1, n=1, m=0. n%2 != m%2. k%2 == n%2.
        // Consider (2,0) in 2 moves. k=2, n=2, m=0. n%2 == m%2. k%2 == n%2.
        // Consider (1,1) in 1 move. k=1, n=1, m=1. n%2 == m%2. k%2 != n%2.
        // The correct parity condition is:
        // If (abs_n % 2) == (abs_m % 2):
        //   Then k must have the same parity as abs_n (and abs_m).
        //   i.e., (k % 2) == (abs_n % 2).
        // If (abs_n % 2) != (abs_m % 2):
        //   Then k must have a different parity than abs_n (and abs_m).
        //   i.e., (k % 2) != (abs_n % 2).
        // This can be combined: (k % 2) == ((abs_n + abs_m) % 2).
        // No, this is also wrong.
        // The correct parity condition is:
        // If (abs_n % 2) == (abs_m % 2):
        //   Then k must have the same parity as abs_n (and abs_m).
        //   (k % 2) == (abs_n % 2)
        // If (abs_n % 2) != (abs_m % 2):
        //   Then k must have a different parity than abs_n (and abs_m).
        //   (k % 2) != (abs_n % 2)
        // This is equivalent to: (k - abs_n) % 2 == 0 if (abs_n % 2) == (abs_m % 2)
        // And (k - abs_n) % 2 == 1 if (abs_n % 2) != (abs_m % 2)
        // This is equivalent to: (k - abs_n) % 2 == (abs_n - abs_m) % 2.
        // Which simplifies to: (k % 2) == (abs_m % 2).
        // Let's test this:
        // (2,2,3) -> abs_n=2, abs_m=2, k=3. (k%2) = 1, (abs_m%2) = 0. Not equal. Output 1.
        // My condition says it should be -1. Example output is 1. So my condition is wrong.

        // Let's re-think the parity.
        // Each move changes x by dx, y by dy.
        // (x_final, y_final) = (sum(dx_i), sum(dy_i))
        // k moves.
        // The minimum number of moves to reach (abs_n, abs_m) is abs_n (assuming abs_n >= abs_m).
        // This involves abs_m diagonal moves and (abs_n - abs_m) non-diagonal moves.
        // Total min_moves = abs_m + (abs_n - abs_m) = abs_n.
        // If k > abs_n, we have (k - abs_n) extra moves.
        // Each extra move must be paired with a "return" move to cancel out displacement.
        // E.g., (0,0) -> (1,0) -> (0,0). This uses 2 moves, changes (x,y) by (0,0).
        // (0,0) -> (1,1) -> (0,0). This uses 2 moves, changes (x,y) by (0,0).
        // Each pair of such moves adds 2 to k, but doesn't change (abs_n, abs_m).
        // So, (k - abs_n) must be an even number.
        // If (k - abs_n) is odd, it's impossible.
        // This is the standard Manhattan distance + parity argument for grid problems.
        // (k - abs_n) % 2 != 0 implies impossible.

        if ((k - abs_n) % 2 != 0) {
            std::cout << -1 << "\n";
            continue;
        }

        // If we reach here, it's possible.
        // We want to maximize diagonal moves.
        // We make abs_m diagonal moves to reach (abs_m, abs_m).
        // We make (abs_n - abs_m) non-diagonal moves to reach (abs_n, abs_m).
        // This uses abs_n moves.
        // We have (k - abs_n) remaining moves. This quantity is even.
        // We can use these remaining moves in pairs.
        // Each pair can be:
        // 1. (1,0) then (-1,0) - 0 diagonal moves.
        // 2. (1,1) then (-1,-1) - 2 diagonal moves.
        // 3. (1,0) then (0,1) then (-1,0) then (0,-1) - 0 diagonal moves. (4 moves)
        // To maximize diagonal moves, we should use pairs of (1,1) and (-1,-1).
        // Each such pair adds 2 to the total diagonal moves and 2 to k.
        // So, we can add (k - abs_n) / 2 * 2 = (k - abs_n) diagonal moves.
        // Total diagonal moves = abs_m (initial diagonal moves) + (k - abs_n) (from extra pairs).

        long long max_diag_moves = abs_m + (k - abs_n);

        std::cout << max_diag_moves << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> d(n);
    std::deque<int> q;

    // Calculate distances from left boundary
    for (int i = 0; i < n; ++i) {
        d[i] = 1; // Minimum 1 operation for any block
        if (i > 0) {
            d[i] = std::max(d[i], d[i - 1] + 1);
        }
        d[i] = std::min(d[i], h[i]); // A block cannot be destroyed more times than its height
        q.push_back(i);
    }

    // Calculate distances from right boundary and combine
    long long max_ops = 0;
    for (int i = n - 1; i >= 0; --i) {
        long long current_right_dist = 1;
        if (i < n - 1) {
            current_right_dist = std::max(current_right_dist, d[i + 1] + 1);
        }
        current_right_dist = std::min(current_right_dist, h[i]);

        d[i] = std::min(d[i], current_right_dist);
        max_ops = std::max(max_ops, d[i]);
    }

    std::cout << max_ops << std::endl;

    return 0;
}

