int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;

    for (int i = 0; i < n; ++i) {
        int start_block = std::max(0, current_val - k + 1);
        int end_block = current_val;

        for (int j = end_block; j >= start_block; --j) {
            if (j >= 1) { // Ensure we don't go below 1
                p[i++] = j;
            }
        }
        --i; // Adjust i because it was incremented one extra time in the inner loop
        current_val = start_block - 1;
        if (current_val < 1) break; // All numbers assigned
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total number of substrings
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // If m == n, there are no zeros, so no substrings of all zeros.
        // All substrings contain at least one '1'.
        if (num_zeros == 0) {
            std::cout << total_substrings << "\n";
            continue;
        }

        // To minimize substrings of all zeros, distribute num_zeros as evenly as possible
        // into m+1 blocks.
        // Let k be the number of zeros in each of the (m+1) blocks.
        // There will be (m+1) blocks.
        // num_zeros = q * (m+1) + r, where q = num_zeros / (m+1) and r = num_zeros % (m+1).
        // r blocks will have (q+1) zeros.
        // (m+1 - r) blocks will have q zeros.

        long long q = num_zeros / (m + 1);
        long long r = num_zeros % (m + 1);

        // Calculate the number of substrings of all zeros
        long long substrings_of_zeros = 0;

        // Blocks with (q+1) zeros
        substrings_of_zeros += r * (q + 1) * (q + 2) / 2;

        // Blocks with q zeros
        substrings_of_zeros += (m + 1 - r) * q * (q + 1) / 2;

        // The maximum value of f(s) is total_substrings - substrings_of_zeros
        std::cout << total_substrings - substrings_of_zeros << "\n";
    }
    return 0;
}

