        // No, this is wrong. We need -a[i] to be a multiple of (n-1).
        // The problem states "add a multiple of len".
        // So we need to add `k * (n-1)` to `a[i]` such that `a[i] + k * (n-1) = 0`.
        // This means `k * (n-1) = -a[i]`.
        // This implies `-a[i]` must be a multiple of `(n-1)`.
        // But `a[i]` is a multiple of `n`.
        // This is only possible if `a[i]` is a multiple of `n * (n-1)`.
        // This is not guaranteed.

        // Let's re-evaluate the strategy.
        // The standard approach for this type of problem:
        // 1. Make all elements except the last one zero.
        // 2. Make the last element zero.
        // This uses two operations. We need three.

        // A common trick for 3 operations:
        // Op 1: Segment [1, n-1]. Add `(n-1 - (a[i] % (n-1))) % (n-1)` to `a[i]`.
        // This makes `a[i]` divisible by `n-1` for `i` from `0` to `n-2`.
        // Op 2: Segment [n, n]. Add `(n - (a[n-1] % n)) % n` to `a[n-1]`.
        // This makes `a[n-1]` divisible by `n`.
        // Op 3: Segment [1, n]. Now all `a[i]` are divisible by `n-1` (for `i < n-1`) or `n` (for `i = n-1`).
        // This doesn't seem right.

        // Let's use the property that `n` and `n-1` are coprime.
        // For any `x`, we can find `k` such that `x + k * n` is a multiple of `n-1`.
        // `x + k * n = 0 (mod n-1)`
        // `x + k * 1 = 0 (mod n-1)`
        // `k = -x (mod n-1)`
        // So `k = (-x % (n-1) + (n-1)) % (n-1)`.
        // Then `x + k * n` will be a multiple of `n-1`.

        // Strategy:
        // 1. For elements a[0]...a[n-2]:
        //    Segment [1, n-1] (0-indexed: [0, n-2]), length `n-1`.
        //    For each a[i], add `k_i * (n-1)` such that `a[i] + k_i * (n-1)` becomes a multiple of `n`.
        //    `a[i] + k_i * (n-1) = 0 (mod n)`
        //    `a[i] + k_i * (-1) = 0 (mod n)`
        //    `k_i = a[i] (mod n)`
        //    So `k_i = (a[i] % n + n) % n`.
        //    Add `k_i * (n-1)` to `a[i]`.
        //    After this, `a[i]` for `i < n-1` are multiples of `n`.
        std::cout << 1 << " " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long remainder = (a[i] % n + n) % n;
            long long k_i = remainder; // k_i = a[i] (mod n)
            long long to_add = k_i * (n - 1);
            std::cout << to_add << (i == n - 2 ? "" : " ");
            a[i] += to_add;
        }
        std::cout << "\n";

        // 2. For element a[n-1]:
        //    Segment [n, n] (0-indexed: [n-1, n-1]), length `1`.
        //    Add `-a[n-1]` to `a[n-1]`.
        std::cout << n << " " << n << "\n";
        std::cout << -a[n - 1] << "\n";
        a[n - 1] = 0;

        // 3. For elements a[0]...a[n-2]:
        //    Segment [1, n-1] (0-indexed: [0, n-2]), length `n-1`.
        //    Now `a[i]` for `i < n-1` are multiples of `n`.
        //    We need to make them zero by adding a multiple of `n-1`.
        //    Since `a[i]` is a multiple of `n`, and `n` and `n-1` are coprime,
        //    `a[i]` must be a multiple of `n-1` if `a[i]` is a multiple of `n` and `a[i]` is to be made zero by adding a multiple of `n-1`.
        //    This is not true. `a[i]` is a multiple of `n`. We need to add `-a[i]`.
        //    We need `-a[i]` to be a multiple of `n-1`.
        //    This means `a[i]` must be a multiple of `n-1`.
        //    So `a[i]` must be a multiple of `lcm(n, n-1) = n * (n-1)`.
        //    The previous step made `a[i]` a multiple of `n`.
        //    So `a[i] = M * n` for some integer `M`.
        //    We need `M * n` to be a multiple of `n-1`.
        //    Since `n` and `n-1` are coprime, `M` must be a multiple of `n-1`.
        //    So `M = K * (n-1)` for some integer `K`.
        //    Then `a[i] = K * (n-1) * n`.
        //    So we need to add `-a[i]` which is `-(K * (n-1) * n)`.
        //    This is a multiple of `n-1`. So we can add it.
        std::cout << 1 << " " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            std::cout << -a[i] << (i == n - 2 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0-9), track its state if initial bit was 0, and if initial bit was 1.
    // val0[j] = final value of bit j if initial bit j was 0
    // val1[j] = final value of bit j if initial bit j was 1
    // Initialize: if initial bit was 0, it's 0. If initial bit was 1, it's 1.
    std::vector<int> val0(10); // All zeros
    std::vector<int> val1(10);
    std::iota(val1.begin(), val1.end(), 0); // val1[j] = j, but we need 1 for each bit.
                                            // Correct initialization: val1[j] = 1 for all j.
    std::fill(val1.begin(), val1.end(), 1);

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int j = 0; j < 10; ++j) {
            int bit_x = (x >> j) & 1;
            if (op_char == '&') {
                val0[j] = val0[j] & bit_x;
                val1[j] = val1[j] & bit_x;
            } else if (op_char == '|') {
                val0[j] = val0[j] | bit_x;
                val1[j] = val1[j] | bit_x;
            } else { // '^'
                val0[j] = val0[j] ^ bit_x;
                val1[j] = val1[j] ^ bit_x;
            }
        }
    }

    // Now, for each bit j, we know its final state based on its initial state.
    // There are 4 possibilities for (val0[j], val1[j]):
    // (0,0): bit j is always 0, regardless of input.
    // (0,1): bit j is the same as input bit j.
    // (1,0): bit j is the inverse of input bit j.
    // (1,1): bit j is always 1, regardless of input.

    // We want to find A, O, X such that:
    // (input & A | O) ^ X
    // For each bit j:
    // (x_j & A_j | O_j) ^ X_j == val0[j] if x_j=0
    // (x_j & A_j | O_j) ^ X_j == val1[j] if x_j=1

    // Let's determine A_j, O_j, X_j for each bit j.
    // For x_j = 0: (0 & A_j | O_j) ^ X_j = O_j ^ X_j = val0[j]
    // For x_j = 1: (1 & A_j | O_j) ^ X_j = (A_j | O_j) ^ X_j = val1[j]

    // We can choose A_j, O_j, X_j to simplify.
    // A common strategy is to use one AND, one OR, one XOR.
    // Let's try to construct the final A, O, X constants.
    int final_and_const = 0; // Represents A
    int final_or_const = 0;  // Represents O
    int final_xor_const = 0; // Represents X

    for (int j = 0; j < 10; ++j) {
        if (val0[j] == 0 && val1[j] == 0) {
            // Bit j is always 0.
            // O_j ^ X_j = 0  => O_j = X_j
            // (A_j | O_j) ^ X_j = 0
            // If O_j = X_j, then (A_j | O_j) ^ O_j = 0
            // This means A_j | O_j = O_j, which implies A_j = 0.
            // So, A_j=0, O_j=0, X_j=0 works. (0 & 0 | 0) ^ 0 = 0
            // Or A_j=0, O_j=1, X_j=1 works. (0 & 0 | 1) ^ 1 = 0
            // To minimize operations, we want to set bits in A, O, X only if necessary.
            // For (0,0): A_j=0, O_j=0, X_j=0.
            // (x_j & 0 | 0) ^ 0 = 0. Correct.
            // No bits set in final_and_const, final_or_const, final_xor_const for this j.
        } else if (val0[j] == 0 && val1[j] == 1) {
            // Bit j is the same as input bit j.
            // O_j ^ X_j = 0  => O_j = X_j
            // (A_j | O_j) ^ X_j = 1
            // If O_j = X_j, then (A_j | O_j) ^ O_j = 1
            // This means A_j | O_j = 1 ^ O_j.
            // If O_j = 0, then A_j | 0 = 1, so A_j = 1.
            // So, A_j=1, O_j=0, X_j=0 works.
            // (x_j & 1 | 0) ^ 0 = x_j. Correct.
            final_and_const |= (1 << j);
        } else if (val0[j] == 1 && val1[j] == 0) {
            // Bit j is the inverse of input bit j.
            // O_j ^ X_j = 1
            // (A_j | O_j) ^ X_j = 0
            // From O_j ^ X_j = 1, we know O_j != X_j.
            // If O_j = 0, then X_j = 1.
            // (A_j | 0) ^ 1 = 0 => A_j ^ 1 = 0 => A_j = 1.
            // So, A_j=1, O_j=0, X_j=1 works.
            // (x_j & 1 | 0) ^ 1 = x_j ^ 1. Correct.
            final_and_const |= (1 << j);
            final_xor_const |= (1 << j);
        } else { // val0[j] == 1 && val1[j] == 1
            // Bit j is always 1.
            // O_j ^ X_j = 1
            // (A_j | O_j) ^ X_j = 1
            // From O_j ^ X_j = 1, we know O_j != X_j.
            // If O_j = 1, then X_j = 0.
            // (A_j | 1) ^ 0 = 1 => (A_j | 1) = 1. This is always true.
            // So, A_j=0, O_j=1, X_j=0 works.
            // (x_j & 0 | 1) ^ 0 = 1. Correct.
            final_or_const |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If A is not all 1s, we need an AND operation.
                                   // If A is 1023, it means all bits are passed through for AND.
                                   // (x & 1023) is just x for numbers up to 1023.
                                   // So, if final_and_const is 1023, we can omit the '&' operation.
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) {
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) {
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

