#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> deletion_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> deletion_order[i];
        deletion_order[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false); // Initially no vertices are active

    // Process vertices in reverse deletion order (i.e., addition order)
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = deletion_order[k_idx]; // The vertex being added in this step

        active_vertices[k] = true; // Mark vertex k as active

        // Update shortest paths using vertex k as an intermediate node
        // This is the core Floyd-Warshall step
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue; // Only consider active vertices for i
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue; // Only consider active vertices for j

                // Path i -> k -> j
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using a sentinel for infinity
                    if (dist[i][j] == -1 || dist[i][k] + dist[k][j] < dist[i][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }

        // Also update paths involving k as source or destination
        // This is crucial because k itself is now active
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;

                // Path i -> k -> j (already handled above, but good to be explicit)
                if (dist[i][k] != -1 && dist[k][j] != -1) {
                    if (dist[i][j] == -1 || dist[i][k] + dist[k][j] < dist[i][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }

                // Path k -> i -> j (using k as source)
                if (dist[k][i] != -1 && dist[i][j] != -1) {
                    if (dist[k][j] == -1 || dist[k][i] + dist[i][j] < dist[k][j]) {
                        dist[k][j] = dist[k][i] + dist[i][j];
                    }
                }

                // Path i -> j -> k (using k as destination)
                if (dist[i][j] != -1 && dist[j][k] != -1) {
                    if (dist[i][k] == -1 || dist[i][j] + dist[j][k] < dist[i][k]) {
                        dist[i][k] = dist[i][j] + dist[j][k];
                    }
                }
            }
        }


        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (reverse of how they were calculated)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
