struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b_prime(n, std::numeric_limits<long long>::max());

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_max_val = ops[i].val;
            long long min_prefix_sum = 0;
            long long current_prefix_sum = 0;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                // Calculate the minimum prefix sum of d_k values for operations *before* current type 2 op
                // that affect index j.
                // This is equivalent to finding the minimum sum of d_k values that would be added to b_j
                // if we were to process operations up to this point.
                // The actual value of a_j at this point is b_j + sum(d_k for k < i affecting j).
                // We want b_j + sum(d_k for k < i affecting j) <= current_max_val.
                // So, b_j <= current_max_val - sum(d_k for k < i affecting j).
                // To find the tightest upper bound for b_j, we need to find the maximum possible value of
                // sum(d_k for k < i affecting j) for j in [l, r].
                // This is not what min_prefix_sum is doing.

                // Let's re-evaluate.
                // For a type 2 query (l, r, M), we know that for all j in [l, r], a_j <= M.
                // a_j = b_j + sum(d_k for k < i affecting j).
                // So, b_j + sum(d_k for k < i affecting j) <= M.
                // This implies b_j <= M - sum(d_k for k < i affecting j).
                // We need to find the tightest upper bound for b_j.
                // The tightest upper bound for b_j is M - sum(d_k for k < i affecting j).
                // We want to set b_j to this value, but we need to consider all type 2 queries.
                // So, b_j <= min(M_q - sum(d_k for k < q affecting j)) for all type 2 queries q where j is in [l_q, r_q].

                // The current approach is to find b_prime[j] = min(M_q - sum(d_k for k < q affecting j))
                // for all type 2 queries q where j is in [l_q, r_q].
                // The sum(d_k for k < q affecting j) is the `current_prefix_sum` at the time of query q.
                // So, b_prime[j] = min(b_prime[j], ops[i].val - current_prefix_sum).
                // This `current_prefix_sum` is the sum of `d` values from type 1 operations *before* the current type 2 operation `i`.

                // The `current_prefix_sum` is the sum of `d` values from type 1 operations that affect index `j`
                // and occurred *before* the current operation `i`.
                // This is what `min_prefix_sum` is trying to capture, but it's not quite right.
                // `min_prefix_sum` should be the sum of `d` values for operations *before* `i` that affect `j`.
                // This sum is specific to `j`.

                // Let's use a different variable name for clarity.
                // `sum_d_before_i_for_j` is the sum of `d_k` for `k < i` where `ops[k].type == 1` and `j` is in `[ops[k].l, ops[k].r]`.
                // We need to calculate this for each `j` in `[ops[i].l, ops[i].r]`.
                long long sum_d_before_i_for_j = 0;
                for (int k = 0; k < i; ++k) {
                    if (ops[k].type == 1 && j >= ops[k].l && j <= ops[k].r) {
                        sum_d_before_i_for_j += ops[k].val;
                    }
                }
                b_prime[j] = std::min(b_prime[j], ops[i].val - sum_d_before_i_for_j);
            }
        }
    }

    // If b_prime[j] is still max_long_long, it means no type 2 query constrained it.
    // We can set it to 0, as per problem statement |a_i| <= 10^9.
    // Setting it to 0 is a valid choice.
    for (int j = 0; j < n; ++j) {
        if (b_prime[j] == std::numeric_limits<long long>::max()) {
            b_prime[j] = 0;
        }
    }

    // Verify the solution
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_max_val = ops[i].val;
            long long max_found = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                long long sum_d_before_i_for_j = 0;
                for (int k = 0; k < i; ++k) {
                    if (ops[k].type == 1 && j >= ops[k].l && j <= ops[k].r) {
                        sum_d_before_i_for_j += ops[k].val;
                    }
                }
                max_found = std::max(max_found, b_prime[j] + sum_d_before_i_for_j);
            }
            if (max_found != current_max_val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b_prime[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
