int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long good_pairs = 0;

    // dp[i] will store the maximum length of a prefix s[0...i-1]
    // that does NOT contain a bad triplet.
    // This is equivalent to the minimum 'l' such that s[l-1...i-1] is good.
    // Or, more precisely, dp[i] is the smallest 'l' (1-indexed) such that
    // the substring s[l-1 ... i-1] contains a bad triplet.
    // If no bad triplet ends at or before i-1, dp[i] can be 1.
    // Let's redefine: `min_l_for_bad_suffix[i]` is the smallest `l` (1-indexed)
    // such that `s[l-1 ... i-1]` contains a bad triplet.
    // If no bad triplet ends at or before `i-1`, then `min_l_for_bad_suffix[i]` is `i+1`.
    // We want to count pairs (l, r) such that s[l-1 ... r-1] is good.
    // For a fixed `r`, we need to find how many `l` (1 <= l <= r) make s[l-1 ... r-1] good.
    // Let `last_bad_start[r]` be the smallest `l` such that `s[l-1 ... r-1]` contains a bad triplet.
    // If no such `l` exists, `last_bad_start[r]` is `r+1`.
    // Then for a fixed `r`, the number of good `l`'s is `last_bad_start[r] - 1`.
    // The total number of good pairs is sum(last_bad_start[r] - 1) for r from 1 to n.

    // Initialize `last_bad_start[0]` to 1 (meaning s[0...-1] is good, or no bad triplet ends at index -1)
    // `last_bad_start[i]` will store the minimum `l` (1-indexed) such that `s[l-1 ... i-1]` contains a bad triplet.
    // If no such `l` exists, it's `i+1`.
    std::vector<int> last_bad_start(n + 1);
    last_bad_start[0] = 1; // Base case: before any characters, the "start" of a bad segment is 1.

    for (int r_idx = 0; r_idx < n; ++r_idx) { // r_idx is 0-indexed, corresponds to r-1
        int current_min_l = last_bad_start[r_idx]; // Inherit from previous r

        // Check for bad triplets ending at r_idx
        // k=1: x = r_idx - 2. Indices: r_idx-2, r_idx-1, r_idx
        if (r_idx >= 2 && s[r_idx] == s[r_idx - 1] && s[r_idx] == s[r_idx - 2]) {
            current_min_l = std::max(current_min_l, r_idx - 2 + 1); // r_idx-2 is 0-indexed x, so l is x+1
        }
        // k=2: x = r_idx - 4. Indices: r_idx-4, r_idx-2, r_idx
        if (r_idx >= 4 && s[r_idx] == s[r_idx - 2] && s[r_idx] == s[r_idx - 4]) {
            current_min_l = std::max(current_min_l, r_idx - 4 + 1);
        }
        // k=3: x = r_idx - 6. Indices: r_idx-6, r_idx-3, r_idx
        if (r_idx >= 6 && s[r_idx] == s[r_idx - 3] && s[r_idx] == s[r_idx - 6]) {
            current_min_l = std::max(current_min_l, r_idx - 6 + 1);
        }

        last_bad_start[r_idx + 1] = current_min_l;
        good_pairs += (long long)current_min_l - 1;
    }

    std::cout << total_pairs - good_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could accumulate many a_x values.
// For example, if x always moves to n and then to 1, and a_x is large.
// Max y could be roughly n * max(a_i) * (number of steps).
// If it terminates quickly, say 2 steps, y could be 2 * 10^9.
// If it takes many steps, it could exceed 2^31-1.
// A path of length N could sum up to N * 2 * 10^9.
// N can be up to 2*10^5. So 2*10^5 * 2 * 10^9 = 4 * 10^14, which fits in long long.

// Using long long for x is not strictly necessary as x is an index (up to n),
// but it's safer to keep it consistent with y if intermediate calculations
// involving a[x] could temporarily exceed int max before being clamped by n.
// However, x is always an index, so it will be compared to n.
// The problem states x <= 0 or x > n, so x itself doesn't need to be long long.
// But the values a[x] are large, so when adding/subtracting a[x] from x,
// the intermediate value of x could exceed int max before being checked against n.
// For example, if x=1 and a[x]=10^9, then x+a[x] would be 1+10^9. This fits in int.
// If x=1 and a[x]=2*10^9, then x+a[x] would be 1+2*10^9. This fits in int.
// So int for x is fine.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_input stores a_2, a_3, ..., a_n
    // We will use 1-based indexing for the actual 'a' array in simulation.
    // So a_sim[1] will be the current 'i' value.
    // a_sim[k] for k >= 2 will be a_input[k-2].
    std::vector<long long> a_input(n - 1);
    for (int k = 0; k < n - 1; ++k) {
        std::cin >> a_input[k];
    }

    // dp[pos][parity] stores the result for starting at 'pos' with 'parity'
    // parity 0: next step is x+a[x], y+a[x]
    // parity 1: next step is x-a[x], y+a[x]
    // The problem states "first step 2, then step 3", so the initial state
    // for any run is effectively 'parity 0' (step 2).
    // However, the problem defines the sequence of steps as "step 2, step 3, step 2, step 3..."
    // This means after step 2, the next step is step 3. After step 3, the next step is step 2.
    // So, if we are at position `p` and the *next* operation is `+a[p]`, we are in state `(p, 0)`.
    // If we are at position `p` and the *next* operation is `-a[p]`, we are in state `(p, 1)`.
    // The initial state for each run is `x=1`, `y=0`, and the first operation is `x+a[x], y+a[x]`.
    // So, we are effectively starting at `(1, 0)`.

    // dp[pos][0] stores {final_x_offset, final_y_offset} if starting at pos, next is +a[pos]
    // dp[pos][1] stores {final_x_offset, final_y_offset} if starting at pos, next is -a[pos]
    // We need to store the *change* in x and y from the current state to the termination state.
    // This is because the initial a[1] changes for each run.
    // The actual value of a[pos] depends on the current 'i' for a[1].
    // So, we can't directly store the final y.
    // We can store the final y if a[1] is fixed, but it's not.

    // Let's re-evaluate the DP state.
    // The values a_2, ..., a_n are fixed. Only a_1 changes.
    // If x is not 1, then a[x] is fixed.
    // This suggests that we can precompute results for x > 1.
    // For x = 1, the value a[1] is 'i'.

    // dp[pos][parity] will store {delta_x, delta_y}
    // delta_x: the change in x from 'pos' to the termination point.
    // delta_y: the change in y from 0 to the termination point, assuming y was 0 at 'pos'.
    // This is tricky because y accumulates.

    // Let's define dp[pos][parity] as the pair {final_x, final_y} if we start at 'pos' with 'y=0'
    // and the next operation is determined by 'parity'.
    // Parity 0: next is x+a[x], y+a[x]
    // Parity 1: next is x-a[x], y+a[x]

    // We need to handle cycles. Use a visited array.
    // visited[pos][parity] = 0: not visited
    // visited[pos][parity] = 1: currently visiting (in recursion stack) -> cycle
    // visited[pos][parity] = 2: visited and computed

    std::vector<std::vector<std::pair<long long, long long>>> dp(n + 1, std::vector<std::pair<long long, long long>>(2));
    std::vector<std::vector<int>> visited(n + 1, std::vector<int>(2, 0));

    // The actual 'a' array for simulation. a_sim[0] is unused.
    // a_sim[1] will be 'i' for each run.
    // a_sim[k] for k >= 2 will be a_input[k-2].
    std::vector<long long> a_sim(n + 1);
    for (int k = 2; k <= n; ++k) {
        a_sim[k] = a_input[k - 2];
    }

    // Recursive function to compute dp values
    // current_a1 is the value of a[1] for the current run.
    // This function will only be called for pos > 1, where a[pos] is fixed.
    // For pos = 1, we handle it separately for each 'i'.
    std::pair<long long, long long> solve(int pos, int parity) {
        if (pos <= 0 || pos > n) {
            return {pos, 0}; // Terminated. x is 'pos', y accumulated 0 more.
        }

        if (visited[pos][parity] == 1) { // Cycle detected
            return {0, -1}; // Special value to indicate cycle
        }
        if (visited[pos][parity] == 2) { // Already computed
            return dp[pos][parity];
        }

        visited[pos][parity] = 1; // Mark as visiting

        long long current_val_a_x = a_sim[pos];
        long long next_x;
        long long current_y_add = current_val_a_x;
        int next_parity;

        if (parity == 0) { // Next step is x+a[x], y+a[x]
            next_x = pos + current_val_a_x;
            next_parity = 1; // After step 2, next is step 3
        } else { // Parity == 1, next step is x-a[x], y+a[x]
            next_x = pos - current_val_a_x;
            next_parity = 0; // After step 3, next is step 2
        }

        std::pair<long long, long long> res;
        if (next_x <= 0 || next_x > n) {
            res = {next_x, current_y_add}; // Terminated. x is next_x, y accumulated current_y_add.
        } else {
            std::pair<long long, long long> next_res = solve(static_cast<int>(next_x), next_parity);
            if (next_res.second == -1) { // Cycle detected in subproblem
                res = {0, -1};
            } else {
                res = {next_res.first, current_y_add + next_res.second};
            }
        }

        visited[pos][parity] = 2; // Mark as computed
        dp[pos][parity] = res;
        return res;
    }

    // Precompute for pos > 1
    for (int pos = 2; pos <= n; ++pos) {
        solve(pos, 0); // Compute for both parities implicitly
        solve(pos, 1);
    }

    // Now, for each i from 1 to n-1
    for (int i = 1; i < n; ++i) {
        a_sim[1] = i; // Set a[1] for the current run

        long long current_x = 1;
        long long current_y = 0;
        int current_parity = 0; // Always starts with step 2 (x+a[x])

        // Simulate until termination or cycle
        // We need to detect cycles involving x=1.
        // Since a[1] changes, we can't use the global 'visited' for x=1.
        // We can use a local visited for the current run, or just simulate.
        // Given N is up to 2*10^5, a direct simulation for each 'i' might be too slow
        // if paths are long. N * N = 4*10^10 operations.
        // The DP approach is for fixed a[x].
        // For x=1, a[1] is 'i'.
        // If x becomes > 1, we can use the precomputed DP values.

        // Let's simulate for each 'i', but use DP for x > 1.
        // This means the simulation path will be:
        // (1, 0) -> (1 + a[1], 1) -> (1 + a[1] - a[1+a[1]], 0) -> ...
        // If x ever becomes > 1, we can jump using DP.

        // To detect cycles involving x=1, we need to keep track of states (x, parity)
        // encountered *within the current run*.
        // A simple way is to use a vector to store the path.
        std::vector<std::pair<long long, int>> path_states;
        bool cycle_detected_in_run = false;

        while (true) {
            if (current_x <= 0 || current_x > n) {
                break; // Terminated
            }

            // Check for cycle in current run
            // This is only relevant if current_x == 1, as other states are handled by DP.
            if (current_x == 1) {
                for (const auto& state : path_states) {
                    if (state.first == current_x && state.second == current_parity) {
                        cycle_detected_in_run = true;
                        break;
                    }
                }
                if (cycle_detected_in_run) {
                    current_y = -1;
                    break;
                }
                path_states.push_back({current_x, current_parity});
            }

            long long val_a_x;
            if (current_x == 1) {
                val_a_x = a_sim[1]; // Use 'i'
            } else {
                val_a_x = a_sim[static_cast<int>(current_x)]; // Use precomputed a_sim
            }

            long long next_x_val;
            long long y_add_val = val_a_x;
            int next_parity_val;

            if (current_parity == 0) { // Step 2: x+a[x], y+a[x]
                next_x_val = current_x + val_a_x;
                next_parity_val = 1;
            } else { // Step 3: x-a[x], y+a[x]
                next_x_val = current_x - val_a_x;
                next_parity_val = 0;
            }

            current_y += y_add_val;

            if (next_x_val <= 0 || next_x_val > n) {
                current_x = next_x_val; // Update x to reflect termination state
                break; // Terminated
            }

            // If next_x_val is 1, we continue simulation.
            // If next_x_val > 1, we can use DP.
            if (next_x_val == 1) {
                current_x = next_x_val;
                current_parity = next_parity_val;
            } else {
                // Use DP for x > 1
                std::pair<long long, long long> dp_result = dp[static_cast<int>(next_x_val)][next_parity_val];
                if (dp_result.second == -1) { // Cycle detected by DP
                    current_y = -1;
                    break;
                } else {
                    current_x = dp_result.first;
                    current_y += dp_result.second;
                    break; // DP result means termination
                }
            }
        }
        std::cout << current_y << "\n";
    }

    return 0;
}

#include <iostream>
