int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        }
    }

    // To form '1' (from "one"): requires one 'o', one 'n', one 'e'
    // The number of '1's is limited by the minimum of these counts.
    // Since 'o' and 'e' are also used by 'zero', we prioritize '1's first
    // because we want the maximum possible binary number.
    // The problem statement guarantees that a valid rearrangement is possible.
    // This means the total counts of 'o' and 'e' will be sufficient for
    // the '1's and '0's that can be formed.

    int num_ones = count_n; // 'n' is unique to "one"

    // After forming 'num_ones' "one"s, we use up 'num_ones' 'o's and 'num_ones' 'e's.
    // The remaining 'o's and 'e's are available for "zero"s.
    // 'z' and 'r' are unique to "zero".
    // To form '0' (from "zero"): requires one 'z', one 'e', one 'r', one 'o'

    int num_zeros = count_z; // 'z' is unique to "zero"

    // Print all '1's first
    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    // Then print all '0's
    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

