int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks needed for k torches:
        // k sticks for crafting + k * y sticks for buying k coal
        long long total_sticks_required = k * y + k;

        // Number of trades to get enough sticks:
        // We start with 1 stick. Each trade (1 stick for x sticks) gives x-1 net sticks.
        // We need to reach total_sticks_required sticks.
        // We have 1 stick, so we need to gain (total_sticks_required - 1) more sticks.
        // Each trade gives (x - 1) sticks.
        // Number of stick-gaining trades = ceil((total_sticks_required - 1) / (x - 1))
        long long stick_gain_trades = (total_sticks_required - 1 + (x - 1) - 1) / (x - 1);

        // Total trades = stick_gain_trades + trades for buying coal
        // Trades for buying coal = k (since 1 coal costs 1 trade)
        long long total_trades = stick_gain_trades + k;

        std::cout << total_trades << std::endl;
    }
    return 0;
}

