int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_consecutive_L = 0;
        int current_consecutive_L = 0;
        // Add an implicit 'R' at the beginning (cell 0)
        // and an implicit 'R' at the end (cell n+1)
        // This simplifies finding gaps between 'R's.
        // The frog is at cell 0, which acts like an 'R' cell allowing jumps to the right.
        // The target cell n+1 also acts like an 'R' cell, as we need to reach it.
        // So we are looking for the maximum distance between any two consecutive 'R's,
        // including the implicit 'R' at 0 and the implicit 'R' at n+1.

        // The positions of 'R's are 1-indexed based on the string.
        // Cell 0 is an 'R' position.
        // Cell n+1 is an 'R' position.

        // Let's track the last 'R' position.
        // Initially, the frog is at cell 0, which is effectively an 'R' position.
        int last_R_pos = 0; 
        int n = s.length();

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is (i+1)
                // The distance from the last 'R' to this 'R' is (i+1) - last_R_pos
                max_consecutive_L = std::max(max_consecutive_L, (i + 1) - last_R_pos);
                last_R_pos = i + 1;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' found
        // to the target cell n+1.
        max_consecutive_L = std::max(max_consecutive_L, (n + 1) - last_R_pos);

        std::cout << max_consecutive_L << "\n";
    }
    return 0;
}

