#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is 0 (which means all a[i][j] for j!=i were 0)
    // This would imply p[i] should be n, as 1..n are used.
    // This happens if p[i] is the largest value in the permutation.
    // If max_val_in_row is 0, it means all other p[j] are greater than p[i].
    // In this case, p[i] must be n.
    // More generally, if max_val_in_row is 0, it means p[i] is the largest element.
    // The largest element in a permutation 1..n is n.
    // So, if p[i] is 0, it should be n.
    // This logic is equivalent to finding the maximum value among all a[i][j]
    // and if p[i] is less than that maximum, it means p[i] is not the largest.
    // If p[i] is 0, it means it's the largest.
    // The problem statement guarantees a solution exists.
    // The maximum value in the entire matrix (excluding 0s on diagonal)
    // will be n-1 if n is the largest element.
    // If n is one of the p_i, then for some j, a[i][j] = min(p_i, p_j).
    // If p_i is n, then a[i][j] = p_j.
    // The maximum value in the matrix will be n-1.
    // If p_i is n, then max_val_in_row for that i will be n-1.
    // If p_i is not n, then max_val_in_row for that i will be p_i.
    // So, if p[i] is 0, it means it should be n.
    // This happens if all a[i][j] for j!=i are 0. This is not possible for n >= 2.
    // The smallest possible value for max_val_in_row is 1 (if n >= 2).
    // So p[i] will always be at least 1.
    // The only case where p[i] might be incorrect is if p[i] is the largest element, n.
    // In that case, for all j != i, a[i][j] = min(n, p[j]) = p[j].
    // So max_val_in_row for that i would be max(p[j] for j!=i), which is n-1.
    // So if p[i] is n, our current logic sets p[i] to n-1.
    // We need to find the element that should be n.
    // The element that should be n is the one whose calculated p[i] is n-1,
    // AND all other p[j] are less than n-1.
    // Or, more simply, the element that should be n is the one whose row
    // contains the maximum possible value (n-1).
    // If there are multiple such elements, it means they are all n.
    // But a permutation has unique elements.
    // The problem guarantees a solution.
    // The maximum value in the entire matrix (excluding diagonal 0s) is n-1.
    // If p_k = n, then for all j != k, a[k][j] = p_j.
    // So max_{j!=k} a[k][j] = max_{j!=k} p_j = n-1.
    // For any other p_i != n, max_{j!=i} a[i][j] = max(p_i, max_{j!=i, p_j < p_i} p_j, max_{j!=i, p_j > p_i} p_i)
    // This simplifies to p_i.
    // So, the element p_k that is n will have max_val_in_row = n-1.
    // All other p_i will have max_val_in_row = p_i.
    // So, we need to find the index `k` such that `p[k]` (as calculated) is `n-1`.
    // And then set `p[k]` to `n`.
    // If there are multiple such indices, it means there's an issue with this logic.
    // But the problem guarantees a solution.
    // The values 1 to n-1 are present in the calculated p array.
    // The value n is missing. The value n-1 appears twice.
    // One of the n-1s should be n.
    // The one that should be n is the one whose original value was n.
    // The one whose original value was n will have its max_val_in_row as n-1.
    // All other values p_i (where p_i != n) will have max_val_in_row = p_i.
    // So, the calculated `p` array will contain `1, 2, ..., n-2, n-1, n-1`.
    // We need to change one of the `n-1`s to `n`.
    // Which one? The one that corresponds to the original `n`.
    // The original `n` is the one whose row contains `n-1`.
    // All other rows `i` (where `p_i != n`) will have `max_val_in_row = p_i`.
    // So, the `p` array we constructed will have `n-1` at the index where the original permutation had `n`.
    // And `n-1` at the index where the original permutation had `n-1`.
    // We need to find the index `k` such that `p[k]` (as calculated) is `n-1` AND `p[k]` is the largest value in the permutation.
    // This is not quite right.
    // The values in `p` (as calculated) will be `1, 2, ..., n-2, n-1` (from the `n-1` element) and `n-1` (from the `n` element).
    // So, the set of values in `p` will be `{1, 2, ..., n-2, n-1, n-1}`.
    // We need to change one of the `n-1`s to `n`.
    // The one that should be `n` is the one whose row `i` has `max_{j!=i} a[i][j] = n-1`.
    // And for this `i`, `p_i` (original) was `n`.
    // For the `i'` where `p_{i'}` (original) was `n-1`, `max_{j!=i'} a[i'][j]` would also be `n-1`.
    // This is the ambiguity.
    // The problem states "reconstruct ANY permutation".
    // So, we can just find the maximum value in the `p` array we constructed.
    // If it's `n-1`, then one of the `n-1`s should be `n`.
    // We can just pick any `n-1` and change it to `n`.
    // Let's find the maximum value in the constructed `p`.
    int max_in_constructed_p = 0;
    for (int val : p) {
        if (val > max_in_constructed_p) {
            max_in_constructed_p = val;
        }
    }

    if (max_in_constructed_p < n) { // This means n is missing, and n-1 is present twice.
        // Find the first occurrence of max_in_constructed_p (which is n-1)
        // and change it to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == max_in_constructed_p) {
                p[i] = n;
                break; // Only change one instance
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

