#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i is a new value.
                // But as a safety check for permutation validity.
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some number less than q_i
            // and not yet used. We need to pick the smallest available number
            // that satisfies this condition.
            // The largest possible value for p_i is q_i - 1.
            // The smallest possible value for p_i is 1.
            // We need to find an unused number x such that 1 <= x < q_i.
            // To maximize chances of finding a solution, we should pick the smallest available number.
            // This is because larger numbers might be needed later for other q_j == q_{j-1} cases.
            // Or, if we pick a large number, it might conflict with a future q_k > q_{k-1} where q_k is that large number.
            // The problem asks for *any* suitable permutation.
            // Let's try to fill with the smallest available number.
            // The numbers 1 to n are available.
            // We need to find the smallest number 'val' such that 'val' is not in used_numbers.
            // And 'val' must be less than q_i.

            // Find the smallest unused number
            int current_val = 1;
            while (used_numbers.count(current_val)) {
                current_val++;
            }

            if (current_val >= q[i]) {
                // If the smallest available number is already >= q_i,
                // then we cannot find a p_i such that p_i < q_i.
                possible = false;
                break;
            }
            p[i] = current_val;
            used_numbers.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

