        long long sum_of_costs = 0;

        while (true) {
            // Calculate the cost for the next staircase in the sequence (1, 3, 7, 15, ...)
            // This is 2^k - 1 stairs, which costs (2^k - 1) * (2^k) / 2 cells.
            // The sequence of costs is 1, 6, 28, 120, ...
            // current_cost represents the cost of a staircase with (2^k - 1) stairs.
            // The next staircase in the sequence will have (2 * (2^k - 1) + 1) = (2^(k+1) - 1) stairs.
            // Its cost will be (2^(k+1) - 1) * (2^(k+1)) / 2.
            // This can be derived from the previous cost:
            // Let N_k = 2^k - 1. Cost_k = N_k * (N_k + 1) / 2 = (2^k - 1) * 2^k / 2.
            // N_{k+1} = 2^(k+1) - 1 = 2 * N_k + 1.
            // Cost_{k+1} = N_{k+1} * (N_{k+1} + 1) / 2 = (2 * N_k + 1) * (2 * N_k + 2) / 2
            // = (2 * N_k + 1) * (N_k + 1)
            // = 2 * N_k * (N_k + 1) + (N_k + 1)
            // = 4 * (N_k * (N_k + 1) / 2) + (N_k + 1)
            // = 4 * Cost_k + (N_k + 1)
            // = 4 * Cost_k + 2^k
            // Since N_k = 2^k - 1, then 2^k = N_k + 1.
            // So, the next cost is 4 * current_cost + (N_k + 1).
            // N_k + 1 is the number of cells in the first column of the staircase with N_k stairs, which is 2^k.
            // The number of stairs for the current `current_cost` is `n_stairs = (sqrt(8 * current_cost + 1) - 1) / 2`.
            // The next number of stairs is `2 * n_stairs + 1`.
            // The cost for `n` stairs is `n * (n + 1) / 2`.
            // If current_cost is for `n` stairs, then `n = (2^k - 1)`.
            // The next `n'` is `2 * n + 1`.
            // The next cost is `n' * (n' + 1) / 2`.
            // `n + 1` is `2^k`.
            // `n' = 2 * (2^k - 1) + 1 = 2^(k+1) - 1`.
            // `n' + 1 = 2^(k+1)`.
            // Next cost = `(2^(k+1) - 1) * 2^(k+1) / 2`.
            // This is `(2 * n + 1) * (2 * n + 2) / 2 = (2n+1)(n+1)`.
            // We can update `current_cost` directly:
            // `current_cost` is `n * (n+1) / 2`.
            // `n` is `2^k - 1`.
            // `n+1` is `2^k`.
            // The next `n'` is `2^(k+1) - 1`.
            // The next `n'+1` is `2^(k+1)`.
            // So, `next_cost = (2^(k+1) - 1) * 2^(k+1) / 2`.
            // This is `(2 * (2^k - 1) + 1) * (2 * 2^k) / 2 = (2 * n + 1) * (n + 1)`.
            // `current_cost` is `n * (n+1) / 2`.
            // `n+1` is `2^k`.
            // `next_cost = (2 * n + 1) * (n + 1)`.
            // `next_cost = 2 * n * (n + 1) + (n + 1)`.
            // `next_cost = 4 * (n * (n + 1) / 2) + (n + 1)`.
            // `next_cost = 4 * current_cost + (n + 1)`.
            // `n+1` is `2^k`.
            // The sequence of `n+1` values is 2, 4, 8, 16, ...
            // Let `power_of_2 = n+1`. Initially `power_of_2 = 2`.
            // `next_cost = 4 * current_cost + power_of_2`.
            // `power_of_2` then becomes `2 * power_of_2`.

            if (sum_of_costs + current_cost <= x) {
                sum_of_costs += current_cost;
                count++;
                // Calculate the next cost
                // current_cost is for n stairs. n = 2^k - 1.
                // n+1 = 2^k.
                // Next staircase has n' = 2n+1 stairs.
                // Next cost = n'(n'+1)/2 = (2n+1)(2n+2)/2 = (2n+1)(n+1).
                // current_cost = n(n+1)/2.
                // So, next_cost = (2n+1)(n+1) = 2n(n+1) + (n+1) = 4 * (n(n+1)/2) + (n+1)
                // next_cost = 4 * current_cost + (n+1).
                // (n+1) is the `power_of_2` from the previous step.
                // For the first staircase (n=1), current_cost=1. n+1=2.
                // Next cost = 4*1 + 2 = 6. (This is for n=3).
                // For n=3, current_cost=6. n+1=4.
                // Next cost = 4*6 + 4 = 28. (This is for n=7).
                // For n=7, current_cost=28. n+1=8.
                // Next cost = 4*28 + 8 = 112 + 8 = 120. (This is for n=15).
                // This pattern holds.
                long long n_plus_1 = (current_cost == 1) ? 2 : (current_cost / ((current_cost / 4) + 1)); // This is a bit tricky to get n+1 from current_cost.
                                                                                                          // A simpler way is to keep track of n.
                                                                                                          // Or, just use the formula for the next cost directly.
                // The number of stairs for current_cost is `n`.
                // `n * (n + 1) / 2 = current_cost`.
                // `n^2 + n - 2 * current_cost = 0`.
                // `n = (-1 + sqrt(1 + 8 * current_cost)) / 2`.
                // `n_plus_1 = (1 + sqrt(1 + 8 * current_cost)) / 2`.
                long long n_plus_1_val = (1 + static_cast<long long>(std::sqrt(1 + 8 * current_cost))) / 2;
                current_cost = 4 * current_cost + n_plus_1_val;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

