void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This is the start of the potential "valley" or "peak" structure.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // From this point `i`, find the rightmost index `j` such that a[j...i-1] is non-increasing.
    // This means a[j] >= a[j+1] >= ... >= a[i-1].
    // The combined suffix a[j...n-1] would be non-increasing then non-decreasing.
    int j = i;
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now a[j...i-1] is non-increasing.
    // The suffix a[j...n-1] is of the form [non-increasing part] [non-decreasing part].
    // This is the structure required for a "good" array.

    std::cout << j << std::endl;
}

