#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[k] stores the 0-indexed position of k in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, min_idx and max_idx are already set to pos[1].
        // The segment [pos[1], pos[1]] contains only 1. Length is 1.
        // min_val in segment is 1, max_val is 1.
        // So m=1 is always beautiful.

        // For m > 1, we expand the current segment to include m.
        // The current segment [min_idx, max_idx] contains numbers 1 to m-1.
        // To include m, we need to extend the segment to include pos[m].
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // A number m is beautiful if there exists a subsegment [l, r]
        // such that it contains exactly numbers 1 to m.
        // This implies:
        // 1. The length of the subsegment (r - l + 1) must be m.
        // 2. The minimum value in the subsegment must be 1.
        // 3. The maximum value in the subsegment must be m.
        //
        // The segment [min_idx, max_idx] by construction contains all numbers
        // from 1 to m. Its minimum value is 1 and maximum value is m.
        // If its length (max_idx - min_idx + 1) is exactly m,
        // then it must be a permutation of 1 to m.
        // (Because it contains m distinct numbers, all between 1 and m,
        // and its length is m, so it must contain exactly 1 to m).
        if (max_idx - min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

