#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int last_diff_01 = -1; // last index i where a[i]='0' and b[i]='1'
    int last_diff_10 = -1; // last index i where a[i]='1' and b[i]='0'

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] = '0', b[i] = '1'
                if (last_diff_10 != -1) { // Found a '1'->'0' mismatch before
                    // We can swap a[last_diff_10] and a[i]
                    // a[last_diff_10] was '1', b[last_diff_10] was '0'
                    // a[i] is '0', b[i] is '1'
                    // After swap: a[last_diff_10] becomes '0' (matches b[last_diff_10])
                    //              a[i] becomes '1' (matches b[i])
                    // Cost is (i - last_diff_10)
                    cost += (i - last_diff_10);
                    last_diff_10 = -1; // This '1'->'0' mismatch is resolved
                } else {
                    // Cannot resolve with a swap yet, mark this '0'->'1' mismatch
                    last_diff_01 = i;
                }
            } else { // a[i] = '1', b[i] = '0'
                if (last_diff_01 != -1) { // Found a '0'->'1' mismatch before
                    // We can swap a[last_diff_01] and a[i]
                    // a[last_diff_01] was '0', b[last_diff_01] was '1'
                    // a[i] is '1', b[i] is '0'
                    // After swap: a[last_diff_01] becomes '1' (matches b[last_diff_01])
                    //              a[i] becomes '0' (matches b[i])
                    // Cost is (i - last_diff_01)
                    cost += (i - last_diff_01);
                    last_diff_01 = -1; // This '0'->'1' mismatch is resolved
                } else {
                    // Cannot resolve with a swap yet, mark this '1'->'0' mismatch
                    last_diff_10 = i;
                }
            }
        }
    }

    // Any remaining mismatches must be resolved by flips
    // Each remaining 'last_diff_01' or 'last_diff_10' represents one unresolved mismatch
    // that needs a flip.
    if (last_diff_01 != -1) {
        cost++;
    }
    if (last_diff_10 != -1) {
        cost++;
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<std::vector<int>> a(n, std::vector<int>(m));
    std::vector<bool> row_taken(n, false);
    std::vector<bool> col_taken(m, false);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            std::cin >> a[i][j];
            if (a[i][j] == 1) {
                row_taken[i] = true;
                col_taken[j] = true;
            }
        }
    }

    int available_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_taken[i]) {
            available_rows++;
        }
    }

    int available_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_taken[j]) {
            available_cols++;
        }
    }

    int moves_possible = std::min(available_rows, available_cols);

    if (moves_possible % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[i] <= d

    for (int i = 0; i < n; ++i) {
        // Advance right_ptr until x[right_ptr] - x[i] > d or right_ptr reaches end
        // The condition is x[right_ptr] <= x[i] + d
        while (right_ptr < n && x[right_ptr] <= x[i] + d) {
            right_ptr++;
        }
        // At this point, all points from x[i] to x[right_ptr-1] satisfy the condition with x[i]
        // We need to choose two more points from the range (x[i+1], ..., x[right_ptr-1])
        // The number of available points in this range is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i

        long long num_available_points = right_ptr - 1 - i;

        // We need to choose 2 points from num_available_points.
        // This is C(num_available_points, 2) = num_available_points * (num_available_points - 1) / 2
        if (num_available_points >= 2) {
            count += num_available_points * (num_available_points - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2;

    // The median element a[mid_idx] must become s.
    // Add the cost for this element.
    operations += std::abs(a[mid_idx] - s);

    // Elements to the left of the median (a[0]...a[mid_idx-1])
    // must be <= s. If any a[i] < s, it's fine.
    // If any a[i] > s, it must be decreased to s.
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of the median (a[mid_idx+1]...a[n-1])
    // must be >= s. If any a[i] > s, it's fine.
    // If any a[i] < s, it must be increased to s.
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

