// Function to check if a subarray is a permutation of length 'len'
// The subarray is defined by a pointer 'start' and its 'len'
// It uses a boolean array 'seen' for efficiency.
bool check_permutation(const int* start, int len, std::vector<bool>& seen) {
    if (len == 0) return false; // Permutations must have non-zero length
    std::fill(seen.begin(), seen.begin() + len + 1, false); // Reset seen array for current length

    for (int i = 0; i < len; ++i) {
        int val = start[i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
    }
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    // Precompute suffix maximums
    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    std::vector<std::pair<int, int>> results;
    std::vector<bool> seen_p1(n + 1); // Max possible length for p1 is n-1
    std::vector<bool> seen_p2(n + 1); // Max possible length for p2 is n-1

    // Iterate through all possible split points l1
    // l1 is the length of p1, l2 is the length of p2
    // l1 ranges from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if p1 (a[0...l1-1]) can be a permutation of length l1
        // Condition 1: Max element in p1 must be l1
        if (prefix_max[l1 - 1] != l1) {
            continue;
        }

        // Check if p2 (a[l1...n-1]) can be a permutation of length l2
        // Condition 1: Max element in p2 must be l2
        if (suffix_max[l1] != l2) {
            continue;
        }

        // Condition 2: Check uniqueness and range for p1
        bool p1_is_perm = check_permutation(a.data(), l1, seen_p1);
        if (!p1_is_perm) {
            continue;
        }

        // Condition 2: Check uniqueness and range for p2
        bool p2_is_perm = check_permutation(a.data() + l1, l2, seen_p2);
        if (p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

