        int countS = 0;
        int countP = 0;

        for (char ch : s) {
            if (ch == 'R') {
                countR++;
            } else if (ch == 'S') {
                countS++;
            } else { // ch == 'P'
                countP++;
            }
        }

        char optimal_choice;
        if (countR >= countS && countR >= countP) {
            // If 'R' is most frequent, we should play 'P' to beat it.
            // If there's a tie, any choice is fine.
            // Example: R=2, S=2, P=1. Playing P beats R. Playing R beats S. Playing S beats P.
            // If we play P, we win 2 times.
            // If we play R, we win 1 time.
            // If we play S, we win 1 time.
            // So P is optimal.
            optimal_choice = 'P';
        } else if (countS >= countR && countS >= countP) {
            // If 'S' is most frequent, we should play 'R' to beat it.
            optimal_choice = 'R';
        } else { // countP is most frequent
            // If 'P' is most frequent, we should play 'S' to beat it.
            optimal_choice = 'S';
        }

        for (int i = 0; i < n; ++i) {
            std::cout << optimal_choice;
        }
        std::cout << "\n";
    }
