            prev_won = false;
        }
    }
    return current_score;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        if (k == 0) {
            std::cout << calculate_score(n, s) << "\n";
            continue;
        }

        int initial_wins = 0;
        for (char c : s) {
            if (c == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins + k >= n) { // Can make all games 'W'
            std::cout << 2 * n - 1 << "\n";
            continue;
        }

        // Find the first and last 'W'
        int first_w = -1, last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) first_w = i;
                last_w = i;
            }
        }

        if (first_w == -1) { // All 'L's initially
            std::cout << std::max(0, 2 * k - 1) << "\n"; // If k=0, score 0. If k=1, score 1. If k>0, 2k-1.
            continue;
        }

        // Collect lengths of 'L' segments between 'W's
        std::vector<int> l_segments;
        int current_l_count = 0;
        for (int i = first_w + 1; i < last_w; ++i) {
            if (s[i] == 'L') {
                current_l_count++;
            } else {
                if (current_l_count > 0) {
                    l_segments.push_back(current_l_count);
                }
                current_l_count = 0;
            }
        }
        if (current_l_count > 0) {
            l_segments.push_back(current_l_count);
        }
        std::sort(l_segments.begin(), l_segments.end());

        int current_k = k;
        int score_increase_from_segments = 0;
        for (int segment_len : l_segments) {
            if (current_k >= segment_len) {
                current_k -= segment_len;
                score_increase_from_segments += 2; // Each segment converted to W adds 2 points (W L W -> W W W)
            } else {
                break;
            }
        }

        int base_score = calculate_score(n, s);
        int max_score = base_score + 2 * (k - (k - current_k)) + score_increase_from_segments; // 2 points for each L converted to W

        // Consider converting L's before first W or after last W
        int l_before_first_w = first_w;
        int l_after_last_w = n - 1 - last_w;

        int score_from_ends = 0;
        if (current_k > 0) {
            if (l_after_last_w <= current_k) {
                score_from_ends += 2 * l_after_last_w;
                current_k -= l_after_last_w;
                if (l_before_first_w <= current_k) {
                    score_from_ends += 2 * l_before_first_w;
                    current_k -= l_before_first_w;
                } else {
                    score_from_ends += 2 * current_k;
                    current_k = 0;
                }
            } else {
                score_from_ends += 2 * current_k;
                current_k = 0;
            }
        }

        max_score = base_score + 2 * (k - current_k) + score_increase_from_segments;

        std::cout << max_score << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Friends who get w_i = 1: they get 2 * largest remaining numbers
    // These are the k_one largest numbers from 'a'.
    // Since w is sorted, these are the friends with largest w_i values if w_i=1.
    // But we want to give the largest numbers to friends with w_i=1.
    // So we iterate w from largest to smallest.
    // The friends with w_i = 1 should get the largest available numbers.
    // The friends with w_i > 1 should get the next largest available numbers as their max.

    // First, handle friends with w_i = 1.
    // These friends will get one number, which will be both their min and max.
    // To maximize happiness, they should get the largest available numbers.
    // We iterate w from largest to smallest.
    // The friends with w_i = 1 will be at the end of the sorted w array.

    int a_ptr_right = n - 1; // Pointer to the largest available number in 'a'

    // Give the largest numbers to friends with w_i = 1
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_right];
            a_ptr_right--;
        } else {
            // All remaining w[i] will be > 1.
            // Since w is sorted, all w[i] for i < current_i will also be > 1.
            // We can break here and handle the rest.
            break;
        }
    }

    // Now handle friends with w_i > 1.
    // These friends need a max and a min.
    // To maximize happiness, they should get the largest remaining numbers as their max.
    // And the smallest remaining numbers as their min.
    // The largest remaining numbers are pointed to by a_ptr_right.
    // The smallest remaining numbers are pointed to by a_ptr_left.

    int a_ptr_left = 0; // Pointer to the smallest available number in 'a'

    // Iterate through friends with w_i > 1 (these are at the beginning of sorted w)
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            // Each such friend gets the largest available number as their max.
            total_happiness += a[a_ptr_right];
            a_ptr_right--;

            // Each such friend also needs w[i]-1 additional numbers,
            // and one smallest number as their min.
            // The w[i]-1 numbers in between don't affect min/max.
            // To maximize sum of happiness, we give the smallest available numbers
            // as the minimums for these friends.
            total_happiness += a[a_ptr_left];
            a_ptr_left += (w[i] - 1); // Move pointer past the w[i]-1 intermediate numbers
            a_ptr_left++; // Move pointer past the minimum number itself
        }
    }

    std::cout << total_happiness << std::endl;
}

