void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // Condition: current_sum = 2 * current_xor_sum
    // If already good, append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // We need to append elements.
    // Let S' = current_sum + b1 + b2 + ...
    // Let X' = current_xor_sum ^ b1 ^ b2 ^ ...
    // We want S' = 2 * X'

    // Strategy: Append two elements.
    // Let the first element be current_xor_sum (X).
    // New sum: S + X
    // New XOR sum: X ^ X = 0
    // The condition becomes S + X = 2 * 0 = 0. This is generally not true.

    // Let's try to make the XOR sum 0.
    // Append X (current_xor_sum) to the array.
    // New sum: S_new = S + X
    // New XOR sum: X_new = X ^ X = 0
    // Now we need S_new = 2 * X_new, which means S + X = 2 * 0 = 0.
    // This is only true if S + X = 0, which implies S=0 and X=0 (since elements are non-negative).
    // If S+X is not 0, we need to append more elements.

    // After appending X, the array has sum S+X and XOR sum 0.
    // Let's call these S_prime = S+X and X_prime = 0.
    // We need S_prime = 2 * X_prime, which is S_prime = 0.
    // If S_prime is not 0, we need to append another element, say Y.
    // New sum: S_prime + Y
    // New XOR sum: X_prime ^ Y = 0 ^ Y = Y
    // We want S_prime + Y = 2 * Y
    // S_prime = Y

    // So, if we append X, then S_prime = S + X.
    // We then need to append Y = S_prime.
    // The two elements to append are X and S + X.

    // Let's verify this strategy:
    // Original array: sum S, xor_sum X
    // Append b1 = X
    // New array: sum S+X, xor_sum X^X = 0
    // Append b2 = S+X
    // Final array: sum (S+X) + (S+X) = 2*(S+X)
    // Final array: xor_sum 0 ^ (S+X) = S+X
    // Check condition: 2*(S+X) = 2 * (S+X). This is always true.

    // So, we can always append two elements: current_xor_sum and (current_sum + current_xor_sum).
    // This strategy works for any initial S and X.
    // The problem states that appended elements can be up to 10^18.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // So, current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
}

