#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>

long long solve() {
    long long p, q;
    std::cin >> p >> q;

    if (p % q != 0) {
        return p;
    }

    // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
    // This means x must not be a multiple of q.
    // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
    // If x is a multiple of q, then x must be a multiple of f_i^a_i for all i.
    // To make x not a multiple of q, we need to make x not a multiple of at least one f_i^a_i.
    // To maximize x, we should divide p by the smallest possible factor that makes it not divisible by q.
    // This means we should divide p by f_i for some i, such that p/f_i is not divisible by q.
    // More precisely, we want to remove just enough factors from p to break its divisibility by q,
    // while keeping the resulting number as large as possible.

    // Find prime factors of q
    std::vector<long long> prime_factors_q;
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            prime_factors_q.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back(temp_q);
    }

    long long max_x = 0;

    for (long long f : prime_factors_q) {
        long long current_p = p;
        // Divide current_p by f until it's no longer divisible by q
        while (current_p % q == 0) {
            current_p /= f;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

