void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int p = 0; p <= 9; ++p) {
        std::string colors(n, ' ');
        char last1 = '0';
        char last2 = '0';
        bool possible = true;
        bool p_seen_in_color1 = false;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];

            if (current_digit < p + '0') {
                // Must be color 1
                if (current_digit < last1) {
                    possible = false;
                    break;
                }
                colors[i] = '1';
                last1 = current_digit;
            } else if (current_digit > p + '0') {
                // Must be color 2
                if (current_digit < last2) {
                    possible = false;
                    break;
                }
                colors[i] = '2';
                last2 = current_digit;
                p_seen_in_color1 = true; // If we put a digit > p in color 2, then any p must have been in color 1
            } else { // current_digit == p + '0'
                if (!p_seen_in_color1) {
                    // Try to put in color 1
                    if (current_digit < last1) {
                        // Cannot put in color 1, must put in color 2
                        if (current_digit < last2) {
                            possible = false;
                            break;
                        }
                        colors[i] = '2';
                        last2 = current_digit;
                        p_seen_in_color1 = true; // Once a 'p' goes to color 2, all subsequent 'p's must go to color 2
                    } else {
                        colors[i] = '1';
                        last1 = current_digit;
                    }
                } else {
                    // Must put in color 2
                    if (current_digit < last2) {
                        possible = false;
                        break;
                    }
                    colors[i] = '2';
                    last2 = current_digit;
                }
            }
        }

        if (possible) {
            std::cout << colors << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

