int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m by swapping if necessary.
        // This simplifies logic as we can always assume n is the larger coordinate.
        if (n < m) {
            std::swap(n, m);
        }

        // Case 1: k is less than the minimum number of moves required to reach (n, m).
        // The minimum moves is max(n, m) because each move can cover at most 1 unit in both x and y.
        // Since we ensured n >= m, min moves is n.
        if (k < n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k has the same parity as n and m.
        // This means (k - n) is even, and (k - m) is even.
        // Since n >= m, (n - m) is non-negative.
        // If (n - m) is even, then n and m have the same parity.
        // If (k - n) is even, then k and n have the same parity.
        // Thus, if (n - m) is even and (k - n) is even, then k, n, m all have the same parity.
        if ((n - m) % 2 == 0) {
            // In this case, we can make n diagonal moves to reach (n, n) or (n, m) if m=n.
            // Then we need to make (k - n) more moves.
            // Since (k - n) is even, we can make (k - n) / 2 pairs of moves like (1,0) then (-1,0)
            // or (1,1) then (-1,-1) etc.
            // Each such pair of moves (e.g., (1,0) and (-1,0)) uses 2 moves and results in 0 net displacement.
            // If we use (1,1) and (-1,-1), it uses 2 diagonal moves.
            // If we use (1,0) and (-1,0), it uses 0 diagonal moves.
            // To maximize diagonal moves, we want to use as many diagonal moves as possible.
            // The maximum number of diagonal moves is limited by k.
            // If we reach (n, m) using m diagonal moves and (n-m) axial moves, total moves = n.
            // The remaining k-n moves must be pairs of cancelling moves.
            // If k-n is even, we can make (k-n)/2 pairs of moves.
            // Each pair can be (1,1) and (-1,-1), contributing 2 diagonal moves.
            // So, we can add (k-n) diagonal moves.
            // Total diagonal moves = m (to reach (m,m)) + (n-m) (to reach (n,m) from (m,m) using axial) + (k-n) (cancelling diagonal moves).
            // This simplifies to k.
            // However, the number of diagonal moves cannot exceed k.
            // The maximum number of diagonal moves is k.
            // The number of diagonal moves is k.
            std::cout << k << "\n";
        }
        // Case 3: k has different parity than n and m.
        // This means (n - m) is odd, or (k - n) is odd.
        // If (n - m) is odd, then n and m have different parities.
        // If (k - n) is odd, then k and n have different parities.
        // If (n - m) is odd, then n and m have different parities.
        // If (k - n) is even, then k and n have the same parity.
        // This implies k and m have different parities.
        // If (n - m) is even, then n and m have the same parity.
