        q.push_back(i);
    }

    q.clear();
    long long max_ops = 0;

    // Calculate d_i for right-to-left pass and find max_ops
    for (int i = n - 1; i >= 0; --i) {
        while (!q.empty() && h[q.back()] >= h[i]) {
            q.pop_back();
        }
        long long prev_d = (q.empty() ? 0 : d[q.back()]);
        d[i] = std::min(d[i], prev_d + ((q.empty() ? n : q.back()) - i));
        q.push_back(i);
        max_ops = std::max(max_ops, d[i]);
    }

    std::cout << max_ops << std::endl;

    return 0;
}

