#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // balance_L[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // for k from 0 to n
    std::vector<int> balance_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        balance_L[i + 1] = balance_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate prefix sums for the right half (jars n+1 to 2n)
    // balance_R[k] = (count of 1s in a[2n-1...2n-k]) - (count of 2s in a[2n-1...2n-k])
    // for k from 0 to n
    std::vector<int> balance_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        balance_R[i + 1] = balance_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars removed from the left (L)
    // to achieve a certain balance_L value.
    // key: balance_L value, value: L (number of jars removed)
    std::map<int, int> left_balance_to_L;
    for (int L = 0; L <= n; ++L) {
        int current_balance = balance_L[L];
        if (left_balance_to_L.find(current_balance) == left_balance_to_L.end()) {
            left_balance_to_L[current_balance] = L;
        }
    }

    int min_total_removed = 2 * n; // Initialize with maximum possible removals

    // Iterate through all possible numbers of jars removed from the right (R)
    for (int R = 0; R <= n; ++R) {
        int current_balance_R = balance_R[R];
        // We need balance_L[L] + current_balance_R = 0
        // So, balance_L[L] = -current_balance_R
        int target_balance_L = -current_balance_R;

        if (left_balance_to_L.count(target_balance_L)) {
            int L = left_balance_to_L[target_balance_L];
            min_total_removed = std::min(min_total_removed, L + R);
        }
    }

    std::cout << min_total_removed << std::endl;
}

