        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m == 0) {
        return 0;
    }

    long long total_substrings = n * (n + 1) / 2;

    long long num_zeros = n - m;

    // If there are no zeros, all substrings contain '1's.
    if (num_zeros == 0) {
        return total_substrings;
    }

    // To minimize substrings of all zeros, distribute zeros as evenly as possible.
    // This means dividing the num_zeros into m+1 blocks (potentially empty)
    // separated by '1's, or into m blocks if we place '1's at ends.
    // The optimal strategy is to place '1's such that the blocks of '0's are
    // as equal in length as possible.
    // This is achieved by dividing num_zeros by (m+1) to get base length,
    // and then distributing the remainder.
    // The string structure will be like 0...010...01...10...0
    // There will be m+1 segments of zeros.
    // Let q = num_zeros / (m+1) and r = num_zeros % (m+1).
    // There will be r segments of length q+1 and (m+1-r) segments of length q.

    long long q = num_zeros / (m + 1);
    long long r = num_zeros % (m + 1);

    long long num_zero_substrings = 0;

    // r segments of length q+1
    num_zero_substrings += r * (q + 1) * (q + 2) / 2;

    // (m+1-r) segments of length q
    num_zero_substrings += (m + 1 - r) * q * (q + 1) / 2;

    return total_substrings - num_zero_substrings;
}

