int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    long long total_operations = 0;
    int consecutive_matches = 0;
    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // If the chain starts with 1, it's a candidate for the main sequence
        if (chain[0] == 1) {
            // Count how many consecutive elements match the target sequence 1, 2, 3...
            for (int j = 0; j < m; ++j) {
                if (chain[j] == j + 1) {
                    consecutive_matches++;
                } else {
                    break; // Mismatch, sequence broken
                }
            }
        }
    }

    // The total number of 'put' operations needed for a chain of length N is N-1.
    // If we have 'consecutive_matches' elements already in place (1, 2, ..., consecutive_matches),
    // then we don't need to perform 'put' operations for these.
    // Specifically, we save 'consecutive_matches - 1' put operations (1->2, 2->3, ..., (consecutive_matches-1)->consecutive_matches).
    // The number of 'put' operations we *do* need is (n-1) - (consecutive_matches - 1).
    // This simplifies to n - consecutive_matches.
    // This is the number of 'put' operations for the final assembly.

    // The number of 'get out' operations:
    // Each chain needs to be disassembled.
    // A chain of length m has m-1 nested pairs.
    // To get all dolls out, we need m-1 'get out' operations.
    // Summing over all k chains: sum(m_i - 1) for i=1 to k.
    // Since sum(m_i) = n, this is n - k.
    // However, if a part of a chain is already part of the final sequence (1, 2, ..., consecutive_matches),
    // we don't need to disassemble that part.
    // The dolls 1, 2, ..., consecutive_matches are already in their correct relative positions.
    // So, we don't need to 'get out' doll 'i' from 'i+1' for i from 1 to consecutive_matches-1.
    // This means we save (consecutive_matches - 1) 'get out' operations.
    // So, the 'get out' operations needed are (n - k) - (consecutive_matches - 1).
    // This simplifies to n - k - consecutive_matches + 1.

    // Total operations = (put operations) + (get out operations)
    // Total = (n - consecutive_matches) + (n - k - consecutive_matches + 1)
    // Total = 2*n - k - 2*consecutive_matches + 1

    // Let's re-evaluate.
    // Total dolls = n.
    // Total 'put' operations to form 1->2->...->n from n individual dolls is n-1.
    // If we have 'consecutive_matches' dolls already in the sequence 1->2->...->consecutive_matches,
    // then (consecutive_matches - 1) 'put' operations are already done.
    // So, we need (n-1) - (consecutive_matches - 1) = n - consecutive_matches 'put' operations.

    // For 'get out' operations:
    // Each chain `m_i` has `m_i - 1` nested pairs.
    // Total nested pairs across all chains is `sum(m_i - 1) = sum(m_i) - sum(1) = n - k`.
    // These `n - k` operations are the maximum 'get out' operations needed.
    // However, the `consecutive_matches - 1` nested pairs (1->2, 2->3, ..., (consecutive_matches-1)->consecutive_matches)
    // are part of the final desired structure and are already correctly nested.
    // So, we don't need to 'get out' these.
    // The number of 'get out' operations is (n - k) - (consecutive_matches - 1).

    // Total operations = (n - consecutive_matches) + (n - k - (consecutive_matches - 1))
    // Total operations = n - consecutive_matches + n - k - consecutive_matches + 1
    // Total operations = 2 * n - k - 2 * consecutive_matches + 1

    total_operations = (long long)2 * n - k - 2 * consecutive_matches + 1;

    std::cout << total_operations << std::endl;

    return 0;
}

