    // = k - zeros_count - ones_count = question_count.

    // If we reach here, it's possible to fill the first k characters.
    // The remaining '?'s in fixed_chars can be filled arbitrarily to satisfy the counts.
    // We don't actually need to fill them in fixed_chars, just check if it's possible.

    std::cout << "YES\n";
}

