        for (int i = 0; i < num_elements_for_block; ++i) {
            result_array.push_back(current_val);
        }
        X -= ((1LL << num_elements_for_block) - 1);
        current_val += d;
    }

    if (result_array.size() > 10000) {
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (b_1=a_1, b_n=a_n, no middle elements)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zero_dist(n);
    std::vector<int> right_zero_dist(n);

    // Calculate left_zero_dist
    if (a[0] == 0) {
        left_zero_dist[0] = 0;
    } else {
        left_zero_dist[0] = -1; // Represents infinity or 'no zero yet'
    }
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_dist[i] = 0;
        } else {
            if (left_zero_dist[i - 1] == -1) {
                left_zero_dist[i] = -1;
            } else {
                left_zero_dist[i] = left_zero_dist[i - 1] + 1;
            }
        }
    }

    // Calculate right_zero_dist
    if (a[n - 1] == 0) {
        right_zero_dist[n - 1] = 0;
    } else {
        right_zero_dist[n - 1] = -1;
    }
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_dist[i] = 0;
        } else {
            if (right_zero_dist[i + 1] == -1) {
                right_zero_dist[i] = -1;
            } else {
                right_zero_dist[i] = right_zero_dist[i + 1] + 1;
            }
        }
    }

    int max_dist = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            int current_dist = -1;
            if (left_zero_dist[i] != -1 && right_zero_dist[i] != -1) {
                current_dist = std::min(left_zero_dist[i], right_zero_dist[i]);
            } else if (left_zero_dist[i] != -1) { // Only left zero exists
                current_dist = left_zero_dist[i];
            } else if (right_zero_dist[i] != -1) { // Only right zero exists
                current_dist = right_zero_dist[i];
            }
            // If current_dist is still -1, it means no zeros exist, so it's an all-ones sequence.
            // In this case, max_dist remains 0, and the sequence is stable.
            if (current_dist != -1) {
                max_dist = std::max(max_dist, current_dist);
            }
        }
    }

    int k = (max_dist + 1) / 2;

    std::cout << k << std::endl;

    std::vector<int> result(n);
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            result[i] = 0;
        } else {
            int current_min_dist = -1;
            if (left_zero_dist[i] != -1 && right_zero_dist[i] != -1) {
                current_min_dist = std::min(left_zero_dist[i], right_zero_dist[i]);
            } else if (left_zero_dist[i] != -1) {
                current_min_dist = left_zero_dist[i];
            } else if (right_zero_dist[i] != -1) {
                current_min_dist = right_zero_dist[i];
            }

            if (current_min_dist == -1) { // No zeros in the sequence
                result[i] = 1;
            } else {
                result[i] = (current_min_dist <= k) ? 0 : 1;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, 0);
    std::vector<long long> current_diff(n, 0); // Stores the sum of 'd's applied to each element

    // First pass: Determine upper bounds for initial_a[i]
    // For each type 2 operation (l, r, m), we know that for all j in [l, r],
    // initial_a[j] + current_diff[j] <= m.
    // This implies initial_a[j] <= m - current_diff[j].
    // We want to find the largest possible initial_a[j] that satisfies all constraints.
    // So, initial_a[j] will be the minimum of (m - current_diff[j]) over all relevant type 2 ops.
    // Initialize initial_a[j] to a very large value (effectively infinity)
    for (int i = 0; i < n; ++i) {
        initial_a[i] = std::numeric_limits<long long>::max();
    }

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_diff[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_diff[j]);
            }
        }
    }

    // Second pass: Verify the solution
    // Reconstruct the array with the determined initial_a values and check all operations.
    // If initial_a[j] was not constrained by any type 2 operation, it remains max_long_long.
    // We can set such elements to 0, as they don't affect any max constraints.
    // However, the problem states |a_i| <= 10^9. Setting to 0 is safe.
    // If initial_a[j] is still max_long_long, it means it was never part of a type 2 query range.
    // We can set it to 0.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == std::numeric_limits<long long>::max()) {
            initial_a[i] = 0;
        }
    }

    // Reset current_diff for verification
    std::fill(current_diff.begin(), current_diff.end(), 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_diff[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, initial_a[j] + current_diff[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could be n * max(a_i) * 2, which is 2*10^5 * 10^9 * 2 = 4*10^14.
// This fits in a long long.

// Using a vector for a, with 1-based indexing for convenience.
// a[0] will be unused.
std::vector<long long> a_values;
int N;

// Memoization table for (x, parity) -> (final_y, final_x)
// state_info[x][0] stores info for x when it's about to execute step 2 (x is odd step)
// state_info[x][1] stores info for x when it's about to execute step 3 (x is even step)
// The pair stores {final_y_delta, final_x_delta}
// We need to store the full y and x values, not just deltas, because the termination condition depends on x.
// To detect cycles, we can use a special value or a visited array.
// Let's use a pair {y_val, x_val} where x_val is the final x, and y_val is the final y.
// If x_val is 0, it means it terminated with x <= 0.
// If x_val is N+1, it means it terminated with x > N.
// If x_val is -1, it means it's part of a cycle.
// If x_val is -2, it means it's currently being computed (to detect cycles).

// We need to store the result for a state (current_x, current_y, current_step_parity)
// The current_y is cumulative, so we can't just memoize (current_x, current_step_parity).
// However, the problem structure is that y accumulates a_x values.
// The path taken only depends on x and a_x.
// So, if we reach a state (x, step_parity) again, the *relative* change in y and x will be the same.
// We can memoize (x, step_parity) -> (delta_y, final_x_after_path).
// If final_x_after_path is 0 or N+1, it means termination.
// If final_x_after_path is -1, it means infinite loop.

// Let's define a state as (current_x, current_y_sum_so_far, current_step_type)
// The current_step_type is 0 for step 2, 1 for step 3.
// The problem is that current_y_sum_so_far is not fixed.
// The key observation is that the *sequence of x values* only depends on the initial x and the array `a`.
// The `y` value is just an accumulation along this path.
// So, we can compute the `(delta_y, final_x)` for each starting `x` and `step_type`.

// `memo[x][0]` stores the result if we start at `x` and are about to execute step 2.
// `memo[x][1]` stores the result if we start at `x` and are about to execute step 3.
// The result is a pair: `{total_y_added, final_x_value}`.
// `total_y_added` is the sum of `a_k` values encountered.
// `final_x_value` is the `x` value when the program terminates or enters a cycle.
// Special values for `final_x_value`:
//   -1: indicates an infinite loop.
//   -2: indicates that this state is currently being computed (used for cycle detection).
//   0: indicates termination with `x <= 0`.
//   N+1: indicates termination with `x > N`.
//   Any other value `1 <= x_val <= N`: indicates termination at `x_val` (this shouldn't happen if we correctly propagate termination).
//    Actually, it should be `1 <= x_val <= N` if it transitions to another state that is already computed.

struct Result {
    long long y_delta;
    int final_x; // 0 for x<=0, N+1 for x>N, -1 for cycle, -2 for computing
};

std::vector<std::vector<Result>> memo;

Result solve(int current_x, int step_type) {
    if (current_x <= 0) return {0, 0};
    if (current_x > N) return {0, N + 1};

    if (memo[current_x][step_type].final_x != -3) { // -3 is initial uncomputed state
        return memo[current_x][step_type];
    }

    // Mark as currently computing to detect cycles
    memo[current_x][step_type] = {0, -2};

    Result res;
    if (step_type == 0) { // About to execute step 2
        long long val_ax = a_values[current_x];
        int next_x = current_x + val_ax;
        long long y_added = val_ax;

        Result next_res = solve(next_x, 1); // Next is step 3

        if (next_res.final_x == -2) { // Cycle detected
            res = {0, -1};
        } else {
            res = {y_added + next_res.y_delta, next_res.final_x};
        }
    } else { // About to execute step 3
        long long val_ax = a_values[current_x];
        int next_x = current_x - val_ax;
        long long y_added = val_ax;

        Result next_res = solve(next_x, 0); // Next is step 2

        if (next_res.final_x == -2) { // Cycle detected
            res = {0, -1};
        } else {
            res = {y_added + next_res.y_delta, next_res.final_x};
        }
    }

    return memo[current_x][step_type] = res;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_values.resize(N + 1);
    for (int i = 2; i <= N; ++i) {
        std::cin >> a_values[i];
    }

    // Initialize memo table. -3 indicates uncomputed.
    memo.resize(N + 1, std::vector<Result>(2, {0, -3}));

    for (int i = 1; i < N; ++i) {
        a_values[1] = i; // Set a_1 for this run

        // Initial state: x=1, y=0. First operation is step 2.
        // So we call solve(1, 0)
        Result final_state = solve(1, 0);

        if (final_state.final_x == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << final_state.y_delta << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // This child is now cured

        long long current_cry_volume = children[i].v;
        long long cumulative_d_cry = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cumulative d_cry from previous children who left
            children[j].p -= cumulative_d_cry;

            // Apply current child's v_cry
            if (current_cry_volume > 0) {
                children[j].p -= current_cry_volume;
                current_cry_volume = std::max(0LL, current_cry_volume - 1);
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                cumulative_d_cry += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // The new string is s2s1.
    // We need s2s1 to be a palindrome and s2s1 != s.
    // Iterate through all possible cut points.
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // For k=2, we need to show that it's always possible unless all characters are the same.
    // If all characters are the same, e.g., "aaaa", then any rearrangement of substrings
    // will result in "aaaa". In this case, it's impossible to get s' != s.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 is always possible.
        // Example: "nolon" -> "no|l|on" -> "on|l|no" is a palindrome and != "nolon".
        // This works because if not all characters are the same,
        // there must be at least two distinct characters.
        // Since s is a palindrome, it must have at least two distinct characters
        // if it's not all_same.
        // Consider the string s. If it's not all_same, then s.substr(0, n-1) is not all_same.
        // If s.substr(0, n-1) is not a palindrome, then we can cut s into
        // s.substr(0, n-1) and s.substr(n-1, 1).
        // The new string would be s.substr(n-1, 1) + s.substr(0, n-1).
        // This is not guaranteed to be a palindrome.
        //
        // The problem statement guarantees s is a palindrome.
        // If k=1 fails, it means for any split s = s1s2, s2s1 is either not a palindrome or s2s1 == s.
        //
        // Consider the case where n is odd, e.g., "abacaba".
        // If we cut "abacaba" into "aba" | "c" | "aba", and rearrange to "aba" | "c" | "aba", it's the same.
        // But if we cut "abacaba" into "ab" | "ac" | "aba", this is not a valid cut for k=2.
        //
        // The proof for k=2 being sufficient when not all_same and k=1 fails:
        // If s is a palindrome and not all characters are the same, then there exists
        // at least one character s[i] such that s[i] != s[0].
        // Since s is a palindrome, s[n-1-i] = s[i].
        //
        // Consider the string s. If it's not all_same, then s has at least two distinct characters.
        // Since s is a palindrome, its first half (excluding middle char for odd length)
        // must contain at least two distinct characters.
        //
        // Let's take the first half of the string: `s_half = s.substr(0, n/2)`.
        // If `s_half` is not a palindrome, then we can cut `s` into `s_half`, `s_middle` (if n is odd), and `s_half_reversed`.
        // This is not how cuts work. Cuts are substrings of `s`.
        //
        // The logic for k=2 is simpler:
        // If `s` is not composed of all identical characters, then `s` must contain at least two distinct characters.
        // Since `s` is a palindrome, its first half (up to `n/2 - 1`) must contain at least two distinct characters.
        // If `s` is not all_same, then `s.substr(0, n-1)` is not all_same.
        //
        // Consider `s = "nolon"`. `n=5`.
        // `s.substr(0, n/2)` is "no".
        // `s.substr(0, n/2)` is not a palindrome.
        //
        // If `s` is not all_same, then `s.substr(0, n/2)` is not all_same.
        // If `s.substr(0, n/2)` is not a palindrome, then we can cut `s` into `s.substr(0, n/2)`, `s.substr(n/2, n - 2*(n/2))`, `s.substr(n/2 + (n - 2*(n/2)))`.
        //
        // The example "nolon" -> "no|l|on" -> "on|l|no" works with 2 cuts.
        // This is `s[0...1]`, `s[2]`, `s[3...4]`.
        // Rearranged: `s[3...4]`, `s[2]`, `s[0...1]`.
        // This is `s.substr(n/2 + 1)`, `s.substr(n/2, 1)`, `s.substr(0, n/2)`.
        // This forms a palindrome `s_rev_half + s_mid + s_half`.
        // Since `s` is a palindrome, `s_rev_half` is `reverse(s_half)`.
        // So the new string is `reverse(s.substr(0, n/2)) + s.substr(n/2, n - 2*(n/2)) + s.substr(0, n/2)`.
        //
        // If `s` is not all_same, then `s.substr(0, n/2)` is not all_same.
        // If `s.substr(0, n/2)` is not a palindrome, then `reverse(s.substr(0, n/2))` is different from `s.substr(0, n/2)`.
        // So `reverse(s.substr(0, n/2)) + s.substr(n/2, n - 2*(n/2)) + s.substr(0, n/2)` will be different from `s`.
        // And it will be a palindrome.
        // This construction uses 2 cuts (3 pieces).
        //
        // This covers all cases where `s` is not all_same.
        // If `s` is not all_same, and `k=1` fails, then `k=2` is the answer.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., S1).
    // All f values are a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences.
    // The minimum possible f value is a[0].value + a[1].value.
    // The maximum possible f value is max(a[n-1].value + a[n-2].value, a[n-1].value + a[0].value + h).
    // This is because a[n-1] and a[0] are the largest and smallest elements.
    // If they are in the same subsequence, max_f could be a[n-1]+a[n-2].
    // If they are in different subsequences, max_f could be a[n-1]+a[0]+h.
    // The overall maximum f value will be max(a[n-1]+a[n-2], a[n-1]+a[0]+h).
    // The overall minimum f value will be a[0]+a[1].
    // So, goodness = max(a[n-1]+a[n-2], a[n-1]+a[0]+h) - (a[0]+a[1]).

    // Let's consider a specific partition: a[0] in S1, a[1]...a[n-1] in S2.
    // Or more generally, a[0] in S1, and all other elements in S2.
    // This means a[0] is in S1, and a[1], ..., a[n-1] are in S2.
    // Possible f values:
    // 1. a_i + a_j for i, j in {1, ..., n-1} (both in S2)
    // 2. a[0].value + a_j + h for j in {1, ..., n-1} (a[0] in S1, a_j in S2)

    // Min f value:
    // If n >= 2, a[1].value + a[2].value (if n >= 3) or a[0].value + a[1].value + h (if n=2)
    // The smallest sum of two elements in S2 is a[1].value + a[2].value (if n >= 3).
    // The smallest sum of one from S1 and one from S2 is a[0].value + a[1].value + h.
    // So, min_f = min(a[1].value + a[2].value (if n>=3), a[0].value + a[1].value + h).
    // However, the problem states "Consider all possible values of the function f for some partition".
    // This means we need to find the global min and max f values for a given partition.
    // For the partition where a[0] is in S1 and others in S2:
    // min_f = min(a[1].value + a[2].value (if n>=3), a[0].value + a[1].value + h).
    // If n=2, S2 only has a[1]. No pairs in S2. min_f = a[0].value + a[1].value + h.
    // If n=2, a[0] in S1, a[1] in S2. Only one pair (a[0], a[1]). f = a[0]+a[1]+h. goodness = 0.
    // This is covered by the general logic below.

    // Let's consider the partition where a[0] is in S1, and a[1], ..., a[n-1] are in S2.
    // min_f_val:
    // If n >= 3, min_f_val = min(a[1].value + a[2].value, a[0].value + a[1].value + h).
    // If n == 2, min_f_val = a[0].value + a[1].value + h.
    // max_f_val:
    // max_f_val = max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h).

    // Let's simplify.
    // The minimum possible sum of two elements is a[0].value + a[1].value.
    // The maximum possible sum of two elements is a[n-1].value + a[n-2].value.

    // If we put a[0] in S1 and all other elements in S2:
    // The smallest f value will be min(a[1].value + a[2].value (if n>=3), a[0].value + a[1].value + h).
    // The largest f value will be max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h).
    // This partition is: a[0] in S1, a[1...n-1] in S2.
    // The minimum value of f is `min(a[1].value + a[2].value, a[0].value + a[1].value + h)` if n >= 3.
    // If n=2, the only pair is (a[0], a[1]), they are in different sets, so f = a[0].value + a[1].value + h.
    // In this case, min_f = max_f = a[0].value + a[1].value + h, so goodness = 0.
    // This is a special case.

    // For n >= 3:
    // min_f_val_case2 = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    // max_f_val_case2 = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h);
    // goodness2 = max_f_val_case2 - min_f_val_case2;

    // Let's re-evaluate the minimum and maximum f values for a general partition.
    // Let `min_sum_same = a[0].value + a[1].value`.
    // Let `max_sum_same = a[n-1].value + a[n-2].value`.
    // Let `min_sum_diff = a[0].value + a[1].value + h`.
    // Let `max_sum_diff = a[n-1].value + a[n-2].value + h`. (This is not necessarily true, it could be a[n-1]+a[0]+h)

    // The minimum possible value of `a_i + a_j` is `a[0].value + a[1].value`.
    // The maximum possible value of `a_i + a_j` is `a[n-1].value + a[n-2].value`.

    // Consider the partition where a[0] is in S1, and a[1], ..., a[n-1] are in S2.
    // This is the "optimal" partition for the second case.
    // The values of f are:
    // 1. `a_i + a_j` for `i, j \in \{1, \dots, n-1\}`.
    //    Min of these: `a[1].value + a[2].value` (if n >= 3).
    //    Max of these: `a[n-1].value + a[n-2].value`.
    // 2. `a[0].value + a_j + h` for `j \in \{1, \dots, n-1\}`.
    //    Min of these: `a[0].value + a[1].value + h`.
    //    Max of these: `a[0].value + a[n-1].value + h`.

    // So, for this partition:
    // min_f = (n >= 3) ? std::min(a[1].value + a[2].value, a[0].value + a[1].value + h) : (a[0].value + a[1].value + h);
    // max_f = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h);
    // goodness2 = max_f - min_f;

    // This logic is correct for n >= 2.
    // If n=2: a[0] in S1, a[1] in S2. Only one pair (a[0], a[1]). f = a[0]+a[1]+h. min_f = max_f = a[0]+a[1]+h. goodness = 0.
    // Using the formulas:
    // min_f = (2 >= 3) ? ... : (a[0].value + a[1].value + h) = a[0].value + a[1].value + h.
    // max_f = std::max(a[1].value + a[0].value, a[0].value + a[1].value + h).
    // Since h >= 0, a[0].value + a[1].value + h >= a[0].value + a[1].value.
    // So max_f = a[0].value + a[1].value + h.
    // goodness2 = (a[0].value + a[1].value + h) - (a[0].value + a[1].value + h) = 0. This is correct.

    // For n >= 3:
    long long min_f_val_case2 = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    long long max_f_val_case2 = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h);
    long long goodness2 = max_f_val_case2 - min_f_val_case2;

    // If n=2, goodness2 is 0.
    if (n == 2) {
        goodness2 = 0;
    }

    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1; // Smallest element in S1
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2; // Others in S2
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks
    for (int i = 0; i < n; ++i) { // Iterate through each head
        if (p_idx >= m) { // All target tracks covered
            return true;
        }

        long long head_pos = h[i];
        long long head_left_reach = head_pos - T;
        long long head_right_reach = head_pos + T;

        // If the current head cannot reach the current target track p[p_idx],
        // it means this head cannot cover any tracks before p[p_idx] either,
        // so we need to move to the next head.
        // However, we must ensure that p[p_idx] is covered by *some* head.
        // If p[p_idx] is to the right of head_right_reach, this head cannot cover it.
        // If p[p_idx] is to the left of head_left_reach, this head cannot cover it.
        // So, if p[p_idx] is outside [head_left_reach, head_right_reach], this head cannot cover it.
        // But we are trying to cover tracks greedily.
        // If p[p_idx] is already covered by a previous head, we just advance p_idx.
        // If p[p_idx] is not covered, this head must cover it.

        // Find the first track this head can cover.
        // If p[p_idx] is too far to the left for this head, this head cannot cover it.
        // We need to find the first p[k] such that p[k] >= head_left_reach.
        // If such p[k] exists and p[k] <= head_right_reach, then this head can cover it.
        // The greedy strategy is to cover as many tracks as possible to the right.

        // Skip tracks already covered by previous heads or those too far left for current head
        while (p_idx < m && p[p_idx] < head_left_reach) {
            p_idx++;
        }

        if (p_idx >= m) { // All tracks covered
            return true;
        }

        // If the current head can cover p[p_idx], it can cover a range [p[p_idx], min(head_right_reach, p[p_idx] + T_remaining_from_p_idx)]
        // The actual range covered by this head is [max(head_left_reach, p[p_idx]), head_right_reach].
        // We want to cover tracks starting from p[p_idx] as far right as possible.
        // The rightmost track this head can cover is head_right_reach.
        // So, we advance p_idx past all tracks that are <= head_right_reach.
        while (p_idx < m && p[p_idx] <= head_right_reach) {
            p_idx++;
        }
    }
    return p_idx >= m; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between p_i and h_i is ~10^10.
                                    // A safe upper bound is 2 * 10^10.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> adj(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> adj[i][j];
        }
    }

    std::vector<int> removal_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> removal_order[i];
        removal_order[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false); // Tracks which vertices are currently in the graph

    // Process in reverse order of removal, which means adding vertices
    for (int step = n - 1; step >= 0; --step) {
        int k = removal_order[step]; // The vertex being added in this step
        active_vertices[k] = true;

        // Floyd-Warshall update: consider k as an intermediate vertex
        // d[i][j] = min(d[i][j], d[i][k] + d[k][j])
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (adj[i][k] != -1 && adj[k][j] != -1) { // Check if paths through k exist
                    if (adj[i][j] == -1 || adj[i][j] > adj[i][k] + adj[k][j]) {
                        adj[i][j] = adj[i][k] + adj[k][j];
                    }
                }
            }
        }

        // After updating with k, calculate the sum of shortest paths
        // between all pairs of currently active vertices.
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (active_vertices[i]) {
                for (int j = 0; j < n; ++j) {
                    if (active_vertices[j] && i != j) { // Only sum for distinct active pairs
                        current_sum += adj[i][j];
                    }
                }
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (reverse of how they were collected)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0 to 9), we need to track how it transforms.
    // A bit can either remain the same (0 -> 0, 1 -> 1) or be flipped (0 -> 1, 1 -> 0).
    // We can represent this with two values:
    // `val_if_0`: what the bit becomes if it was initially 0.
    // `val_if_1`: what the bit becomes if it was initially 1.
    // Initialize: 0 -> 0, 1 -> 1
    std::vector<int> val_if_0(10); // Stores the final state of bit_i if initial bit_i was 0
    std::vector<int> val_if_1(10); // Stores the final state of bit_i if initial bit_i was 1

    for (int i = 0; i < 10; ++i) {
        val_if_0[i] = 0;
        val_if_1[i] = 1;
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int i = 0; i < 10; ++i) {
            int bit_x = (x >> i) & 1; // i-th bit of constant x

            if (op_char == '&') {
                val_if_0[i] &= bit_x;
                val_if_1[i] &= bit_x;
            } else if (op_char == '|') {
                val_if_0[i] |= bit_x;
                val_if_1[i] |= bit_x;
            } else if (op_char == '^') {
                val_if_0[i] ^= bit_x;
                val_if_1[i] ^= bit_x;
            }
        }
    }

    // Now we have the final transformation for each bit.
    // We need to find a minimal sequence of operations (at most 5) that achieves this.
    // The target values for the three operations are:
    // AND_mask: if a bit becomes 0 regardless of input, it must be 0 in AND_mask.
    // OR_mask: if a bit becomes 1 regardless of input, it must be 1 in OR_mask.
    // XOR_mask: if a bit flips its input, it must be 1 in XOR_mask.

    int final_and_mask = 1023; // All bits 1 initially for AND
    int final_or_mask = 0;     // All bits 0 initially for OR
    int final_xor_mask = 0;    // All bits 0 initially for XOR

    for (int i = 0; i < 10; ++i) {
        if (val_if_0[i] == 0 && val_if_1[i] == 0) {
            // Bit always becomes 0. This means it must be 0 in the AND mask.
            final_and_mask &= ~(1 << i);
        } else if (val_if_0[i] == 1 && val_if_1[i] == 1) {
            // Bit always becomes 1. This means it must be 1 in the OR mask.
            final_or_mask |= (1 << i);
        } else if (val_if_0[i] == 0 && val_if_1[i] == 1) {
            // Bit remains unchanged (0->0, 1->1).
            // This is the default for AND, OR, XOR with 0.
            // No specific action needed for this bit in AND/OR/XOR masks yet.
        } else if (val_if_0[i] == 1 && val_if_1[i] == 0) {
            // Bit flips (0->1, 1->0). This means it must be 1 in the XOR mask.
            final_xor_mask |= (1 << i);
        }
    }

    // The order of operations matters. A common canonical form is:
    // ( (x & A) | B ) ^ C
    // Let's verify if this form can represent all transformations.
    // For each bit i:
    // Initial: x_i
    // After & A: x_i & A_i
    // After | B: (x_i & A_i) | B_i
    // After ^ C: ((x_i & A_i) | B_i) ^ C_i

    // We need to find A, B, C such that for each bit i:
    // If x_i = 0: ((0 & A_i) | B_i) ^ C_i = val_if_0[i]  => (0 | B_i) ^ C_i = val_if_0[i] => B_i ^ C_i = val_if_0[i]
    // If x_i = 1: ((1 & A_i) | B_i) ^ C_i = val_if_1[i]  => (A_i | B_i) ^ C_i = val_if_1[i]

    // Let's try to construct A, B, C directly from val_if_0 and val_if_1.
    // A bit i is affected by AND if val_if_1[i] becomes 0 when val_if_0[i] is 0.
    // A bit i is affected by OR if val_if_0[i] becomes 1 when val_if_1[i] is 1.
    // A bit i is affected by XOR if val_if_0[i] != val_if_1[i].

    // Let's define the masks for the canonical form: (x & A) | B ^ C
    int A = 0; // AND mask
    int B = 0; // OR mask
    int C = 0; // XOR mask

    for (int i = 0; i < 10; ++i) {
        if (val_if_0[i] == 0 && val_if_1[i] == 0) {
            // Bit always 0.
            // (0 & A_i) | B_i ^ C_i = 0 => B_i ^ C_i = 0
            // (1 & A_i) | B_i ^ C_i = 0 => A_i | B_i ^ C_i = 0
            // From B_i ^ C_i = 0, we have B_i = C_i.
            // So, A_i | B_i ^ B_i = 0 => A_i | 0 = 0 => A_i = 0.
            // If A_i = 0, then B_i ^ C_i = 0. We can choose B_i = 0, C_i = 0.
            // So, A_i=0, B_i=0, C_i=0.
            // This means A_i must be 0.
            // A &= ~(1 << i); // A_i = 0
            // B_i = 0, C_i = 0
        } else if (val_if_0[i] == 1 && val_if_1[i] == 1) {
            // Bit always 1.
            // (0 & A_i) | B_i ^ C_i = 1 => B_i ^ C_i = 1
            // (1 & A_i) | B_i ^ C_i = 1 => A_i | B_i ^ C_i = 1
            // From B_i ^ C_i = 1, we have B_i != C_i.
            // So, A_i | 1 = 1. This is always true for any A_i.
            // We can choose B_i = 1, C_i = 0.
            // So, A_i=0, B_i=1, C_i=0.
            // B |= (1 << i); // B_i = 1
            // A &= ~(1 << i); // A_i = 0
            // C_i = 0
        } else if (val_if_0[i] == 0 && val_if_1[i] == 1) {
            // Bit unchanged (0->0, 1->1).
            // (0 & A_i) | B_i ^ C_i = 0 => B_i ^ C_i = 0
            // (1 & A_i) | B_i ^ C_i = 1 => A_i | B_i ^ C_i = 1
            // From B_i ^ C_i = 0, we have B_i = C_i.
            // So, A_i | B_i ^ B_i = 1 => A_i | 0 = 1 => A_i = 1.
            // If A_i = 1, then B_i ^ C_i = 0. We can choose B_i = 0, C_i = 0.
            // So, A_i=1, B_i=0, C_i=0.
            A |= (1 << i); // A_i = 1
            // B_i = 0, C_i = 0
        } else if (val_if_0[i] == 1 && val_if_1[i] == 0) {
            // Bit flips (0->1, 1->0).
            // (0 & A_i) | B_i ^ C_i = 1 => B_i ^ C_i = 1
            // (1 & A_i) | B_i ^ C_i = 0 => A_i | B_i ^ C_i = 0
            // From B_i ^ C_i = 1, we have B_i != C_i.
            // So, A_i | 1 = 0. This is impossible.
            // This means the canonical form (x & A) | B ^ C is not sufficient if A is fixed to 1 for unchanged bits.

            // Let's rethink. We need to find A, B, C such that:
            // For input 0: (0 & A) | B ^ C = result_for_0
            // For input 1: (1 & A) | B ^ C = result_for_1
            // This is for a single bit.
            // Let x_i be the i-th bit of input.
            // Let A_i, B_i, C_i be the i-th bits of A, B, C.
            // Output bit for x_i: ((x_i & A_i) | B_i) ^ C_i

            // For x_i = 0: (0 & A_i) | B_i ^ C_i = B_i ^ C_i
            // For x_i = 1: (1 & A_i) | B_i ^ C_i = (A_i | B_i) ^ C_i

            // We have val_if_0[i] and val_if_1[i] for each bit i.
            // We need to solve for A_i, B_i, C_i:
            // 1) B_i ^ C_i = val_if_0[i]
            // 2) (A_i | B_i) ^ C_i = val_if_1[i]

            // From (1), C_i = B_i ^ val_if_0[i]. Substitute into (2):
            // (A_i | B_i) ^ (B_i ^ val_if_0[i]) = val_if_1[i]

            // Case 1: val_if_0[i] = 0, val_if_1[i] = 0 (bit always 0)
            // B_i ^ C_i = 0 => B_i = C_i
            // (A_i | B_i) ^ B_i = 0
            // If B_i = 0: (A_i | 0) ^ 0 = A_i = 0. So A_i=0, B_i=0, C_i=0.
            // If B_i = 1: (A_i | 1) ^ 1 = 1 ^ 1 = 0. So A_i can be 0 or 1.
            // To minimize operations, we prefer A_i=1 if possible.
            // If A_i=1, B_i=1, C_i=1: (x & 1) | 1 ^ 1 = x | 1 ^ 1 = 1 ^ 1 = 0. This works.
            // So for (0,0) we can use A_i=1, B_i=1, C_i=1.
            // Or A_i=0, B_i=0, C_i=0.
            // Let's choose A_i=0, B_i=0, C_i=0 for this case. This means the bit is forced to 0 by the AND operation.
            // A &= ~(1 << i); // A_i = 0
            // B &= ~(1 << i); // B_i = 0
            // C &= ~(1 << i); // C_i = 0

        } else if (val_if_0[i] == 1 && val_if_1[i] == 1) {
            // Bit always 1.
            // B_i ^ C_i = 1
            // (A_i | B_i) ^ C_i = 1
            // From B_i ^ C_i = 1, we have B_i != C_i.
            // (A_i | B_i) ^ C_i = 1. Since B_i != C_i, one is 0 and one is 1.
            // If B_i=0, C_i=1: (A_i | 0) ^ 1 = A_i ^ 1 = 1 => A_i = 0.
            // If B_i=1, C_i=0: (A_i | 1) ^ 0 = 1 ^ 0 = 1. This is always true. A_i can be 0 or 1.
            // To minimize operations, we prefer A_i=1 if possible.
            // Let's choose A_i=1, B_i=1, C_i=0.
            // A |= (1 << i); // A_i = 1
            // B |= (1 << i); // B_i = 1
            // C &= ~(1 << i); // C_i = 0

        } else if (val_if_0[i] == 0 && val_if_1[i] == 1) {
            // Bit unchanged (0->0, 1->1).
            // B_i ^ C_i = 0 => B_i = C_i
            // (A_i | B_i) ^ B_i = 1
            // If B_i = 0: (A_i | 0) ^ 0 = A_i = 1. So A_i=1, B_i=0, C_i=0.
            // If B_i = 1: (A_i | 1) ^ 1 = 1 ^ 1 = 0. This is not 1.
            // So, A_i=1, B_i=0, C_i=0.
            A |= (1 << i); // A_i = 1
            // B &= ~(1 << i); // B_i = 0
            // C &= ~(1 << i); // C_i = 0

        } else if (val_if_0[i] == 1 && val_if_1[i] == 0) {
            // Bit flips (0->1, 1->0).
            // B_i ^ C_i = 1
            // (A_i | B_i) ^ C_i = 0
            // From B_i ^ C_i = 1, we have B_i != C_i.
            // If B_i=0, C_i=1: (A_i | 0) ^ 1 = A_i ^ 1 = 0 => A_i = 1.
